const jobs = $$ || [];
const batchSize = 10;
const out = [];

for (let i = 0; i < jobs.length; i += batchSize) {
  const batch = jobs.slice(i, i + batchSize);
  const settled = await Promise.all(batch.map(async (job) => {
    try {
      const res = await $query({
        api: job.api,
        statement: job.statement,   // <-- key is `statement`, not `query`
        variables: job.variables
      });
      const root = (res && res.data) ? res.data : res;  // handle both return shapes
      const conn = root ? root[job.field] : null;        // dynamic field read-back
      const edges = (conn && conn.edges) || [];
      return {
        id: job.id, name: job.name, type: job.type, typeName: job.typeName,
        total: conn ? conn.total : 0,
        changes: edges.map(e => e.node)
      };
    } catch (err) {
      return {
        id: job.id, name: job.name, type: job.type, typeName: job.typeName,
        error: err.message, changes: []
      };
    }
  }));
  out.push(...settled);
}

return out;

