const TEAM_DOMAINS = { 'fuuz.com': true, 'mfgx.io': true };
const TEAM_LABEL = 'Fuuz Team';
function domainFor(email) {
  if (!email) return 'Unknown';
  const at = email.lastIndexOf('@');
  const d = at >= 0 ? email.slice(at + 1).toLowerCase() : email.toLowerCase();
  return TEAM_DOMAINS[d] ? TEAM_LABEL : d;
}
function bucketWeek(iso) {
  try { const m = $moment(iso).startOf('week'); return { key: m.toISOString(), label: m.format('MM/DD/YYYY') }; }
  catch (e) { const d = (iso || '').slice(0, 10), p = d.split('-');
    return { key: d, label: p.length === 3 ? p[1] + '/' + p[2] + '/' + p[0] : d }; }
}
function uniqPush(arr, seen, k) { if (!seen[k]) { seen[k] = 1; arr.push(k); } }

const builders = {
  screenComplexity: function () {
    const grpOrder = [], grpSeen = {}, modOrder = [], modSeen = {}, agg = {};
    screens.forEach(function (s) {
      const g = (s.module && s.module.moduleGroup && s.module.moduleGroup.name) || 'Ungrouped';
      const mod = (s.module && s.module.name) || 'Unassigned';
      const el = (s.elements && Number(s.elements.total)) || 0;
      uniqPush(grpOrder, grpSeen, g); uniqPush(modOrder, modSeen, mod);
      if (!agg[mod]) agg[mod] = {}; agg[mod][g] = (agg[mod][g] || 0) + el;
    });
    grpOrder.sort(); modOrder.sort();
    const c = baseChart('Screen Complexity by Module', 'Elements per module group', 'Module Group', 'Elements');
    c.showValues = '0'; c.showSum = '1'; c.plotSpacePercent = '40';
    c.numVisiblePlot = '12'; c.scrollToEnd = '0'; c.flatScrollBars = '1';
    c.scrollheight = '8'; c.scrollColor = C.border;
    return {
      type: 'scrollstackedcolumn2d', chart: c,
      categories: [{ category: grpOrder.map(function (g) { return { label: g }; }) }],
      dataset: modOrder.map(function (mod) {
        return { seriesname: mod, data: grpOrder.map(function (g) {
          return { value: String((agg[mod] && agg[mod][g]) || 0) }; }) };
      })
    };
  },

  screenTrend: function () {
    const wkSeen = {}, wkOrder = [], wkLabel = {}, created = {}, updated = {};
    function addWeek(iso, bucket) {
      if (!iso) return;
      const b = bucketWeek(iso);
      uniqPush(wkOrder, wkSeen, b.key); wkLabel[b.key] = b.label;
      bucket[b.key] = (bucket[b.key] || 0) + 1;
    }
    screens.forEach(function (s) { addWeek(s.createdAt, created); addWeek(s.updatedAt, updated); });
    wkOrder.sort();
    const vals = wkOrder.map(function (k) { return created[k] || 0; });
    const avg = vals.length ? Math.round(vals.reduce(function (a, b) { return a + b; }, 0) / vals.length) : 0;
    const c = baseChart('Screen Activity Trend', 'Created vs. updated per week', 'Week', 'Screens');
    c.showValues = '0'; c.lineThickness = '2'; c.drawAnchors = '1';
    c.anchorRadius = '3'; c.anchorBorderThickness = '1';
    c.labelDisplay = 'rotate'; c.slantLabels = '1';
    c.numVisiblePlot = '14'; c.scrollToEnd = '1'; c.flatScrollBars = '1';
    c.scrollheight = '8'; c.scrollColor = C.border;
    return {
      type: 'scrollline2d', chart: c,
      categories: [{ category: wkOrder.map(function (k) { return { label: wkLabel[k] }; }) }],
      dataset: [
        { seriesname: 'Created', data: wkOrder.map(function (k) { return { value: String(created[k] || 0) }; }) },
        { seriesname: 'Updated', data: wkOrder.map(function (k) { return { value: String(updated[k] || 0) }; }) }
      ],
      trendlines: [{ line: [{ startvalue: String(avg), color: C.warn,
        displayvalue: 'Avg created ' + avg, valueOnRight: '1', thickness: '1', dashed: '1', dashLen: '4', dashGap: '3' }] }]
    };
  },

  deploymentHealth: function () {
    const lgOrder = [], lgSeen = {}, dep = {}, undep = {};
    screens.forEach(function (s) {
      const g = (s.module && s.module.moduleGroup && s.module.moduleGroup.name) || 'Ungrouped';
      uniqPush(lgOrder, lgSeen, g);
      const isDep = (s.currentDeployment != null) || ((s.deployments && Number(s.deployments.total)) > 0);
      if (isDep) dep[g] = (dep[g] || 0) + 1; else undep[g] = (undep[g] || 0) + 1;
    });
    lgOrder.sort();
    const c = baseChart('Deployment Health', 'Deployed vs. undeployed screens', 'Module Group', 'Screens');
    c.paletteColors = C.good + ',' + C.risk;
    c.showValues = '0'; c.showSum = '1'; c.plotSpacePercent = '40';
    c.numVisiblePlot = '12'; c.scrollToEnd = '0'; c.flatScrollBars = '1';
    c.scrollheight = '8'; c.scrollColor = C.border;
    return {
      type: 'scrollstackedcolumn2d', chart: c,
      categories: [{ category: lgOrder.map(function (g) { return { label: g }; }) }],
      dataset: [
        { seriesname: 'Deployed',   data: lgOrder.map(function (g) { return { value: String(dep[g] || 0) }; }) },
        { seriesname: 'Undeployed', data: lgOrder.map(function (g) { return { value: String(undep[g] || 0) }; }) }
      ]
    };
  },

  authorship: function () {
    const domOrder = [], domSeen = {}, domCreated = {}, domVersions = {};
    function domBump(map, email) { const d = domainFor(email); uniqPush(domOrder, domSeen, d); map[d] = (map[d] || 0) + 1; }
    screens.forEach(function (s) {
      if (s.createdByUser) domBump(domCreated, s.createdByUser.email);
      ((s.versions && s.versions.edges) || []).forEach(function (ve) {
        const vn = (ve && ve.node) ? ve.node : ve;
        if (vn && vn.createdByUser) domBump(domVersions, vn.createdByUser.email);
      });
    });
    domOrder.sort(function (a, b) {
      if (a === TEAM_LABEL) return -1; if (b === TEAM_LABEL) return 1;
      return a < b ? -1 : (a > b ? 1 : 0);
    });
    const c = baseChart('Authorship by Domain', 'Screens created & versions authored', 'Domain', 'Count');
    c.showValues = '1'; c.showZeroValues = '0'; c.plotSpacePercent = '45';
    return {
      type: 'mscolumn2d', chart: c,
      categories: [{ category: domOrder.map(function (d) { return { label: d }; }) }],
      dataset: [
        { seriesname: 'Screens Created',   data: domOrder.map(function (d) { return { value: String(domCreated[d] || 0) }; }) },
        { seriesname: 'Versions Authored', data: domOrder.map(function (d) { return { value: String(domVersions[d] || 0) }; }) }
      ]
    };
  }
};

