var src = ($$ != null) ? $$ : (($state && $state.context && $state.context.models) || []);
var models;
if (Array.isArray(src)) models = src;
else if (src && Array.isArray(src.edges)) models = src.edges.map(function (e) { return (e && e.node) ? e.node : e; });
else models = [];

var SIG_THRESHOLD = 3;
var BOOKKEEPING = { updatedAt: 1, createdAt: 1, updatedByUserId: 1, createdByUserId: 1, updatedByUser: 1, createdByUser: 1, id: 1, _trace: 1, _metadata: 1 };
function countKeys(o) { return o ? Object.keys(o).length : 0; }
function meaningfulKeys(o) { if (!o) return 0; var n = 0; Object.keys(o).forEach(function (k) { if (!BOOKKEEPING[k]) n++; }); return n; }
function dcType(diff) {
  var a = countKeys(diff.added), d = countKeys(diff.deleted), u = countKeys(diff.updated);
  if (a > 0 && d === 0 && u === 0) return "Create";
  if (d > 0 && a === 0 && u === 0) return "Delete";
  return "Update";
}
function meaningfulCount(diff) { return meaningfulKeys(diff.added) + meaningfulKeys(diff.updated) + meaningfulKeys(diff.deleted); }
function bucketWeek(iso) {
  try { var m = $moment(iso).startOf("week"); return { key: m.toISOString(), label: m.format("MM/DD/YYYY") }; }
  catch (e) { var d = (iso || "").slice(0, 10), p = d.split("-"); return { key: d, label: p.length === 3 ? p[1] + "/" + p[2] + "/" + p[0] : d }; }
}

// flatten once (all panels use events)
var events = [];
models.forEach(function (mdl) {
  var typeName = mdl.typeName || mdl.type || "Unknown";
  var modelName = mdl.name || mdl.id || "Unknown";
  (mdl.changes || []).forEach(function (c) {
    var diff = c.difference || {};
    var t = dcType(diff);
