function kpiCard(label, value, sublabel, tone) {
  const accent = tone === 'risk' ? C.risk
              : tone === 'warn' ? C.warn
              : tone === 'good' ? C.good
              : tone === 'sec'  ? C.security
              : C.accent;
  const sub = sublabel
    ? '<div style="font-size:11px;color:' + C.textMuted + ';margin-top:4px;'
    +   'white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(sublabel) + '</div>'
    : '';
  return ''
    + '<div style="flex:1 1 150px;min-width:135px;max-width:220px;padding:14px 16px;'
    +   'background:' + C.bg + ';'
    +   'border:1px solid ' + C.border + ';'
    +   'border-left:3px solid ' + accent + ';'
    +   'border-radius:8px;'
    +   'box-shadow:0 1px 2px rgba(0,0,0,0.08);">'
    +   '<div style="font-size:10px;text-transform:uppercase;letter-spacing:0.08em;'
    +     'color:' + C.textMuted + ';font-weight:700;'
    +     'white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(label) + '</div>'
    +   '<div style="font-size:26px;font-weight:700;color:' + C.text + ';'
    +     'margin-top:6px;line-height:1;letter-spacing:-0.02em;">' + esc(value) + '</div>'
    +   sub
    + '</div>';
}

