// === Fuuz Data Model Governance Metrics — Risk-tiered + schema hygiene, theme-aware ===
// Input: $.dataModel.edges OR $.dataModelDefinition.edges
// Theme: $state.context.REQUEST.theme  (also honors $$.theme, $.theme,
//        $state.context.theme — first non-empty wins; default Light)
//
// CHANGE LOG
//   - THEME now follows Fuuz convention: literal 'Light' / 'Dark', default
//     Light. Was using lowercase 'light'/'dark' AND defaulting to 'dark'
//     — both off from convention. The C palette comparison was also
//     updated to match ('Dark', not 'dark').
//   - donutOpts now includes the full compact mixin (showLabels:'0',
//     enableSlicing:'0', slicingDistance:'0', smartLineThickness:'0',
//     centerLabelColor/FontSize/Bold pinned, manageResize:'1') — stops
//     the outer pull-out labels overflowing and the doughnut from auto-
//     sizing past the canvas. Particularly important here since
//     modelKinds and modelTypes can have up to 8 slices each.
//   - BASE picks up manageResize:'1' + animation:'0' so every chart type
//     (bars, area, column) recomputes layout on container resize.

const NOW = $moment().valueOf();
const DAY = 86400000;
const D7  = NOW -  7 * DAY;
const D30 = NOW - 30 * DAY;
const D90 = NOW - 90 * DAY;

// ===== Theme — Fuuz convention: literal 'Light' or 'Dark' =====
// Server-side cannot auto-detect dark/light. The screen passes theme via
// the $executeFlow payload (REQUEST.theme) or on the input directly.
// Anything other than the literal 'Dark' → Light (the deployed default).
const _theme = ($state && $state.context && $state.context.REQUEST && $state.context.REQUEST.theme)
            || (typeof $$ !== 'undefined' && $$ && $$.theme)
            || ($ && $.theme)
            || ($state && $state.context && $state.context.theme)
            || '';
const THEME = _theme === 'Dark' ? 'Dark' : 'Light';

const C = THEME === 'Dark' ? {
  bg:'#1e293b', bgDeeper:'#0f172a',
  border:'rgba(148,163,184,0.18)', divLine:'rgba(148,163,184,0.12)',
  text:'#e2e8f0', textMuted:'#94a3b8',
  accent:'#3b82f6', good:'#10b981', warn:'#f59e0b', risk:'#ef4444',
  tooltipBg:'#0f172a', tooltipBd:'#3b82f6',
  palette:['#3b82f6','#10b981','#f59e0b','#a855f7','#06b6d4','#ec4899','#84cc16','#f97316','#8b5cf6','#14b8a6','#eab308','#ef4444']
} : {
  bg:'#ffffff', bgDeeper:'#f8fafc',
  border:'rgba(15,23,42,0.10)', divLine:'rgba(15,23,42,0.08)',
  text:'#0f172a', textMuted:'#64748b',
  accent:'#2563eb', good:'#059669', warn:'#d97706', risk:'#dc2626',
  tooltipBg:'#0f172a', tooltipBd:'#2563eb',
  palette:['#2563eb','#059669','#d97706','#9333ea','#0891b2','#db2777','#65a30d','#ea580c','#7c3aed','#0d9488','#ca8a04','#dc2626']
};

// ===== Parse inputs =====
const src = ($ && $.dataModel && $.dataModel.edges)
         || ($ && $.dataModelDefinition && $.dataModelDefinition.edges)
         || ($state && $state.context && $state.context.dataModels) || [];

const models = [];
for (let i = 0; i < src.length; i++) {
  const n = (src[i] && src[i].node) ? src[i].node : src[i];
  if (n) models.push(n);
}
const total = models.length;

// ===== Schema extraction =====
function extractLatestSchema(m) {
  const verEdges = (m.versions && m.versions.edges) || [];
  for (let v = verEdges.length - 1; v >= 0; v--) {
    const vn = verEdges[v] && verEdges[v].node;
    if (!vn) continue;
    const dc = (vn.dataChanges && vn.dataChanges.edges) || [];
    for (let d = 0; d < dc.length; d++) {
      const added = dc[d].node && dc[d].node.difference && dc[d].node.difference.added;
      if (added && added.modelDefinition) return added.modelDefinition;
    }
  }
  return null;
}

const SCALARS = { ID:1, String:1, Int:1, Float:1, Boolean:1, DateTime:1, Duration:1, JSON:1 };
function classifyFieldType(typeStr) {
  if (!typeStr) return { category:'Unknown', baseType:'Unknown', isRequired:false, isList:false };
  const isRequired = typeStr.indexOf('!') >= 0;
  const isList = typeStr.indexOf('[') === 0;
  const base = String(typeStr).replace(/[!\[\]\s]/g, '');
  const category = SCALARS[base] ? base : 'Relation';
  return { category: category, baseType: base, isRequired: isRequired, isList: isList };
}

const DESC_FIELD_RX = /^\s*\*\*`([^`]+)`\*\*/;
function descFieldName(desc) {
  if (!desc) return null;
  const m = DESC_FIELD_RX.exec(desc);
  return m ? m[1] : null;
}

// ===== Counters =====
let deployed=0, neverDeployed=0;
let exposedCt=0, mutableCt=0;
let createMut=0, updateMut=0, delMut=0;
let dataChangeCaptureOff=0;
let hasLabelFieldCt=0, missingLabelFieldCt=0;
let hasIndicesCt=0, noIndicesCt=0;
let customFieldsEnabled=0;

let tier1=0, tier2=0, tier3=0;
let unused=0, stale=0;
let createdL30=0, updatedL30=0, updatedL7=0;
let emptyVersions=0;

let fieldsSum=0, maxFields=0;
let relationsSum=0, maxRelations=0;
let requiredFieldsSum=0;
let jsonFieldsCt=0, dateTimeFieldsCt=0;
let mismatchedDescCt=0, missingDescCt=0;
let unindexedDateTimeFields=0;
let elementsTotal=0;

const kindCt={}, typeCt={}, moduleCt={}, moduleGroupCt={};
const authorCt={}, editorCt={}, versionAuthorCt={};
const fieldTypeCt={};
const activityByDay={}, createdByDay={};

const moduleStats={}, modGrpStats={};
function modShape() { return { total:0, deployed:0, t1:0, t2:0, t3:0, fieldsSum:0, relationsSum:0 }; }
function ensure(map, key, shape) { if (!map[key]) map[key] = shape(); return map[key]; }

const riskList=[], destructiveList=[], descMismatchList=[];
const noLabelFieldList=[], noDataChangeCaptureList=[];
const highCouplingList=[], staleList=[], unusedList=[];
const emptyVersionsList=[], unindexedDateTimeList=[];

// ===== Main loop =====
for (let i = 0; i < models.length; i++) {
  const m = models[i];
  const dep = (m.deployments && m.deployments.total) || 0;
  const isDeployed = dep > 0 || !!m.currentDataModelDeployment;
  if (isDeployed) deployed++; else neverDeployed++;

  const kindLabel = (m.dataModelKind && m.dataModelKind.label) || 'Unknown';
  const typeName = (m.dataModelType && m.dataModelType.name) || 'Unknown';
  kindCt[kindLabel] = (kindCt[kindLabel] || 0) + 1;
  typeCt[typeName] = (typeCt[typeName] || 0) + 1;

  const elemCt = (m.elements && Number(m.elements.total)) || 0;
  elementsTotal += elemCt;
  if (elemCt === 0) {
    unused++;
    if (unusedList.length < 25) unusedList.push({
      name: m.name, module: (m.module && m.module.name) || '—', kind: kindLabel
    });
  }

  // Time
  const cMs = m.createdAt ? $moment(m.createdAt).valueOf() : 0;
  const uMs = m.updatedAt ? $moment(m.updatedAt).valueOf() : 0;
  if (cMs >= D30) createdL30++;
  if (uMs >= D30) updatedL30++;
  if (uMs >= D7)  updatedL7++;
  if (uMs > 0 && uMs < D90) {
    stale++;
    if (staleList.length < 25) staleList.push({
      name: m.name, kind: kindLabel,
      daysSinceUpdate: Math.floor((NOW - uMs) / DAY),
      module: (m.module && m.module.name) || '—',
      lastEditor: (m.updatedByUser && m.updatedByUser.email) || '—'
    });
  }
  if (uMs >= D30) {
    const uk = $moment(uMs).format('YYYY-MM-DD');
    activityByDay[uk] = (activityByDay[uk] || 0) + 1;
  }
  if (cMs >= D30) {
    const ck = $moment(cMs).format('YYYY-MM-DD');
    createdByDay[ck] = (createdByDay[ck] || 0) + 1;
  }

  // Authors
  const author = m.createdByUser && m.createdByUser.email;
  const editor = m.updatedByUser && m.updatedByUser.email;
  if (author) authorCt[author] = (authorCt[author] || 0) + 1;
  if (editor) editorCt[editor] = (editorCt[editor] || 0) + 1;

  // Version authorship + empty versions
  const versionEdges = (m.versions && m.versions.edges) || [];
  for (let v = 0; v < versionEdges.length; v++) {
    const vn = (versionEdges[v] && versionEdges[v].node) ? versionEdges[v].node : versionEdges[v];
    if (vn && vn.createdByUser && vn.createdByUser.email) {
      versionAuthorCt[vn.createdByUser.email] = (versionAuthorCt[vn.createdByUser.email] || 0) + 1;
    }
    if (vn && vn.dataChanges && Number(vn.dataChanges.total) === 0) {
      emptyVersions++;
      if (emptyVersionsList.length < 25) emptyVersionsList.push({
        name: m.name, version: vn.number,
        author: (vn.createdByUser && vn.createdByUser.email) || '—'
      });
    }
  }

  // Module
  const modName = m.module && m.module.name;
  const grpName = m.module && m.module.moduleGroup && m.module.moduleGroup.name;
  if (modName) {
    moduleCt[modName] = (moduleCt[modName] || 0) + 1;
    const ms = ensure(moduleStats, modName, modShape);
    ms.total++;
    if (isDeployed) ms.deployed++;
  }
  if (grpName) {
    moduleGroupCt[grpName] = (moduleGroupCt[grpName] || 0) + 1;
    const gs = ensure(modGrpStats, grpName, modShape);
    gs.total++;
    if (isDeployed) gs.deployed++;
  }

  // Schema analysis
  const schema = extractLatestSchema(m);
  let modelTier = 0;
  const signals = [];

  let fields = [], relCount = 0, reqCount = 0;
  let hasDelMutation = false, isExposed = false, isMutable = false;
  let hasDCC = false, hasLabelField = false, indicesCount = 0;
  let modelMismatches = 0, modelMissingDesc = 0;
  let modelJsonFields = 0, modelDateTimeFields = 0, modelUnindexedDT = 0;

  if (schema) {
    fields = schema.fields || [];
    const mfgx = (schema.metadata && schema.metadata.mfgx) || {};
    isExposed = mfgx.exposed === true;
    isMutable = mfgx.mutable === true;
    const muts = mfgx.mutations || {};
    if (muts.create === true) createMut++;
    if (muts.update === true) updateMut++;
    if (muts.del === true) delMut++;
    hasDelMutation = muts.del === true;

    if (isExposed) exposedCt++;
    if (isMutable) mutableCt++;

    const dcc = mfgx.dataChangeCapture;
    hasDCC = !!(dcc && dcc.exposed === true);
    if (isExposed && !hasDCC) {
      dataChangeCaptureOff++;
      if (noDataChangeCaptureList.length < 25) noDataChangeCaptureList.push({
        name: m.name, module: modName || '—',
        retentionDays: (dcc && dcc.retentionDays) || '—'
      });
    }

    hasLabelField = !!(mfgx.labelField);
    if (hasLabelField) hasLabelFieldCt++;
    else {
      missingLabelFieldCt++;
      if (noLabelFieldList.length < 25) noLabelFieldList.push({
        name: m.name, module: modName || '—', kind: kindLabel
      });
    }

    indicesCount = (mfgx.indices && mfgx.indices.length) || 0;
    if (indicesCount > 0) hasIndicesCt++; else noIndicesCt++;

    if (mfgx.customFields && mfgx.customFields.exposed === true) customFieldsEnabled++;

    // Indexed field set for DateTime check
    const indexedFields = {};
    if (mfgx.indices) {
      for (let ix = 0; ix < mfgx.indices.length; ix++) {
        const flds = mfgx.indices[ix].fields || [];
        for (let f = 0; f < flds.length; f++) indexedFields[flds[f]] = true;
      }
    }

    // Walk fields
    for (let f = 0; f < fields.length; f++) {
      const fld = fields[f];
      const ft = classifyFieldType(fld.type);
      fieldTypeCt[ft.category] = (fieldTypeCt[ft.category] || 0) + 1;
      if (ft.isRequired) reqCount++;
      if (ft.category === 'Relation') relCount++;
      if (ft.category === 'JSON') modelJsonFields++;
      if (ft.category === 'DateTime') {
        modelDateTimeFields++;
        if (!indexedFields[fld.name]) modelUnindexedDT++;
      }

      const desc = fld.description || '';
      if (!desc.trim()) modelMissingDesc++;
      else {
        const declared = descFieldName(desc);
        if (declared !== null && declared !== fld.name) modelMismatches++;
      }
    }

    fieldsSum += fields.length;
    if (fields.length > maxFields) maxFields = fields.length;
    relationsSum += relCount;
    if (relCount > maxRelations) maxRelations = relCount;
    requiredFieldsSum += reqCount;
    jsonFieldsCt += modelJsonFields;
    dateTimeFieldsCt += modelDateTimeFields;
    mismatchedDescCt += modelMismatches;
    missingDescCt += modelMissingDesc;
    unindexedDateTimeFields += modelUnindexedDT;

    if (modelMismatches > 0 && descMismatchList.length < 25) {
      descMismatchList.push({
        name: m.name, module: modName || '—', mismatchedFields: modelMismatches
      });
    }
    if (modelUnindexedDT > 0 && unindexedDateTimeList.length < 25) {
      unindexedDateTimeList.push({
        name: m.name, module: modName || '—', unindexedDateTimeFields: modelUnindexedDT
      });
    }

    // Roll module field/relation sums
    if (modName) {
      const ms = moduleStats[modName];
      if (ms) { ms.fieldsSum += fields.length; ms.relationsSum += relCount; }
    }
    if (grpName) {
      const gs = modGrpStats[grpName];
      if (gs) { gs.fieldsSum += fields.length; gs.relationsSum += relCount; }
    }

    // ===== Risk tier =====
    // T1: del enabled + exposed (external delete possible)
    if (hasDelMutation && isExposed) {
      modelTier = 1;
      signals.push('hard-delete exposed');
    }
    // T2: exposed without DCC (no audit), or > 5 relations
    else if ((isExposed && !hasDCC) || relCount > 5) {
      modelTier = 2;
      if (isExposed && !hasDCC) signals.push('no audit trail');
      if (relCount > 5) signals.push('high coupling (' + relCount + ' relations)');
    }
    // T3: hygiene
    else if (modelMismatches > 0 || modelMissingDesc > 0 || !hasLabelField || modelUnindexedDT > 0) {
      modelTier = 3;
      if (modelMismatches > 0) signals.push('desc mismatches (' + modelMismatches + ')');
      if (modelMissingDesc > 0) signals.push('missing desc (' + modelMissingDesc + ')');
      if (!hasLabelField) signals.push('no labelField');
      if (modelUnindexedDT > 0) signals.push('unindexed DateTime (' + modelUnindexedDT + ')');
    }

    if (hasDelMutation && isExposed && destructiveList.length < 25) {
      destructiveList.push({
        name: m.name, module: modName || '—',
        kind: kindLabel, fields: fields.length,
        retentionDays: (dcc && dcc.retentionDays) || '—'
      });
    }
    if (relCount > 5 && highCouplingList.length < 25) {
      highCouplingList.push({
        name: m.name, module: modName || '—',
        relations: relCount, fields: fields.length
      });
    }
  }

  if (modelTier === 1) {
    tier1++;
    if (modName) ensure(moduleStats, modName, modShape).t1++;
    if (grpName) ensure(modGrpStats, grpName, modShape).t1++;
  } else if (modelTier === 2) {
    tier2++;
    if (modName) ensure(moduleStats, modName, modShape).t2++;
    if (grpName) ensure(modGrpStats, grpName, modShape).t2++;
  } else if (modelTier === 3) {
    tier3++;
    if (modName) ensure(moduleStats, modName, modShape).t3++;
    if (grpName) ensure(modGrpStats, grpName, modShape).t3++;
  }

  if (modelTier > 0 && riskList.length < 50) {
    riskList.push({
      name: m.name,
      tier: 'T' + modelTier, tierNum: modelTier,
      kind: kindLabel,
      module: modName || '—',
      signals: signals.join(', ') || '—',
      fields: fields.length,
      elements: elemCt
    });
  }
}

// Sort lists
riskList.sort(function (a, b) {
  if (a.tierNum !== b.tierNum) return a.tierNum - b.tierNum;
  return (b.elements || 0) - (a.elements || 0);
});
destructiveList.sort(function (a, b) { return b.fields - a.fields; });
highCouplingList.sort(function (a, b) { return b.relations - a.relations; });
descMismatchList.sort(function (a, b) { return b.mismatchedFields - a.mismatchedFields; });
unindexedDateTimeList.sort(function (a, b) { return b.unindexedDateTimeFields - a.unindexedDateTimeFields; });
staleList.sort(function (a, b) { return b.daysSinceUpdate - a.daysSinceUpdate; });

// ===== Helpers =====
function topN(m, n) {
  const a = [], ks = Object.keys(m);
  for (let i = 0; i < ks.length; i++) a.push({ label: ks[i], value: m[ks[i]] });
  a.sort(function (x, y) { return y.value - x.value; });
  return a.slice(0, n);
}
const r1  = function (x) { const n = Number(x); return isFinite(n) ? Math.round(n * 10) / 10 : 0; };
const pct = function (n, d) { return d > 0 ? Math.round((n / d) * 100) : 0; };
const esc = function (s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
};
function sumValues(arr) { let s = 0; for (let i = 0; i < arr.length; i++) s += arr[i].value; return s; }

// Top-N
const kindData = topN(kindCt, 8);
const typeData = topN(typeCt, 8);
const moduleData = topN(moduleCt, 10);
const modGrpData = topN(moduleGroupCt, 10);
const authorData = topN(authorCt, 10);
const editorData = topN(editorCt, 10);
const versionAuthorData = topN(versionAuthorCt, 10);
const fieldTypeData = topN(fieldTypeCt, 10);

const modulesTotal = sumValues(moduleData);
const modGrpTotal = sumValues(modGrpData);
const fieldsTotal = sumValues(fieldTypeData);

// Top by fields
const topByFields = [];
for (let i = 0; i < models.length; i++) {
  const m = models[i];
  const schema = extractLatestSchema(m);
  const flds = schema && schema.fields ? schema.fields.length : 0;
  if (flds > 0) topByFields.push({ name: m.name, value: flds, module: (m.module && m.module.name) || '—' });
}
topByFields.sort(function (a, b) { return b.value - a.value; });
const topByFieldsTrimmed = topByFields.slice(0, 10);

// Activity series
const activitySeries = [];
for (let i = 29; i >= 0; i--) {
  const ms = NOW - i * DAY;
  const dk = $moment(ms).format('YYYY-MM-DD');
  const upd = activityByDay[dk] || 0;
  const cre = createdByDay[dk] || 0;
  activitySeries.push({
    label: $moment(ms).format('MMM D'),
    value: String(upd),
    toolText: '<b>' + $moment(ms).format('ddd, MMM D YYYY') + '</b><br/>'
            + upd + ' updated &middot; ' + cre + ' new'
  });
}

const k = {
  totalModels: total,
  deployedModels: deployed, neverDeployed: neverDeployed,
  deploymentRate: pct(deployed, total),
  exposedModels: exposedCt, mutableModels: mutableCt,
  createMutations: createMut, updateMutations: updateMut, hardDeleteEnabled: delMut,
  modelsNoDCC: dataChangeCaptureOff,
  modelsNoLabelField: missingLabelFieldCt,
  modelsNoIndices: noIndicesCt, modelsWithIndices: hasIndicesCt,
  modelsCustomFields: customFieldsEnabled,
  tier1Models: tier1, tier2Models: tier2, tier3Models: tier3,
  unusedModels: unused, staleModels: stale,
  emptyVersions: emptyVersions,
  totalFields: fieldsSum,
  avgFieldsPerModel: r1(total > 0 ? fieldsSum / total : 0),
  maxFieldsInModel: maxFields,
  totalRelations: relationsSum,
  avgRelationsPerModel: r1(total > 0 ? relationsSum / total : 0),
  maxRelationsInModel: maxRelations,
  requiredFieldPct: pct(requiredFieldsSum, fieldsSum),
  jsonFields: jsonFieldsCt, dateTimeFields: dateTimeFieldsCt,
  unindexedDateTimeFields: unindexedDateTimeFields,
  mismatchedDescriptions: mismatchedDescCt,
  missingDescriptions: missingDescCt,
  elementsReferencingModels: elementsTotal,
  createdLast30: createdL30, updatedLast30: updatedL30, updatedLast7: updatedL7
};

// ========================================================================
// KPI strip
// ========================================================================
function kpiCard(label, value, sublabel, tone) {
  const accent = tone === 'risk' ? C.risk : tone === 'warn' ? C.warn : tone === 'good' ? C.good : C.accent;
  const sub = sublabel
    ? '<div style="font-size:11px;color:' + C.textMuted + ';margin-top:4px;'
    +   'white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(sublabel) + '</div>'
    : '';
  return ''
    + '<div style="flex:1 1 150px;min-width:135px;max-width:220px;padding:14px 16px;'
    +   'background:' + C.bg + ';border:1px solid ' + C.border + ';'
    +   'border-left:3px solid ' + accent + ';border-radius:8px;'
    +   'box-shadow:0 1px 2px rgba(0,0,0,0.08);">'
    +   '<div style="font-size:10px;text-transform:uppercase;letter-spacing:0.08em;'
    +     'color:' + C.textMuted + ';font-weight:700;'
    +     'white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(label) + '</div>'
    +   '<div style="font-size:26px;font-weight:700;color:' + C.text + ';'
    +     'margin-top:6px;line-height:1;letter-spacing:-0.02em;">' + esc(value) + '</div>'
    +   sub
    + '</div>';
}

// =========================================================================
// HTML: KPI STRIP — daily-driver, 8 cards
// =========================================================================
// Tier 1 (inventory):  Total Models, Deployment Rate
// Tier 2 (risk):       Tier 1 Risk, No Audit Trail
// Tier 3 (quality):    Desc Mismatches, Unindexed DT, Stale 90d+, Updated 7d
//
// Everything else (Exposed, Mutable, T2/T3 tiers, Hard Delete standalone,
// Missing Desc, No Label Field, No Indices, JSON Fields, Avg Fields/Relations,
// Required Field %, Empty Versions, Unused) is intentionally OFF the header.
// They're still computed in `k` and rendered in charts/tables below.
// Header is for "what do I act on today."
//
// Design notes:
//   - Tier 1 alone is the destructive-API headline; T2/T3 live in the
//     riskTiers doughnut.
//   - No Audit Trail gets its own card (not folded into a hygiene aggregate)
//     because it's a broken compliance capability, not just hygiene — same
//     reasoning as Orphan Requests on the data-flow dashboard.
//   - Desc Mismatches chosen over Missing Desc because mismatches actively
//     mislead developers reading the schema; missing-desc is an honest gap.
//   - Unindexed DT chosen over No Indices because field-level is the more
//     actionable signal (and No Indices double-counts at the model level).
//   - Updated 7d uses 'good' tone when >0 — gives the strip a positive
//     anchor so it doesn't read as all-warnings.
const kpiStripHtml = ''
  + '<div style="display:flex;flex-wrap:wrap;gap:10px;padding:4px 0;">'
  +   kpiCard('Total Models',    k.totalModels,             'in inventory',                       null)
  +   kpiCard('Deployment Rate', k.deploymentRate + '%',    k.neverDeployed + ' never deployed',  null)
  +   kpiCard('Tier 1 Risk',     k.tier1Models,             'hard-delete exposed',                k.tier1Models > 0 ? 'risk' : 'good')
  +   kpiCard('No Audit Trail',  k.modelsNoDCC,             'exposed without DCC',                k.modelsNoDCC > 0 ? 'risk' : 'good')
  +   kpiCard('Desc Mismatches', k.mismatchedDescriptions,  'copy-paste bugs in schema',          k.mismatchedDescriptions > 0 ? 'warn' : 'good')
  +   kpiCard('Unindexed DT',    k.unindexedDateTimeFields, 'sort/filter perf cost',              k.unindexedDateTimeFields > 0 ? 'warn' : 'good')
  +   kpiCard('Stale 90d+',      k.staleModels,             'idle models',                        k.staleModels > 0 ? 'warn' : 'good')
  +   kpiCard('Updated 7d',      k.updatedLast7,            k.updatedLast30 + ' in 30d',          k.updatedLast7 > 0 ? 'good' : null)
  + '</div>';

// ========================================================================
// Charts
// ========================================================================
const BASE = {
  bgAlpha:'0', canvasBgAlpha:'0',
  showBorder:'0', showShadow:'0', showCanvasBorder:'0',
  // resize behavior — every chart type recomputes on container resize
  manageResize:'1', animation:'0',
  baseFont:'-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif',
  baseFontColor:C.text, baseFontSize:'12',
  captionFontColor:C.text, captionFontSize:'14', captionFontBold:'1',
  subCaptionFontColor:C.textMuted, subCaptionFontSize:'11',
  divLineColor:C.divLine, divLineAlpha:'60', divLineThickness:'1',
  showAlternateHGridColor:'0', showAlternateVGridColor:'0',
  xAxisNameFontColor:C.textMuted, xAxisNameFontSize:'11',
  yAxisNameFontColor:C.textMuted, yAxisNameFontSize:'11',
  xAxisValueFontColor:C.textMuted, xAxisValueFontSize:'11',
  yAxisValueFontColor:C.textMuted, yAxisValueFontSize:'11',
  labelFontColor:C.text, labelFontSize:'11',
  valueFontColor:C.text, valueFontSize:'11', valueFontBold:'0',
  useEllipsesWhenOverflow:'1', manageLabelOverflow:'1',
  toolTipBgColor:C.tooltipBg, toolTipBgAlpha:'95',
  toolTipBorderColor:C.tooltipBd, toolTipBorderRadius:'6', toolTipBorderThickness:'1',
  toolTipColor:'#f1f5f9', toolTipPadding:'8',
  showToolTipShadow:'1',
  legendBgAlpha:'0', legendBorderAlpha:'0', legendShadow:'0',
  legendItemFontColor:C.text, legendItemFontSize:'11',
  showValues:'0',
  paletteColors: C.palette.join(',')
};

function fcChart(type, caption, dataArr, extra) {
  const chart = Object.assign({ caption: caption }, BASE);
  if (extra) Object.assign(chart, extra);
  return { type: type, chart: chart, data: dataArr };
}

const CTR_PRIMARY   = 'color:' + C.text      + ';font-weight:700;font-size:14px;';
const CTR_SECONDARY = 'color:' + C.textMuted + ';font-weight:400;font-size:11px;';
function ctrLabel(line1, line2) {
  let out = '<span style="' + CTR_PRIMARY + '">' + line1 + '</span>';
  if (line2) out += '<br/><span style="' + CTR_SECONDARY + '">' + line2 + '</span>';
  return out;
}

// ===== DOUGHNUT COMPACT MIXIN =====
// Keep doughnuts inside the panel regardless of container aspect ratio.
// Outer pull-out labels are KILLED (they were overflowing); info flows:
// caption → bold center label → bottom legend (with %) → hover tooltip.
const donutOpts = {
  // Kill the outer pull-out labels — these were the culprits
  showLabels:           '0',
  showValues:           '0',
  enableSmartLabels:    '1',   // belt-and-braces if showLabels is ever flipped on
  smartLineThickness:   '0',
  // Pin the size so FC doesn't auto-size from canvas height and clip the top
  doughnutRadius:       '72',
  pieRadius:            '92',
  // No click-to-pull-out — cleaner for small panels
  enableSlicing:        '0',
  slicingDistance:      '0',
  // Legend at the bottom carries label + %
  showLegend:           '1',
  legendPosition:       'bottom',
  showPercentValues:    '1',
  showPercentInToolTip: '0',
  // Center label — explicit color/size/bold so FC theme doesn't override
  centerLabelFontSize:  '13',
  centerLabelBold:      '1',
  centerLabelColor:     C.text
};

const barOpts = {
  yAxisName:'', xAxisName:'Count',
  chartLeftMargin:'4', chartRightMargin:'14',
  chartTopMargin:'4', chartBottomMargin:'4',
  showValues:'1', placeValuesInside:'0', plotSpacePercent:'30',
  usePlotGradientColor:'0', showXAxisLine:'0', showYAxisLine:'0'
};

function moduleTooltip(label, value, rank, denom, statMap) {
  const s = statMap[label] || { total:value, deployed:0, t1:0, t2:0, t3:0, fieldsSum:0, relationsSum:0 };
  const lines = [
    '<b>#' + rank + ' &middot; ' + esc(label) + '</b>',
    s.total + ' models &middot; ' + (denom > 0 ? Math.round((s.total/denom)*1000)/10 : 0) + '% of total',
    s.deployed + ' deployed (' + pct(s.deployed, s.total) + '%)',
    'Avg ' + (s.total > 0 ? Math.round((s.fieldsSum/s.total)*10)/10 : 0) + ' fields, '
          + (s.total > 0 ? Math.round((s.relationsSum/s.total)*10)/10 : 0) + ' relations'
  ];
  if (s.t1 > 0) lines.push('<span style="color:#fca5a5;">⚠ ' + s.t1 + ' Tier 1</span>');
  if (s.t2 > 0) lines.push('<span style="color:#fcd34d;">◐ ' + s.t2 + ' Tier 2</span>');
  return lines.join('<br/>');
}
function simpleTooltip(label, value, rank, denom, unit) {
  const p = denom > 0 ? Math.round((value/denom)*1000)/10 : 0;
  return '<b>#' + rank + ' &middot; ' + esc(label) + '</b><br/>'
       + value + ' ' + unit + '<br/>' + p + '% of total';
}
function mapWith(data, fn, denom, statMap, unit) {
  const out = [];
  for (let i = 0; i < data.length; i++) {
    out.push({
      label: data[i].label,
      value: String(data[i].value),
      toolText: fn(data[i].label, data[i].value, i + 1, denom, statMap || unit)
    });
  }
  return out;
}

const charts = {
  modelKinds: fcChart('doughnut2d', 'Model Kind',
    kindData.map(function (d) {
      return { label: d.label, value: String(d.value),
        toolText: '<b>' + esc(d.label) + '</b><br/>' + d.value + ' models (' + pct(d.value, total) + '%)' };
    }),
    Object.assign({ defaultCenterLabel: ctrLabel(total + ' models', 'across ' + kindData.length + ' kinds') }, donutOpts)),

  modelTypes: fcChart('doughnut2d', 'Model Execution Type',
    typeData.map(function (d) {
      return { label: d.label, value: String(d.value),
        toolText: '<b>' + esc(d.label) + '</b><br/>' + d.value + ' models (' + pct(d.value, total) + '%)' };
    }),
    Object.assign({ defaultCenterLabel: ctrLabel(total + ' models', '') }, donutOpts)),

  deploymentStatus: fcChart('doughnut2d', 'Deployment Status', [
    { label:'Deployed', value:String(deployed), color:C.accent,
      toolText:'<b>Deployed</b><br/>' + deployed + ' (' + pct(deployed, total) + '%)' },
    { label:'Never Deployed', value:String(neverDeployed), color:C.textMuted,
