function simpleTooltip(label, value, rank, denom, unit) {
  const p = denom > 0 ? Math.round((value/denom)*1000)/10 : 0;
  return '<b>#' + rank + ' &middot; ' + esc(label) + '</b><br/>'
       + value + ' ' + unit + '<br/>' + p + '% of total';
}
function mapWith(data, fn, denom, unit) {
  const out = [];
  for (let i = 0; i < data.length; i++) {
    out.push({
      label: data[i].label,
      value: String(data[i].value),
      toolText: fn(data[i].label, data[i].value, i + 1, denom, unit)
