// =====================================================================
// SavedTransform KPI Dashboard
// JavaScript Script node. Returns the header KPI block PLUS every
// FusionCharts payload in one pass — single $executeFlow per page load,
// each Visualization reads its own key.
//
//   Input  ($$): savedTransform nodes (connection, array, single, or
//                $state.context.transforms); $$.theme is also honored as
//                a fallback signal for theme
//   Output:      { kpis, activeStatus, deploymentStatus, languageMix,
//                  topAuthors, topEditors, creationTrend,
//                  versionDistribution, domainMix, _meta }
//
// CHANGE LOG vs 0.0.1
//   - Theme default flipped to LIGHT (matches deployed environment);
//     dark mode uses bumped-brighter inks (#F2F4F8 / #B6BECC) for the
//     legibility-on-dark-bg case. Theme signal read from REQ.theme,
//     $$.theme, or $state.context.theme — first non-empty wins.
//   - Doughnut/pie outer labels hidden (showLabels:"0") to stop the
//     overflow when panels shrink; legend + center label + tooltip
//     carry the info. enableSmartLabels + manageResize folded in.
//   - plotToolText overridden per chart type with the correct macros
//     ($label/$value/$percentValue for pie+doughnut, $seriesName/$label/
//     $dataValue for category charts) and richer HTML formatting.
// =====================================================================


// ---------- 0. theme — read from any signal, LIGHT default -----------
// Server-side cannot auto-detect dark/light (no window/DOM). The screen
// should pass theme via the $executeFlow payload (REQ.theme) or directly
// on $$ ($$.theme). Anything other than the literal "dark" → light.
var REQ = ($state && $state.context && $state.context.REQUEST) || {};
var rawIn = $$;
var themeHint = (
  REQ.theme
  || (rawIn && rawIn.theme)
  || ($state && $state.context && $state.context.theme)
  || ""
).toString().toLowerCase();
var isDark = themeHint === "dark";

// Brighter inks in dark mode so axis/legend/caption text stays legible.
// Light-mode inks unchanged from the locked-in screen/model/flow palette.
var ink      = isDark ? "#F2F4F8" : "#1F2733";   // primary text
var inkMuted = isDark ? "#B6BECC" : "#5E6B7E";   // secondary text
var grid     = isDark ? "#3A4250" : "#E2E6ED";   // gridlines
var axisLine = isDark ? "#55606E" : "#C2C9D4";   // axis / scrollbar

// Tooltip surface — dark in both modes so it always pops off the panel
var tipBg   = "#1F2733";
var tipText = "#F2F4F8";


// ---------- 1. normalize input to a flat array of transform nodes ----
function unwrap(n) { return n && n.node ? n.node : n; }

var rows;
if (Array.isArray(rawIn))                                              rows = rawIn;
else if (rawIn && rawIn.edges)                                         rows = rawIn.edges;
else if (rawIn && rawIn.savedTransform && rawIn.savedTransform.edges)  rows = rawIn.savedTransform.edges;
else if (rawIn && rawIn.savedTransforms && rawIn.savedTransforms.edges) rows = rawIn.savedTransforms.edges;
else if ($state && $state.context && $state.context.transforms)        rows = $state.context.transforms;
else if (rawIn && rawIn.rows && Array.isArray(rawIn.rows))             rows = rawIn.rows;
else if (rawIn)                                                        rows = [rawIn];
else                                                                   rows = [];

var transforms = (rows || []).map(unwrap).filter(function (t) {
  return t && (t.name || t.scriptLanguage || t.versions);
});


// ---------- shared helpers -------------------------------------------
var TEAM_DOMAINS = { "fuuz.com": true, "mfgx.io": true };
var TEAM_LABEL   = "Fuuz Team";

function domainFor(email) {
  if (!email) return "Unknown";
  var at = email.lastIndexOf("@");
  var d = at >= 0 ? email.slice(at + 1).toLowerCase() : email.toLowerCase();
  return TEAM_DOMAINS[d] ? TEAM_LABEL : d;
}

function bump(obj, key, by) { obj[key] = (obj[key] || 0) + (by == null ? 1 : by); }

function weekKey(iso) {
  if (!iso) return null;
  var dt = new Date(iso);
  if (isNaN(dt.getTime())) return null;
  var d = new Date(Date.UTC(dt.getUTCFullYear(), dt.getUTCMonth(), dt.getUTCDate()));
  d.setUTCDate(d.getUTCDate() - d.getUTCDay()); // back up to Sunday
  return d.toISOString().slice(0, 10);
}
function weekLabel(key) {
  var p = key.split("-");
  return p[1] + "/" + p[2] + "/" + p[0];
}

function daysAgo(iso) {
  if (!iso) return null;
  var t = new Date(iso).getTime();
  if (isNaN(t)) return null;
  return Math.floor((Date.now() - t) / 86400000);
}

function pct(n, d) { return d > 0 ? Math.round((n / d) * 1000) / 10 : 0; }


// ---------- TOOLTIP FACTORY ------------------------------------------
// FusionCharts macros differ by chart type:
//   pie2d / doughnut2d:  $label, $value, $percentValue, $sum
//   category charts:      $seriesName, $label, $dataValue, $yDataValue
// Builders use these factories instead of inheriting baseChart's default
// so the macros line up with the chart type.
function tipShell(innerHtml) {
  return "<div style='padding:6px 9px; font-size:12px; line-height:1.45; "
       + "color:" + tipText + "; background:" + tipBg + ";'>"
       + innerHtml
       + "</div>";
}

function tipPieDoughnut(unitNoun, totalN) {
  return tipShell(
    "<b style='font-size:13px;'>$label</b><br/>"
    + "<span style='opacity:0.85;'>$value of " + totalN + " " + unitNoun + "</span><br/>"
    + "<b>$percentValue</b> of total"
  );
}

function tipBar(unitNoun) {
  return tipShell(
    "<b style='font-size:13px;'>$label</b><br/>"
    + "<b>$dataValue</b> " + unitNoun
  );
}

function tipColumn(unitNoun) {
  return tipShell(
    "<b style='font-size:13px;'>$label</b><br/>"
    + "<b>$dataValue</b> " + unitNoun
  );
}

function tipMultiSeriesWeek(unitNoun) {
  return tipShell(
    "<b style='font-size:13px;'>Week of $label</b><br/>"
    + "<span style='opacity:0.85;'>$seriesName</span><br/>"
    + "<b>$dataValue</b> " + unitNoun
  );
}


// ---------- baseChart: the shared styling contract (theme-aware) ------
function baseChart(caption, subCaption, xName, yName) {
  return {
    caption: caption || "",
    subCaption: subCaption || "",
    xAxisName: xName || "",
    yAxisName: yName || "",

    // zero outer chrome
    chartLeftMargin: "0", chartRightMargin: "0",
    chartTopMargin: "0",  chartBottomMargin: "0",
    captionPadding: "8",  canvasPadding: "0",
    captionFontBold: "1", captionFontSize: "13",
    subCaptionFontSize: "11",

    // resize behavior — recompute layout when panel changes size
    manageResize: "1",
    animation: "0",

    // transparent surface (inherits dashboard bg, flips with theme)
    bgColor: "transparent", bgAlpha: "0", canvasBgAlpha: "0",
    showBorder: "0", showCanvasBorder: "0",

    // text — the dark/light legibility fix (BOTH font-color groups)
    baseFontColor: ink, outCnvBaseFontColor: ink,
    captionFontColor: ink, subCaptionFontColor: inkMuted,
    xAxisNameFontColor: inkMuted, yAxisNameFontColor: inkMuted,
    legendItemFontColor: ink, valueFontColor: ink, sumFontColor: ink,
    labelFontColor: inkMuted,

    // long category labels wrap/rotate instead of colliding
    labelDisplay: "auto", useEllipsesWhenOverflow: "1",

    // gridlines / axis
    divLineColor: grid, divLineAlpha: "60",
