  undeployedScripts:    undeployedCount,
  substitutedScripts:   substitutedCount,
  totalVersions:        totalVersions,
  avgVersionsPerScript: total > 0 ? Math.round((totalVersions / total) * 10) / 10 : 0,
  scriptsWithChanges:   withDataChanges,
  totalDeployments:     totalDeployments,
  jsonataScripts:       languageCounts["JSONata"] || 0,
