function table(title, columns, rows, tone) {
  const accent = tone === 'risk' ? C.risk : tone === 'warn' ? C.warn : C.accent;
  if (!rows.length) {
    return ''
      + '<div style="padding:16px 18px;background:' + C.bg + ';'
      +   'border:1px solid ' + C.border + ';border-left:3px solid ' + C.good + ';border-radius:8px;'
      +   'box-shadow:0 1px 2px rgba(0,0,0,0.08);">'
      +   '<div style="font-size:11px;text-transform:uppercase;letter-spacing:0.08em;'
      +     'color:' + C.textMuted + ';font-weight:700;margin-bottom:6px;">' + esc(title) + '</div>'
      +   '<div style="font-size:13px;color:' + C.good + ';font-weight:500;">No queries match. ✓</div>'
      + '</div>';
  }
  let head = '<tr>';
  for (let c = 0; c < columns.length; c++) {
    head += '<th style="text-align:left;padding:10px 12px;font-size:10px;text-transform:uppercase;'
         +    'letter-spacing:0.08em;color:' + C.textMuted + ';font-weight:700;'
         +    'border-bottom:1px solid ' + C.border + ';background:' + C.bgDeeper + ';">'
         +    esc(columns[c].label) + '</th>';
  }
  head += '</tr>';
  let body = '';
  for (let r = 0; r < rows.length; r++) {
    body += '<tr>';
    for (let c = 0; c < columns.length; c++) {
      const col = columns[c];
      const v = rows[r][col.key];
      let cellHtml;
      if (col.key === 'tier') {
        const tierColor = v === 'T1' ? C.risk : v === 'T2' ? C.warn : C.accent;
        cellHtml = '<span style="display:inline-block;font-size:11px;font-weight:700;color:' + tierColor + ';'
                 + 'padding:2px 8px;border-radius:10px;background:' + tierColor + '1F;">' + esc(v) + '</span>';
      } else {
        cellHtml = esc(v === null || v === undefined ? '—' : v);
      }
      body += '<td style="padding:9px 12px;font-size:13px;color:' + C.text + ';'
           +    'border-bottom:1px solid ' + C.divLine + ';">' + cellHtml + '</td>';
    }
    body += '</tr>';
  }
  return ''
    + '<div style="background:' + C.bg + ';'
    +   'border:1px solid ' + C.border + ';border-left:3px solid ' + accent + ';'
    +   'border-radius:8px;overflow:hidden;box-shadow:0 1px 2px rgba(0,0,0,0.08);">'
    +   '<div style="padding:12px 16px;display:flex;align-items:center;justify-content:space-between;'
    +     'border-bottom:1px solid ' + C.border + ';">'
    +     '<div style="font-size:11px;text-transform:uppercase;letter-spacing:0.08em;'
    +       'color:' + C.textMuted + ';font-weight:700;">' + esc(title) + '</div>'
    +     '<div style="font-size:12px;color:' + accent + ';font-weight:700;'
    +       'padding:3px 10px;border-radius:10px;background:' + accent + '1F;">' + rows.length + '</div>'
    +   '</div>'
    +   '<div style="max-height:400px;overflow-y:auto;">'
    +     '<table style="width:100%;border-collapse:collapse;">'
    +       '<thead>' + head + '</thead><tbody>' + body + '</tbody>'
    +     '</table>'
    +   '</div>'
    + '</div>';
}

