  // ===== Lazy search index ==================================================
  // Built on first keystroke. Reduces wire payload and only computed once.
  let _searchIndex = null;
  function searchIndex() {
    if (_searchIndex) return _searchIndex;
    const models = STATE.models;
    const n = models.length;
    const idx = new Array(n);
    for (let i = 0; i < n; i++) {
      const m = models[i];
      const fields = m.fields;
      const fc = fields.length;
      // Concatenate name + description + field names into one lowercased string.
      // Use a small string builder loop rather than .map(...).join for fewer
      // allocations at 750 models × 30 fields = 22,500 strings to handle.
      let s = m.name + ' ' + (m.description || '');
      for (let j = 0; j < fc; j++) { s += ' ' + fields[j].name; }
      idx[i] = s.toLowerCase();
    }
    _searchIndex = idx;
