  const elDrawerDesc   = document.getElementById('drawerDesc');
  const elDrawerBody   = document.getElementById('drawerBody');
  const elDrawerClose  = document.getElementById('drawerClose');
  const elToggleAudit  = document.getElementById('toggleAudit');
  const elToggleSystem = document.getElementById('toggleSystem');
  const elTopStats     = document.getElementById('topStats');
