  function esc(s) {
    if (s == null) return '';
    return String(s)
      .replace(/&/g,'&amp;').replace(/</g,'&lt;')
      .replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  // ===== Type re-inflation ==================================================
  // Server collapses each field's type to its raw string ("String!", "[ID!]!"
  // etc.) to shrink the URI. Inflate back to { base, required, raw } so the
  // rest of the runtime can keep using the structured shape it was written
