        + '<div class="erd-card system">'
        +   '<div class="erd-card-header">'
        +     '<div class="erd-card-name">' + esc(node.name) + '</div>'
        +     '<div class="erd-card-meta">system</div>'
        +   '</div>'
        + '</div>';
    }
    const m = node.model;
    const visible = diagramFields(m);
    const isFocus = node.kind === 'focus';

    let rows = '';
    for (let i = 0; i < visible.length; i++) {
      const f = visible[i];
      const tCls = rowTypeClass(f);
      const isPK = f.category === 'primary';
      const isFK = f.category === 'fkId' && !f.pairedWith;
      const nameCls = (f.category === 'relation' || f.category === 'listRel') ? 'relation' : '';
      const displayType = (f.category === 'relation') ? f.targetModel
                        : (f.category === 'listRel') ? '[' + f.targetModel + ']'
                        : f.type.raw;
      rows += ''
        + '<div class="erd-row">'
        + (isPK ? '<span class="erd-badge pk">PK</span>' : '')
        + (isFK ? '<span class="erd-badge fk">FK</span>' : '')
        +   '<span class="erd-row-name ' + nameCls + '">' + esc(f.name) + '</span>'
        +   '<span class="erd-row-type ' + tCls + '">' + esc(displayType) + '</span>'
        + '</div>';
    }
    const kindLabel = m.kind === 'topic'            ? 'Topic'
                   :  m.kind === 'edgeSubscription' ? 'Edge Sub'
                   :  '';
    const kindTag = kindLabel
      ? '<span class="erd-card-kind-tag kind-' + m.kind + '">' + kindLabel + '</span>'
      : '';
    return ''
      + '<div class="erd-card' + (isFocus ? ' focus' : '') + '" data-name="' + esc(m.name) + '">'
      +   '<div class="erd-card-header" data-action="open-drawer">'
      +     '<div class="erd-card-name">' + esc(m.name) + '</div>'
      +     kindTag
      +     '<div class="erd-card-meta">' + m.counts.core + ' fields</div>'
      +   '</div>'
      +   '<div class="erd-card-body">'
      +     rows
      +   '</div>'
      + '</div>';
  }

  function rectEdgePoint(cx, cy, w, h, tx, ty) {
    const dx = tx - cx, dy = ty - cy;
    if (dx === 0 && dy === 0) return { x: cx, y: cy };
    const hw = w / 2, hh = h / 2;
    const ax = Math.abs(dx), ay = Math.abs(dy);
    let t;
    if (ax * hh > ay * hw) { t = hw / ax; }
    else                    { t = hh / ay; }
    return { x: cx + dx * t, y: cy + dy * t };
  }

  // ===== Force-directed layout (Fruchterman-Reingold) =====================
  // For large node counts, iteration count is reduced to keep wall-clock
  // reasonable. Quality degrades gracefully — at N > 150 we recommend
  // layered mode anyway (auto-switched in viewAllModels).
  function forceLayout(nodes, edges, sizes) {
    const N = nodes.length;
    if (N === 0) return {};

    let maxW = 0, maxH = 0;
    for (let i = 0; i < N; i++) {
      const s = sizes[nodes[i].name];
      if (s.width  > maxW) maxW = s.width;
      if (s.height > maxH) maxH = s.height;
    }
    const k = Math.max(maxW, maxH) * 1.4;
    const kSq = k * k;

    const cols = Math.ceil(Math.sqrt(N));
    const pos = new Array(N);
    for (let i = 0; i < N; i++) {
      pos[i] = {
        x: (i % cols) * k,
        y: Math.floor(i / cols) * k,
        vx: 0, vy: 0
      };
    }

    const nameIdx = {};
    for (let i = 0; i < N; i++) nameIdx[nodes[i].name] = i;
    const eList = [];
    for (let i = 0; i < edges.length; i++) {
      const e = edges[i];
      const a = nameIdx[e.from], b = nameIdx[e.to];
      if (a != null && b != null && a !== b) eList.push([a, b]);
    }

    // Iteration count scales down for large N to bound execution time.
    let iterations;
    if (N <= 50)       iterations = 400;
    else if (N <= 100) iterations = 250;
    else if (N <= 200) iterations = 150;
    else               iterations = 100;
    const W = cols * k;
    let temp = W / 8;
    const cooling = temp / iterations;

    for (let iter = 0; iter < iterations; iter++) {
      for (let i = 0; i < N; i++) { pos[i].vx = 0; pos[i].vy = 0; }

      for (let i = 0; i < N; i++) {
        const pi = pos[i];
        for (let j = i + 1; j < N; j++) {
          const pj = pos[j];
          let dx = pi.x - pj.x;
          let dy = pi.y - pj.y;
          let d = Math.sqrt(dx * dx + dy * dy);
          if (d < 0.01) {
            dx = (i - j) * 0.01;
            dy = (i + j) * 0.01;
            d = Math.sqrt(dx * dx + dy * dy) || 0.01;
          }
          const force = kSq / d;
          const fx = (dx / d) * force;
          const fy = (dy / d) * force;
          pi.vx += fx;  pi.vy += fy;
          pj.vx -= fx;  pj.vy -= fy;
        }
      }

      for (let i = 0; i < eList.length; i++) {
        const a = eList[i][0], b = eList[i][1];
        const pa = pos[a], pb = pos[b];
        const dx = pa.x - pb.x;
        const dy = pa.y - pb.y;
        const d = Math.sqrt(dx * dx + dy * dy) || 0.01;
        const force = (d * d) / k;
        const fx = (dx / d) * force;
        const fy = (dy / d) * force;
        pa.vx -= fx;  pa.vy -= fy;
        pb.vx += fx;  pb.vy += fy;
      }

      for (let i = 0; i < N; i++) {
        const p = pos[i];
        const speed = Math.sqrt(p.vx * p.vx + p.vy * p.vy);
        if (speed > 0) {
          const step = Math.min(speed, temp);
          p.x += (p.vx / speed) * step;
          p.y += (p.vy / speed) * step;
        }
      }
      temp = Math.max(temp - cooling, 0.3);
    }

    let minX = Infinity, minY = Infinity;
    for (let i = 0; i < N; i++) {
      if (pos[i].x < minX) minX = pos[i].x;
      if (pos[i].y < minY) minY = pos[i].y;
    }
    const positions = {};
    for (let i = 0; i < N; i++) {
      const name = nodes[i].name;
      const s = sizes[name];
      const cx = pos[i].x - minX + 30;
      const cy = pos[i].y - minY + 30;
      positions[name] = {
        x: cx - s.width / 2, y: cy - s.height / 2,
        w: s.width, h: s.height,
        cx: cx, cy: cy
      };
    }
    return positions;
  }

  function renderDiagram(focusName) {
    const showSomething = focusName || ui.viewAll;
    elEmpty.style.display = showSomething ? 'none' : 'block';
    elCardsLayer.innerHTML = '';
    elEdgesLayer.innerHTML = '';
    if (!showSomething) return;

    const sub = focusName ? buildSubgraph(focusName) : buildFullGraph();
    if (!sub || sub.nodes.length === 0) return;

    for (const k in cardPositions) delete cardPositions[k];

    const useCompact = !!ui.viewAll;
    const sizes = {};
    for (let i = 0; i < sub.nodes.length; i++) {
      const n = sub.nodes[i];
      sizes[n.name] = useCompact ? measureCardCompact() : measureCard(n.model, n.external);
    }

    const useForce = (ui.layoutMode === 'force');
    let positions, edgeWaypoints = null;
    if (useForce) {
      positions = forceLayout(sub.nodes, sub.edges, sizes);
    } else {
      const g = new dagre.graphlib.Graph({ multigraph: true });
      g.setGraph({
        rankdir: 'LR',
        nodesep: useCompact ? 24 : 36,
        ranksep: useCompact ? 60 : 90,
        edgesep: useCompact ?  8 : 12,
        marginx: 30,
        marginy: 30
      });
      g.setDefaultEdgeLabel(function () { return {}; });
      for (let i = 0; i < sub.nodes.length; i++) {
        const n = sub.nodes[i];
        g.setNode(n.name, { width: sizes[n.name].width, height: sizes[n.name].height });
      }
      for (let i = 0; i < sub.edges.length; i++) {
        const e = sub.edges[i];
        if (g.hasNode(e.from) && g.hasNode(e.to)) {
          g.setEdge(e.from, e.to, { eid: i }, 'e' + i);
        }
      }
      dagre.layout(g);

      positions = {};
      g.nodes().forEach(function (name) {
        const pos = g.node(name);
        const w = pos.width, h = pos.height;
        positions[name] = { x: pos.x - w / 2, y: pos.y - h / 2, w: w, h: h, cx: pos.x, cy: pos.y };
      });

      edgeWaypoints = {};
      g.edges().forEach(function (edgeMeta) {
        const ed = g.edge(edgeMeta);
        edgeWaypoints[ed.eid] = ed.points || [];
      });
    }

    // Use document fragments to batch DOM writes — fewer reflows when rendering
    // many cards at once (matters at N > 100).
    const cardsFrag = document.createDocumentFragment();
    const edgesFrag = document.createDocumentFragment();

    for (let i = 0; i < sub.nodes.length; i++) {
      const node = sub.nodes[i];
      const name = node.name;
      const p = positions[name];
      if (!p) continue;

      const nodeG = document.createElementNS(SVG_NS, 'g');
      nodeG.setAttribute('class', 'erd-node');
      nodeG.setAttribute('data-name', name);
      nodeG.setAttribute('data-kind', (node.model && node.model.kind) || 'model');
      nodeG.setAttribute('transform', 'translate(' + p.x + ' ' + p.y + ')');

      if (useCompact) {
        nodeG.innerHTML = compactCardSVG(node, p.w, p.h);
      } else {
        const fo = document.createElementNS(SVG_NS, 'foreignObject');
        fo.setAttribute('x', '0');
        fo.setAttribute('y', '0');
        fo.setAttribute('width', String(p.w));
        fo.setAttribute('height', String(p.h));
        fo.innerHTML = cardInnerHTML(node);
        nodeG.appendChild(fo);
      }

      cardPositions[name] = { x: p.x, y: p.y, w: p.w, h: p.h, cx: p.cx, cy: p.cy, el: nodeG };
      cardsFrag.appendChild(nodeG);
    }

    for (let i = 0; i < sub.edges.length; i++) {
      const relation = sub.edges[i];
      const fromPos = cardPositions[relation.from];
      const toPos   = cardPositions[relation.to];
      if (!fromPos || !toPos) continue;

      const points = edgeWaypoints ? (edgeWaypoints[i] || []) : [];
      const firstInner = points[1]                  || { x: toPos.cx,   y: toPos.cy   };
      const lastInner  = points[points.length - 2]  || { x: fromPos.cx, y: fromPos.cy };
      const startPt = rectEdgePoint(fromPos.cx, fromPos.cy, fromPos.w, fromPos.h, firstInner.x, firstInner.y);
      const endPt   = rectEdgePoint(toPos.cx,   toPos.cy,   toPos.w,   toPos.h,   lastInner.x,  lastInner.y);

      const pathPoints = [startPt];
      for (let j = 1; j < points.length - 1; j++) pathPoints.push(points[j]);
      pathPoints.push(endPt);
      const d = pathToD(pathPoints);

      const parts = relation.cardinality.split(':');
      const startMark = parts[0] === 'M' ? 'url(#m-many)' : 'url(#m-one)';
      const endMark   = parts[1] === 'M' ? 'url(#m-many)' : 'url(#m-one)';

      const edgeG = document.createElementNS(SVG_NS, 'g');
      edgeG.setAttribute('class', 'erd-edge-group');
      edgeG.setAttribute('data-edge-from', relation.from);
      edgeG.setAttribute('data-edge-to',   relation.to);
      edgeG.setAttribute('data-edge-via',  relation.via);

      const path = document.createElementNS(SVG_NS, 'path');
      path.setAttribute('class', 'erd-edge' + (relation.inferred ? ' inferred' : ''));
      path.setAttribute('d', d);
      path.setAttribute('marker-start', startMark);
      path.setAttribute('marker-end', endMark);
      edgeG.appendChild(path);

      const midIdx = Math.floor(pathPoints.length / 2);
      const a = pathPoints[Math.max(0, midIdx - 1)];
      const b = pathPoints[Math.min(pathPoints.length - 1, midIdx)];
      const mx = (a.x + b.x) / 2;
      const my = (a.y + b.y) / 2;

      const cardLabel = document.createElementNS(SVG_NS, 'text');
      cardLabel.setAttribute('class', 'erd-edge-label');
      cardLabel.setAttribute('x', String(mx));
      cardLabel.setAttribute('y', String(my - 4));
      cardLabel.setAttribute('text-anchor', 'middle');
      cardLabel.textContent = relation.cardinality;
      edgeG.appendChild(cardLabel);

      const viaLabel = document.createElementNS(SVG_NS, 'text');
      viaLabel.setAttribute('class', 'erd-edge-via');
      viaLabel.setAttribute('x', String(mx));
      viaLabel.setAttribute('y', String(my + 10));
      viaLabel.setAttribute('text-anchor', 'middle');
      viaLabel.textContent = relation.via + (relation.inferred ? ' (inferred)' : '');
      edgeG.appendChild(viaLabel);

      edgesFrag.appendChild(edgeG);
    }

    elCardsLayer.appendChild(cardsFrag);
    elEdgesLayer.appendChild(edgesFrag);

    fitToView();
  }

  function rerouteEdgesForNode(name) {
    const sel = 'g.erd-edge-group[data-edge-from="' + name + '"], g.erd-edge-group[data-edge-to="' + name + '"]';
    const groups = elEdgesLayer.querySelectorAll(sel);
    for (let i = 0; i < groups.length; i++) {
      const eg = groups[i];
      const ef = eg.getAttribute('data-edge-from');
      const et = eg.getAttribute('data-edge-to');
      const fp = cardPositions[ef], tp = cardPositions[et];
      if (!fp || !tp) continue;
      const startPt = rectEdgePoint(fp.cx, fp.cy, fp.w, fp.h, tp.cx, tp.cy);
      const endPt   = rectEdgePoint(tp.cx, tp.cy, tp.w, tp.h, fp.cx, fp.cy);
      const path = eg.querySelector('path');
      if (path) path.setAttribute('d', 'M ' + startPt.x + ' ' + startPt.y + ' L ' + endPt.x + ' ' + endPt.y);
      const mx = (startPt.x + endPt.x) / 2;
      const my = (startPt.y + endPt.y) / 2;
      const labels = eg.querySelectorAll('text');
      if (labels[0]) { labels[0].setAttribute('x', String(mx)); labels[0].setAttribute('y', String(my - 4)); }
      if (labels[1]) { labels[1].setAttribute('x', String(mx)); labels[1].setAttribute('y', String(my + 10)); }
    }
  }

  function pathToD(points) {
    if (points.length === 0) return '';
    let d = 'M ' + points[0].x + ' ' + points[0].y;
    for (let i = 1; i < points.length; i++) {
      d += ' L ' + points[i].x + ' ' + points[i].y;
    }
    return d;
  }

  // ===== Pan / zoom =========================================================
  function applyViewport() {
    elViewport.setAttribute('transform', 'translate(' + ui.pan.x + ' ' + ui.pan.y + ') scale(' + ui.zoom + ')');
    elZoomReadout.textContent = Math.round(ui.zoom * 100) + '%';
  }

  let fitDeferRetries = 0;
  const FIT_MAX_RETRIES = 60;
  const MIN_FIT_ZOOM   = 0.05;

  function fitToView() {
    const names = Object.keys(cardPositions);
    if (names.length === 0) return;

    const cw = elCanvasWrap.clientWidth;
    const ch = elCanvasWrap.clientHeight;

    if (cw <= 0 || ch <= 0) {
      if (fitDeferRetries < FIT_MAX_RETRIES) {
        fitDeferRetries++;
        requestAnimationFrame(fitToView);
      }
      return;
    }
    fitDeferRetries = 0;

    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (let i = 0; i < names.length; i++) {
      const cp = cardPositions[names[i]];
      if (cp.x < minX) minX = cp.x;
      if (cp.y < minY) minY = cp.y;
      if (cp.x + cp.w > maxX) maxX = cp.x + cp.w;
      if (cp.y + cp.h > maxY) maxY = cp.y + cp.h;
    }
    const pad = 40;
    const bw = maxX - minX, bh = maxY - minY;
    if (bw <= 0 || bh <= 0) return;
    const sx = (cw - pad * 2) / bw;
    const sy = (ch - pad * 2) / bh;
    const s = Math.max(MIN_FIT_ZOOM, Math.min(sx, sy, 1.4));
    ui.zoom = s;
    ui.pan.x = (cw - bw * s) / 2 - minX * s;
    ui.pan.y = (ch - bh * s) / 2 - minY * s;
    applyViewport();
  }

  function setZoom(newZoom, originX, originY) {
    const clamped = Math.max(0.2, Math.min(3.0, newZoom));
    if (clamped === ui.zoom) return;
    if (originX != null && originY != null) {
      const ratio = clamped / ui.zoom;
      ui.pan.x = originX - (originX - ui.pan.x) * ratio;
      ui.pan.y = originY - (originY - ui.pan.y) * ratio;
    }
    ui.zoom = clamped;
    applyViewport();
  }

  function setupPanZoom() {
    elCanvasWrap.addEventListener('wheel', function (e) {
      e.preventDefault();
      const rect = elCanvasWrap.getBoundingClientRect();
      const ox = e.clientX - rect.left;
      const oy = e.clientY - rect.top;
      const factor = e.deltaY < 0 ? 1.12 : 0.89;
      setZoom(ui.zoom * factor, ox, oy);
    }, { passive: false });

    let isPanning = false, startX = 0, startY = 0, startPanX = 0, startPanY = 0;
    elSvg.addEventListener('mousedown', function (e) {
      if (e.target.closest('.erd-node')) return;
      isPanning = true;
      startX = e.clientX; startY = e.clientY;
      startPanX = ui.pan.x; startPanY = ui.pan.y;
      elSvg.classList.add('panning');
    });
    window.addEventListener('mousemove', function (e) {
      if (!isPanning) return;
      ui.pan.x = startPanX + (e.clientX - startX);
      ui.pan.y = startPanY + (e.clientY - startY);
      applyViewport();
    });
    window.addEventListener('mouseup', function () {
      isPanning = false;
      elSvg.classList.remove('panning');
    });

    elCardsLayer.addEventListener('mousedown', function (e) {
      const nodeG = e.target.closest('.erd-node');
      if (!nodeG) return;
      const name = nodeG.getAttribute('data-name');
      if (!name || !cardPositions[name]) return;
      e.stopPropagation();
      e.preventDefault();
      const cp = cardPositions[name];
      dragState = {
        name: name,
        startX: e.clientX,
        startY: e.clientY,
        nodeStartX: cp.x,
        nodeStartY: cp.y,
        moved: false
      };
    });
    window.addEventListener('mousemove', function (e) {
      if (!dragState) return;
      const dx = (e.clientX - dragState.startX) / ui.zoom;
      const dy = (e.clientY - dragState.startY) / ui.zoom;
      if (!dragState.moved && Math.abs(dx) + Math.abs(dy) > DRAG_THRESHOLD) {
        dragState.moved = true;
        cardPositions[dragState.name].el.classList.add('dragging');
      }
      if (dragState.moved) {
        const cp = cardPositions[dragState.name];
        cp.x = dragState.nodeStartX + dx;
        cp.y = dragState.nodeStartY + dy;
        cp.cx = cp.x + cp.w / 2;
        cp.cy = cp.y + cp.h / 2;
        cp.el.setAttribute('transform', 'translate(' + cp.x + ' ' + cp.y + ')');
        rerouteEdgesForNode(dragState.name);
      }
    });
    window.addEventListener('mouseup', function () {
      if (dragState && dragState.moved) {
        cardPositions[dragState.name].el.classList.remove('dragging');
        suppressClickUntil = Date.now() + 80;
      }
      dragState = null;
    });

    elCardsLayer.addEventListener('click', function (e) {
      if (Date.now() < suppressClickUntil) return;
      const nodeG = e.target.closest('.erd-node');
      if (!nodeG) return;
      const name = nodeG.getAttribute('data-name');
      if (!name || !MODEL_BY_NAME[name]) return;
      if (e.target.closest('foreignObject') && !e.target.closest('[data-action="open-drawer"]')) return;
      if (name === ui.focused) {
        openDrawer(name);
      } else {
        focusModel(name, true);
      }
    });

    elZoomIn.addEventListener('click', function () { setZoom(ui.zoom * 1.2, elCanvasWrap.clientWidth / 2, elCanvasWrap.clientHeight / 2); });
    elZoomOut.addEventListener('click', function () { setZoom(ui.zoom / 1.2, elCanvasWrap.clientWidth / 2, elCanvasWrap.clientHeight / 2); });
    elZoomFit.addEventListener('click', fitToView);

    elSvg.addEventListener('dblclick', function (e) {
      if (e.target.closest('.erd-node')) return;
      fitToView();
    });
  }

  // ===== Drawer =============================================================
  function openDrawer(modelName) {
    const m = MODEL_BY_NAME[modelName];
    if (!m) return;
    elShell.classList.add('drawer-open');
    elDrawerTitle.textContent = m.name;
    elDrawerDesc.textContent = m.description || 'No description provided.';
    renderDrawerBody(m);
  }
  function closeDrawer() {
    elShell.classList.remove('drawer-open');
  }

  function renderDrawerBody(m) {
    const sections = [];
    const core = m.fields.filter(function (f) { return f.category !== 'audit' && f.category !== 'system'; });
    sections.push({ title: 'Fields', rows: core, kindClass: '' });

    if (ui.showAudit) {
      const audit = m.fields.filter(function (f) { return f.category === 'audit'; });
      if (audit.length > 0) sections.push({ title: 'Audit', rows: audit, kindClass: 'audit' });
    }
    if (ui.showSystem) {
      const sys = m.fields.filter(function (f) { return f.category === 'system'; });
      if (sys.length > 0) sections.push({ title: 'System', rows: sys, kindClass: 'system' });
    }

    let html = '';

    for (let i = 0; i < sections.length; i++) {
      const s = sections[i];
      html += ''
        + '<div class="drawer-section">'
        +   '<div class="drawer-section-title">' + esc(s.title) + '<span class="count">' + s.rows.length + '</span></div>';
      for (let j = 0; j < s.rows.length; j++) {
        const f = s.rows[j];
        const badges = [];
        if (f.category === 'primary') badges.push('<span class="erd-badge pk">PK</span>');
        if (f.category === 'fkId' && !f.pairedWith) badges.push('<span class="erd-badge fk">FK</span>');
        if (f.type.required) badges.push('<span class="erd-badge" style="background:var(--chip-bg);color:var(--dim);">REQ</span>');
        const typeText = f.category === 'relation' ? f.targetModel
                       : f.category === 'listRel' ? '[' + f.targetModel + ']'
                       : f.type.raw;
        html += ''
          + '<div class="field-row ' + s.kindClass + '">'
          +   '<span class="badges">' + badges.join('') + '</span>'
          +   '<span class="field-row-name">' + esc(f.name) + '</span>'
          +   '<span class="field-row-type">' + esc(typeText) + '</span>'
          + (f.desc ? '<div class="field-row-desc">' + esc(f.desc) + '</div>' : '')
          + '</div>';
      }
      html += '</div>';
    }

    const outIdx = STATE.outgoing[m.name] || [];
    const inIdx  = STATE.incoming[m.name] || [];

    if (outIdx.length > 0) html += relationsSectionHTML('Outgoing relations', outIdx, true);
    if (inIdx.length > 0)  html += relationsSectionHTML('Incoming relations', inIdx, false);

    elDrawerBody.innerHTML = html;

    elDrawerBody.querySelectorAll('[data-target]').forEach(function (node) {
      node.addEventListener('click', function () {
        focusModel(node.getAttribute('data-target'), true);
      });
    });
  }

  function relationsSectionHTML(title, idxArray, outgoing) {
    let h = ''
      + '<div class="drawer-section">'
