// ============================================================================
// safeJsonForScriptTag — SINGLE-PASS variant
// ----------------------------------------------------------------------------
// OPTIMIZATION: previous version made 5 sequential .replace passes over the
// JSON string. For a multi-MB STATE, that's 5 full string scans + 4 large
// intermediate string allocations. This version walks the string once via a
// combined regex.
function safeJsonForScriptTag(obj) {
  const json = JSON.stringify(obj);
  return json.replace(
    /<\/(?:script|style|!)|<!--|-->|\u2028|\u2029/gi,
    function (m) {
      const c0 = m.charCodeAt(0);
      if (c0 === 60 /* '<' */) {
        if (m.charAt(1) === '/') return '<\\/' + m.slice(2);   // </script, </style, </!
        return '<\\!--';                                       // <!--
      }
      if (c0 === 45 /* '-' */)     return '--\\>';            // -->
      if (c0 === 0x2028)           return '\\u2028';
      /* 0x2029 */                  return '\\u2029';
    }
  );
}

// ============================================================================
// Encoding — aggressive regex-driven percent encode
// ----------------------------------------------------------------------------
// We DELIBERATELY do not use native encodeURIComponent here. Native leaves
// these characters literal:  '  (  )  *  !  ~  -  _  .
// In a ~250KB+ data URI, that ends up as ~1000+ literal apostrophes, ~3000
// literal parens, ~800 asterisks, etc. If the URI is later embedded into an
// HTML attribute that uses single-quote delimiters — a common pattern in
// screen renderers — those literal apostrophes terminate the attribute and
// the URI breaks halfway through.
//
// This encoder is aggressive: it percent-encodes EVERYTHING outside
// [A-Za-z0-9], so the resulting URI is safe in any attribute (single-quote,
// double-quote, even inline expression interpolation). Performance is good
// because the regex engine scans for matches in native code and only calls
// the JS callback once per character that actually needs encoding.
function fastEncodeURIComponent(str) {
  return str.replace(/[^A-Za-z0-9]/g, function (c) {
    const cp = c.charCodeAt(0);

    // High surrogate — need to pair with the next char (low surrogate) and
    // emit 4-byte UTF-8. Regex matches one char at a time, so we need to
    // look ahead via the offset arg.
    if (cp >= 0xD800 && cp <= 0xDBFF) {
      return ''; // handled below via the 5-arg replace path
    }
    if (cp < 0x80)  return '%' + hex2(cp);
    if (cp < 0x800) return '%' + hex2(0xC0 | (cp >> 6))
                         + '%' + hex2(0x80 | (cp & 0x3F));
    return '%' + hex2(0xE0 | (cp >> 12))
         + '%' + hex2(0x80 | ((cp >> 6) & 0x3F))
         + '%' + hex2(0x80 | (cp & 0x3F));
  });

  function hex2(n) {
    const h = n.toString(16).toUpperCase();
    return h.length === 1 ? '0' + h : h;
  }
}

// Surrogate-pair-aware variant. The simple regex above can't see the second
// half of a surrogate pair, so we pre-process: walk the string once, encode
// surrogate pairs as 4-byte UTF-8, leave everything else for the regex pass.
// For typical inputs (no astral plane chars) this loop is a no-op fast path.
const _fastEncode_inner = fastEncodeURIComponent;
function _encodeSafe(str) {
  // Fast path: no surrogates → straight to regex encoder
  let hasSurrogate = false;
  for (let i = 0; i < str.length; i++) {
    const c = str.charCodeAt(i);
    if (c >= 0xD800 && c <= 0xDFFF) { hasSurrogate = true; break; }
  }
  if (!hasSurrogate) return _fastEncode_inner(str);

  // Slow path: manual UTF-8 for any astral chars, then regex for the rest
  const parts = [];
  let runStart = 0;
  for (let i = 0; i < str.length; i++) {
    const hi = str.charCodeAt(i);
    if (hi >= 0xD800 && hi <= 0xDBFF && i + 1 < str.length) {
      if (i > runStart) parts.push(_fastEncode_inner(str.slice(runStart, i)));
      const lo = str.charCodeAt(i + 1);
      const cp = 0x10000 + ((hi - 0xD800) << 10) + (lo - 0xDC00);
      const h2 = function (n) { const h = n.toString(16).toUpperCase(); return h.length === 1 ? '0' + h : h; };
      parts.push('%' + h2(0xF0 | (cp >> 18))
              + '%' + h2(0x80 | ((cp >> 12) & 0x3F))
              + '%' + h2(0x80 | ((cp >> 6)  & 0x3F))
              + '%' + h2(0x80 | (cp & 0x3F)));
      i++;
      runStart = i + 1;
    }
  }
  if (runStart < str.length) parts.push(_fastEncode_inner(str.slice(runStart)));
  return parts.join('');
}

// ============================================================================
// Assemble + encode + return
// ============================================================================
const themeAttr = THEME === 'Dark' ? 'dark' : 'light';
const themedHead = TPL_HEAD.replace('data-theme="dark"', 'data-theme="' + themeAttr + '"');

