// Tooltip builders
function modTooltip(label, value, rank, denom, statMap) {
  const s = statMap[label] || { total:value, deployed:0, active:0, t1:0, t2:0, t3:0, elementsSum:0 };
  const lines = [
    '<b>#' + rank + ' &middot; ' + esc(label) + '</b>',
    s.total + ' screens &middot; ' + (denom > 0 ? Math.round((s.total/denom)*1000)/10 : 0) + '% of total',
    s.deployed + ' deployed (' + pct(s.deployed, s.total) + '%) &middot; ' + s.active + ' active',
    'Avg ' + (s.total > 0 ? Math.round((s.elementsSum/s.total)*10)/10 : 0) + ' elements per screen'
  ];
  if (s.t1 > 0) lines.push('<span style="color:#fca5a5;">⚠ ' + s.t1 + ' Tier 1 risk</span>');
  if (s.t2 > 0) lines.push('<span style="color:#fcd34d;">◐ ' + s.t2 + ' Tier 2 risk</span>');
  return lines.join('<br/>');
}
function simpleTooltip(label, value, rank, denom, unit) {
  const p = denom > 0 ? Math.round((value/denom)*1000)/10 : 0;
  return '<b>#' + rank + ' &middot; ' + esc(label) + '</b><br/>'
       + value + ' ' + unit + '<br/>' + p + '% of total';
}
function bloatedTooltip(label, value, rank) {
  return '<b>#' + rank + ' &middot; ' + esc(label) + '</b><br/>'
       + value + ' elements<br/>'
       + (value > 100 ? 'Severely bloated — refactor candidate' : 'High UI complexity');
}
function mapWith(data, fn, denom, statMap, unit) {
  const out = [];
  for (let i = 0; i < data.length; i++) {
    out.push({
      label: data[i].label,
      value: String(data[i].value),
      toolText: fn(data[i].label, data[i].value, i + 1, denom, statMap || unit)
    });
  }
  return out;
}

