  // ----- Most active users (stacked horizontal bar, top 10 by total) -----
  topUsers: function () {
    var userAgg = {};
    events.forEach(function (e) {
      if (!userAgg[e.user]) userAgg[e.user] = { sig: 0, ins: 0, total: 0 };
      userAgg[e.user].total++; if (e.significant) userAgg[e.user].sig++; else userAgg[e.user].ins++;
    });
    var list = Object.keys(userAgg).sort(function (a, b) { return userAgg[b].total - userAgg[a].total; }).slice(0, 10);
    var c = baseChart("Most Active Users", "Top 10 by change volume (significant vs. minor)", "Changes", "User");
    c.paletteColors = C.accent + "," + C.textMuted;
    c.showValues = "0"; c.showSum = "1";
    return {
      type: "stackedbar2d", chart: c,
      categories: [{ category: list.map(function (u) { return { label: u }; }) }],
      dataset: [
        { seriesname: "Significant",   data: list.map(function (u) { return { value: String(userAgg[u].sig) }; }) },
        { seriesname: "Insignificant", data: list.map(function (u) { return { value: String(userAgg[u].ins) }; }) }
      ]
    };
  }
};

var out = {};
Object.keys(builders).forEach(function (key) {
  try {
    out[key] = builders[key]();
  } catch (e) {
    out[key] = {
      type: "column2d",
      chart: baseChart("Unavailable", (e && e.message) || "Build error", "", ""),
      categories: [{ category: [] }],
      dataset: [{ data: [] }]
    };
  }
});
return out;

// === Fuuz Data Flow Governance Metrics v8.2 — Flow-list tooltips on integrity bars ===
// Input: $.dataFlow.edges (collection)
// Theme: $state.context.REQUEST.theme ("Dark" | "Light"). Also honors
//        $$.theme, $.theme, $.REQUEST.theme, $.context.REQUEST.theme,
//        $state.context.theme — first non-empty wins; default Light.
//
// CHANGE LOG (v8.1 → v8.2)
//   - integrityIssues bar tooltips now list the actual flow names that
//     fall into each category, so you can scan the chart and decide
//     where to dig in without flipping to the underlying table.
//   - Capped at ~10 names per tooltip with explicit "+N more" and "(N
//     beyond capture limit)" annotations. The bar value still shows the
//     true full count (`mutexUnlockMissingCt` etc.), and the underlying
//     lists retain their existing 25-flow capture cap.
//   - mutexIssueList rows now carry `unlockMissing` and `badRetries`
//     boolean flags so the two mutex bars (Unlock Missing, Retries = -1)
//     can be filtered cleanly to their respective subsets.
//   - nullPortFlowList: a per-flow rollup of the (otherwise
//     per-node-per-flow) nullPortList, used so the Null Port Refs bar
//     tooltip lists each flow once with a node count.
//   - New helper: tooltipFlowList(title, blurb, list, totalCount, opts).

// CHANGE LOG (v8 → v8.1)
//   QUERY OPTIMIZATION (timeout fix)
//   - Flow shape now read from versions.edges[0].node.flow (a JSON scalar
//     exposed directly on dataFlowVersion). The previous path walked
//     versions × dataChanges × difference.added.flow, which is the
//     audit-history payload and by far the heaviest field in the query.
//   - The companion query asks versions(first: 1, orderBy: {createdAt: DESC})
//     — only the most recent version's flow is needed for current-state
//     governance.
//   - extractFlowShape() is now a 3-liner; no version walk, no diff hunt.
//   - All detections (T1/T2/T3, security, integrity, saved refs, error
//     handling, null ports) work identically since they all consume
//     `flow.nodes[]` which the new path returns the same way.

// CHANGE LOG (v7 → v8)
//   NEW DETECTIONS
//   - unhandledErrors: flow has a fallible node (HTTP/Integrate/Mutate/
//     SavedQuery/SavedScript/JS/executeFlow/DB) AND no tryCatch AND no
//     node with logging.executionFailed === true. Not raised for trivial
//     flows that can't fail. Tracked separately from missingErrorLogging
//     (v6 signal, which only checks the log flag).
//   - noTryCatch: per-flow, no tryCatch node anywhere. Tracked for
//     informational reporting; only "unhandledErrors" rises to a table.
//   - nullPort: any node with an explicitly null port field (nextNodes,
//     tryNextNodes, catchNextNodes, or branches[].nextNodes). A missing
//     port is fine (sink nodes); null is broken routing.
//   - savedQueryRefs / savedScriptRefs: cross-reference of which flows
//     use which saved queries (savedQuery node, savedQueryId) and saved
//     scripts (savedTransformV2/savedTransform via transformId, plus
//     dataMapping via dataMappingId). Surfaces in two dedicated tables.
//
//   CHARTS
//   - integrityIssues bar gains Unhandled Errors + Null Ports bars.
//
//   TABLES (new)
//   - unhandledHtml:     flows with fallible ops and no error handling
//   - nullPortHtml:      nodes with explicit null port references
//   - savedQueriesHtml:  savedQueryId × referencing-flows
//   - savedScriptsHtml:  savedScriptId × type × referencing-flows
//
//   KPI STRIP: unchanged. New findings are detail-level, not headline.

// CHANGE LOG (v6 → v7)
//   NEW DETECTIONS
//   - hardcodedHttpCred: literal Bearer/Basic/api_key/password/AWS/JWT
//     baked into http or integrateV2 node transforms. Surfaced as a
//     separate "Security" dimension (NOT folded into T1) so the
//     operational tier donut stays clean.
//   - debugSourceCred: any node whose nd.debug block contains credential
//     patterns (test payloads pasted by developers persist forever).
//   - mutexUnlockMissing: per flow, mutexLock count > mutexUnlock count.
//     Coarse but very low false-positive rate in practice; a flow with
//     unmatched lock/unlock pairs is wrong regardless of routing.
//   - mutexBadRetries: lockRetries === -1. Severity-bumped when paired
//     with throwErrorWhenLockNotAcquired === false (silent discard +
//     infinite retry = silent deadlock).
//   - cycleRisk: iterative DFS (white/gray/black) on the node graph.
//     Detects back-edges. Stack-based so the vm2 sandbox stack limit
//     isn't a problem on large flows.
//   - selfRecursion: executeFlow whose target dataFlowId is f.id.
//   - delayNodePresent: counts delays + sums total ms.
//   - forkCombineMismatch: per-flow fork count vs combine count.
//
//   KPI STRIP
//   - Dropped:  No Error Log, Unused (now table-only).
//   - Added:    Hardcoded Creds (risk), Mutex Issues (warn).
//   - Updated 7d retained as the "good"-tone anchor (per the v6 memo:
//     the strip needs a positive signal so it doesn't read all-warnings).
//
//   RISK MODEL
//   - Operational tiers (T1/T2/T3) UNCHANGED.
//   - "Security" surfaces as its own badge in the risk table and as its
//     own card in the KPI strip. A flow can be Security AND T1/T2/T3.
//   - "Integrity" gains mutex/cycle/fork-mismatch alongside orphan/ambig.
//
//   GRAPH EXTRACTION
//   - collectPortRefs() walks nd.data.nextNodes, nd.nextNodes,
//     nd.data.tryNextNodes, nd.data.catchNextNodes, and
//     nd.data.branches[].nextNodes. Handles both string-id and
//     {id} object refs since the flow shape isn't documented at that
//     level of granularity.

const NOW = $moment().valueOf();
const DAY = 86400000;
const D7  = NOW -  7 * DAY;
const D30 = NOW - 30 * DAY;
const D90 = NOW - 90 * DAY;

// ===== Theme — Fuuz convention: literal 'Light' or 'Dark' =====
const _theme = ($state && $state.context && $state.context.REQUEST && $state.context.REQUEST.theme)
            || (typeof $$ !== 'undefined' && $$ && $$.theme)
            || ($ && $.theme)
            || ($ && $.REQUEST && $.REQUEST.theme)
            || ($ && $.context && $.context.REQUEST && $.context.REQUEST.theme)
            || ($state && $state.context && $state.context.theme)
            || '';
const THEME = _theme === 'Dark' ? 'Dark' : 'Light';

const C = THEME === 'Dark' ? {
  bg:'#1e293b', bgDeeper:'#0f172a',
  border:'rgba(148,163,184,0.18)', divLine:'rgba(148,163,184,0.12)',
  text:'#e2e8f0', textMuted:'#94a3b8',
  accent:'#3b82f6', good:'#10b981', warn:'#f59e0b', risk:'#ef4444',
  security:'#ec4899',
  tooltipBg:'#0f172a', tooltipBd:'#3b82f6',
  palette:['#3b82f6','#10b981','#f59e0b','#a855f7','#06b6d4','#ec4899','#84cc16','#f97316','#8b5cf6','#14b8a6','#eab308','#ef4444']
} : {
  bg:'#ffffff', bgDeeper:'#f8fafc',
  border:'rgba(15,23,42,0.10)', divLine:'rgba(15,23,42,0.08)',
  text:'#0f172a', textMuted:'#64748b',
  accent:'#2563eb', good:'#059669', warn:'#d97706', risk:'#dc2626',
  security:'#db2777',
  tooltipBg:'#0f172a', tooltipBd:'#2563eb',
  palette:['#2563eb','#059669','#d97706','#9333ea','#0891b2','#db2777','#65a30d','#ea580c','#7c3aed','#0d9488','#ca8a04','#dc2626']
};

const edges = ($ && $.dataFlow && $.dataFlow.edges) ? $.dataFlow.edges : [];
const flows = [];
for (let i = 0; i < edges.length; i++) {
  if (edges[i] && edges[i].node) flows.push(edges[i].node);
}
const total = flows.length;

// ===== Risk detection patterns =====
const DELETE_RX            = /\b(delete|remove|purge|drop|truncate)\w*\s*\(/i;
const INTEGRATE_RX         = /\$(integrate|publish|emit|broadcast)\s*\(/;
const DESTRUCTIVE_PATH_RX  = /\/(delete|remove|purge|reset|wipe|clear|destroy|cancel|revoke|expire|abort|kill|terminate)(\/[^/]*)?(\?|$)/i;

// ===== Credential detection patterns =====
// Strategy: look for literal-looking secrets, not JSONata variable refs.
// JSONata literals are quoted strings. A real credential reference would
// be `$.token` or `claims.apiKey` — NO quotes around the value part. So
// we anchor on quoted tokens of sufficient entropy.
// Each pattern returns the matched signal name on hit.
const CRED_PATTERNS = [
  { name: 'aws-access-key',  rx: /\bAKIA[0-9A-Z]{16}\b/ },
  { name: 'jwt',             rx: /\beyJ[A-Za-z0-9_\-]{8,}\.[A-Za-z0-9_\-]{8,}\.[A-Za-z0-9_\-]{8,}\b/ },
  { name: 'bearer-literal',  rx: /["'`]\s*Bearer\s+[A-Za-z0-9._\-+/=]{16,}\s*["'`]/i },
  { name: 'basic-literal',   rx: /["'`]\s*Basic\s+[A-Za-z0-9+/=]{16,}\s*["'`]/i },
  { name: 'authz-header',    rx: /["'`]?\s*authorization\s*["'`]?\s*[:=]\s*["'`]\s*(Bearer|Basic|Token|Key)\s+[A-Za-z0-9._\-+/=]{8,}/i },
  { name: 'api-key-literal', rx: /["'`]?\s*(api[_\-]?key|apikey|x[\-_]api[\-_]key)\s*["'`]?\s*[:=]\s*["'`][A-Za-z0-9._\-+/=]{12,}["'`]/i },
  { name: 'password-literal',rx: /["'`]?\s*(password|passwd|pwd)\s*["'`]?\s*[:=]\s*["'`][^"'`\s]{6,}["'`]/i },
  { name: 'secret-literal',  rx: /["'`]?\s*(secret|client[_\-]?secret|access[_\-]?token|refresh[_\-]?token)\s*["'`]?\s*[:=]\s*["'`][A-Za-z0-9._\-+/=]{12,}["'`]/i }
];

function findCredHits(text) {
  if (!text) return [];
  const s = String(text);
  const hits = [];
  for (let i = 0; i < CRED_PATTERNS.length; i++) {
    if (CRED_PATTERNS[i].rx.test(s)) hits.push(CRED_PATTERNS[i].name);
  }
  return hits;
}

// Nodes that can fail at runtime — used to gate the "unhandledErrors"
// check. A flow without a tryCatch is only flagged if it contains at
// least one of these. set-context, transform, switch, fork, etc. are
// non-fallible and don't require error handling.
const FALLIBLE_NODES = {
  // HTTP / Integration
  http: 1, integrateV2: 1, request: 1, integrate: 1, restApi: 1,
  // Database
  mssql: 1, odbcV2: 1, ftp: 1, sftp: 1,
  // Fuuz API
  query: 1, mutate: 1, savedQuery: 1,
  // Saved transforms
  savedTransformV2: 1, savedTransform: 1, dataMapping: 1,
  // Code
  javascriptTransform: 1, script: 1,
  // Sub-flow
  executeFlow: 1,
  // Side effects
  notification: 1, email: 1, sms: 1,
  // Concurrency primitives that can throw
  combine: 1, mutexLock: 1,
  // Validation
  validate: 1
};

// Detect explicit null in any port field on a node. Returns array of
// field names that are null; empty array if none.
function findNullPorts(node) {
  if (!node) return [];
  const d = node.data || {};
  const hits = [];
  // node-level nextNodes — older flow shapes put it here
  if (node.nextNodes === null) hits.push('node.nextNodes');
  if (d.nextNodes === null)       hits.push('data.nextNodes');
  if (d.tryNextNodes === null)    hits.push('data.tryNextNodes');
  if (d.catchNextNodes === null)  hits.push('data.catchNextNodes');
  if (Array.isArray(d.branches)) {
    for (let i = 0; i < d.branches.length; i++) {
      const b = d.branches[i];
      if (b && b.nextNodes === null) {
        hits.push('branches[' + i + '].nextNodes' + (b.name ? ' (' + b.name + ')' : ''));
      }
    }
  }
  return hits;
}

function classifyHttp(method, url, body) {
  const m = String(method || '').toUpperCase();
  const u = String(url || '');
  const b = String(body || '');
  if (m === 'DELETE') return { tier: 1, signal: 'httpDelete' };
  if (m === 'PUT')    return { tier: 1, signal: 'httpReplace' };
  if (m === 'POST' && (DESTRUCTIVE_PATH_RX.test(u) || DESTRUCTIVE_PATH_RX.test(b))) {
    return { tier: 1, signal: 'httpDestructivePost' };
  }
  if (m === 'POST' || m === 'PATCH') return { tier: 2, signal: 'httpWrite' };
  return { tier: 0, signal: null };
}

// ===== Graph extraction — defensive against unknown serialization =====
function pushRef(out, ref) {
  if (!ref) return;
  if (typeof ref === 'string') { out.push(ref); return; }
  if (ref.id)       { out.push(ref.id); return; }
  if (ref.nodeId)   { out.push(ref.nodeId); return; }
  if (ref.target)   { out.push(ref.target); return; }
}

function collectPortRefs(node) {
  const out = [];
  if (!node) return out;
  const d = node.data || {};

  // standard port (could live at node level or data level)
  const standard = node.nextNodes || d.nextNodes;
  if (Array.isArray(standard)) for (let i = 0; i < standard.length; i++) pushRef(out, standard[i]);

  // try/catch
  if (Array.isArray(d.tryNextNodes))   for (let i = 0; i < d.tryNextNodes.length; i++)   pushRef(out, d.tryNextNodes[i]);
  if (Array.isArray(d.catchNextNodes)) for (let i = 0; i < d.catchNextNodes.length; i++) pushRef(out, d.catchNextNodes[i]);

  // fork branches
  if (Array.isArray(d.branches)) {
    for (let i = 0; i < d.branches.length; i++) {
      const b = d.branches[i];
      if (b && Array.isArray(b.nextNodes)) {
        for (let j = 0; j < b.nextNodes.length; j++) pushRef(out, b.nextNodes[j]);
      }
    }
  }
  return out;
}

// Iterative DFS cycle detection (white=0, gray=1, black=2)
function hasCycle(adj) {
  const color = {};
  const ids = Object.keys(adj);
  for (let i = 0; i < ids.length; i++) color[ids[i]] = 0;

  for (let i = 0; i < ids.length; i++) {
    if (color[ids[i]] !== 0) continue;
    const stack = [[ids[i], 0]];
    color[ids[i]] = 1;
    while (stack.length > 0) {
      const top = stack[stack.length - 1];
      const u = top[0];
      const idx = top[1];
      const nbrs = adj[u] || [];
      if (idx >= nbrs.length) { color[u] = 2; stack.pop(); continue; }
      top[1] = idx + 1;
      const v = nbrs[idx];
      if (!v || color[v] === undefined) continue;
      if (color[v] === 1) return true;       // back edge
      if (color[v] === 0) { color[v] = 1; stack.push([v, 0]); }
    }
  }
  return false;
}

// ===== Counters =====
let active=0, inactive=0, deployed=0, neverDeployed=0;
let scheduled=0, mcpEnabled=0, substituted=0;
let withBreakpoints=0, missingErrorLogging=0;
let unused=0, elementsTotal=0;
let createdL30=0, updatedL30=0, updatedL7=0, stale=0;
let nodesSum=0, maxNodes=0, versionsSum=0;
let tier1=0, tier2=0, tier3=0;
let orphanRequest=0, ambiguousResponse=0;

// existing risk-signal counters
let sigGqlDelete=0, sigGqlWrite=0;
let sigHttpDelete=0, sigHttpReplace=0, sigHttpDestructivePost=0, sigHttpWrite=0;
let sigJs=0, sigIntegrate=0, sigBroadcast=0, sigExecutesFlow=0, sigNotifies=0;

// NEW counters
let secHttpCred=0, secDebugCred=0, secAny=0;
let mutexUnlockMissingCt=0, mutexBadRetriesCt=0, mutexAnyIssueCt=0;
let cycleRiskCt=0, selfRecursionCt=0;
let delayPresentCt=0, delayTotalMs=0;
let forkCt=0, combineCt=0, collectCt=0, forkMismatchCt=0;

// v8 counters
let unhandledErrorsCt=0, noTryCatchCt=0;
let nullPortFlowCt=0, nullPortNodeCt=0;

// Saved-object cross-reference maps
//   savedQueryRefs[id]  = { type, flowIds: {flowId:true}, flowNames: [name,...] }
//   savedScriptRefs[id] = same shape, with `type` discriminating
//     savedTransformV2 / savedTransform / dataMapping
const savedQueryRefs  = {};
const savedScriptRefs = {};

const flowTypeCt={}, moduleCt={}, moduleGroupCt={}, nodeTypeCt={};
const authorCt={}, editorCt={}, apiCt={};
const activityByDay={}, createdByDay={};

const moduleStats   = {};
const modGrpStats   = {};
const authorStats   = {};
const editorStats   = {};
const flowTypeStats = {};
const nodeTypeFlowCt= {};
const apiStats      = {};

const riskList=[], staleList=[], unusedList=[], breakpointList=[];
const orphanRequestList=[], ambiguousResponseList=[];
const hardcodedCredList=[], debugCredList=[];
const mutexIssueList=[], cycleRiskList=[], delayList=[], forkMismatchList=[];
const unhandledList=[], nullPortList=[];

function ensure(map, key, shape) {
  if (!map[key]) map[key] = shape();
  return map[key];
}
const modShape  = function () { return { total:0, deployed:0, active:0, t1:0, t2:0, t3:0, stale:0, unused:0, sec:0 }; };
const authShape = function () { return { total:0, lastCreatedMs:0, deployed:0, active:0 }; };
const editShape = function () { return { total:0, lastEditedMs:0, deployedEdits:0 }; };
const typeShape = function () { return { total:0, deployed:0, active:0 }; };
const apiShape  = function () { return { nodes:0, flows:0 }; };

function extractFlowShape(f) {
  // v8.1: shape lives directly on dataFlowVersion.flow (JSON scalar).
  // Query asks versions(first: 1, orderBy: {createdAt: DESC}) so
  // edges[0] is the most recent version.
  // Fallback to currentDeployment.dataFlowVersion.flow in case the
  // query is shaped that way instead.
  const verEdges = (f.versions && f.versions.edges) || [];
  if (verEdges.length > 0 && verEdges[0].node && verEdges[0].node.flow) {
    return verEdges[0].node.flow;
  }
  if (f.currentDeployment
   && f.currentDeployment.dataFlowVersion
   && f.currentDeployment.dataFlowVersion.flow) {
    return f.currentDeployment.dataFlowVersion.flow;
  }
  return null;
}

// ===== Main loop =====
for (let i = 0; i < flows.length; i++) {
  const f = flows[i];
  const isActive = f.active !== false;
  if (isActive) active++; else inactive++;

  const dep = (f.deployments && f.deployments.total) || 0;
  const isDeployed = dep > 0;
  if (isDeployed) deployed++; else neverDeployed++;

  if (f.schedules && f.schedules.total > 0) scheduled++;
  if (f.mcpToolConfiguration) mcpEnabled++;
  if (f.substitutedByDataFlow) substituted++;

  const elemCt = (f.elements && f.elements.total) || 0;
  elementsTotal += elemCt;
  if (elemCt === 0) {
    unused++;
    if (unusedList.length < 25) unusedList.push({
      id: f.id, name: f.name, module: (f.module && f.module.name) || '—'
    });
  }

  const cMs = f.createdAt ? $moment(f.createdAt).valueOf() : 0;
  const uMs = f.updatedAt ? $moment(f.updatedAt).valueOf() : 0;
  const isStale = uMs > 0 && uMs < D90;

  if (cMs >= D30) createdL30++;
  if (uMs >= D30) updatedL30++;
  if (uMs >= D7)  updatedL7++;
  if (isStale) {
    stale++;
    if (staleList.length < 25) {
      staleList.push({
        id: f.id, name: f.name,
        daysSinceUpdate: Math.floor((NOW - uMs) / DAY),
        module: (f.module && f.module.name) || '—',
        lastEditor: (f.updatedByUser && f.updatedByUser.email) || '—'
      });
    }
  }
  if (uMs >= D30) {
    const uk = $moment(uMs).format('YYYY-MM-DD');
    activityByDay[uk] = (activityByDay[uk] || 0) + 1;
  }
  if (cMs >= D30) {
    const ck = $moment(cMs).format('YYYY-MM-DD');
    createdByDay[ck] = (createdByDay[ck] || 0) + 1;
  }

  versionsSum += (f.versions && f.versions.total) || 0;

  const author = f.createdByUser && f.createdByUser.email;
  const editor = f.updatedByUser && f.updatedByUser.email;
  if (author) {
    authorCt[author] = (authorCt[author] || 0) + 1;
    const as = ensure(authorStats, author, authShape);
    as.total++;
    if (cMs > as.lastCreatedMs) as.lastCreatedMs = cMs;
    if (isDeployed) as.deployed++;
    if (isActive)   as.active++;
  }
  if (editor) {
    editorCt[editor] = (editorCt[editor] || 0) + 1;
    const es = ensure(editorStats, editor, editShape);
    es.total++;
    if (uMs > es.lastEditedMs) es.lastEditedMs = uMs;
    if (isDeployed) es.deployedEdits++;
  }

  const modName = f.module && f.module.name;
  const grpName = f.module && f.module.moduleGroup && f.module.moduleGroup.name;
  if (modName) {
    moduleCt[modName] = (moduleCt[modName] || 0) + 1;
    const ms = ensure(moduleStats, modName, modShape);
    ms.total++;
    if (isDeployed) ms.deployed++;
    if (isActive)   ms.active++;
    if (elemCt === 0) ms.unused++;
    if (isStale)    ms.stale++;
  }
  if (grpName) {
    moduleGroupCt[grpName] = (moduleGroupCt[grpName] || 0) + 1;
    const gs = ensure(modGrpStats, grpName, modShape);
    gs.total++;
    if (isDeployed) gs.deployed++;
    if (isActive)   gs.active++;
    if (elemCt === 0) gs.unused++;
    if (isStale)    gs.stale++;
  }

  const shape = extractFlowShape(f);

  const ftype = (f.dataFlowType && f.dataFlowType.name)
             || f.dataFlowTypeId
             || 'Uncategorized';
  flowTypeCt[ftype] = (flowTypeCt[ftype] || 0) + 1;
  const ts = ensure(flowTypeStats, ftype, typeShape);
  ts.total++;
  if (isDeployed) ts.deployed++;
  if (isActive)   ts.active++;

  const rawNodes = shape && shape.nodes;
  const nodes = Array.isArray(rawNodes) ? rawNodes : [];
  const nLen = nodes.length;
  nodesSum += nLen;
  if (nLen > maxNodes) maxNodes = nLen;

  const riskSignals = {};
  let hasBp=false, anyErrorLog=false;
  let requestCt=0, responseCt=0, branchingCt=0;
  const typesInFlow = {}, apisInFlow = {};

  // Per-flow accumulators for NEW checks
  let fHttpCredHits = [];          // [{nodeName, signals[]}, ...]
  let fDebugCredHits = [];
  let fMutexLockCt = 0, fMutexUnlockCt = 0;
  let fMutexBadRetries = [];       // [{nodeName, retries, silent}]
  let fForkCt = 0, fCombineCt = 0, fCollectCt = 0;
  let fDelays = [];                // [{nodeName, ms}]
  let fSelfRecursion = false;
  const adj = {};                  // node id -> [next ids]
  const idsInFlow = {};

  // v8 per-flow accumulators
  let fHasTryCatch = false;
  let fHasFallible = false;
  let fNullPortNodes = [];         // [{nodeName, nodeType, fields:[...]}]

  for (let n = 0; n < nodes.length; n++) {
    const nd = nodes[n];
    const t  = nd.type || 'unknown';
    const d  = nd.data || {};
    const nName = nd.name || nd.id || t;
    nodeTypeCt[t] = (nodeTypeCt[t] || 0) + 1;
    typesInFlow[t] = true;

    if (nd.id) {
      idsInFlow[nd.id] = true;
      adj[nd.id] = collectPortRefs(nd);
    }

    if (d.api) {
      const a = String(d.api).toLowerCase();
      apiCt[a] = (apiCt[a] || 0) + 1;
      apisInFlow[a] = true;
      ensure(apiStats, a, apiShape).nodes++;
    }

    // -------- existing risk signals --------
    if (t === 'mutate' && d.mutation) {
      if (DELETE_RX.test(d.mutation)) riskSignals.graphqlDelete = true;
      else riskSignals.graphqlWrite = true;
    }

    if (t === 'request') requestCt++;
    if (t === 'response') responseCt++;
    if (t === 'switch' || t === 'condition' || t === 'route') branchingCt++;

    // HTTP / Integrate write classification — covers v6 names + v7 spec names
    if (t === 'request' || t === 'integrate' || t === 'restApi' || t === 'http' || t === 'integrateV2') {
      const method = d.method || d.httpMethod;
      const url    = d.url || d.path || d.endpoint || d.httpPathTransform;
      const body   = d.body || d.payload || d.httpDataTransform || d.requestTransform;
      const cls = classifyHttp(method, url, body);
      if (cls.signal) riskSignals[cls.signal] = true;
    }

    if (t === 'script' || t === 'javascriptTransform') riskSignals.jsCode = true;
    if (t === 'transform' && d.expression && INTEGRATE_RX.test(d.expression)) riskSignals.transformIntegrate = true;
    if (t === 'broadcast' || t === 'mqttPublish' || t === 'publish') riskSignals.broadcast = true;
    if (t === 'executeFlow') riskSignals.executesFlow = true;
    if (t === 'notification' || t === 'email' || t === 'sms') riskSignals.notifies = true;

    if (nd.debug && nd.debug.breakpointEnabled === true) hasBp = true;
    if (nd.logging && nd.logging.executionFailed === true) anyErrorLog = true;

    // -------- NEW: hardcoded credentials in http/integrateV2 --------
    if (t === 'http' || t === 'integrateV2' || t === 'request' || t === 'integrate' || t === 'restApi') {
      const credText = [
        d.httpHeadersTransform || '',
        d.httpDataTransform    || '',
        d.httpPathTransform    || '',
        d.requestTransform     || '',
        d.connectionNameTransform || '',
        d.headers || '', d.body || '', d.url || ''
      ].join('\n');
      const hits = findCredHits(credText);
      if (hits.length > 0) {
        riskSignals.hardcodedHttpCred = true;
        fHttpCredHits.push({ nodeName: nName, nodeType: t, signals: hits.join(', ') });
      }
    }

    // -------- NEW: credentials in debug block (source/test payloads) --------
    if (nd.debug) {
      let debugStr;
      try { debugStr = JSON.stringify(nd.debug); } catch (e) { debugStr = String(nd.debug); }
      const dhits = findCredHits(debugStr);
      if (dhits.length > 0) {
        riskSignals.debugSourceCred = true;
        fDebugCredHits.push({ nodeName: nName, nodeType: t, signals: dhits.join(', ') });
      }
    }

    // -------- NEW: mutex tracking --------
    if (t === 'mutexLock') {
      fMutexLockCt++;
      const retries = d.lockRetries;
      const silent = d.throwErrorWhenLockNotAcquired === false || d.throwErrorWhenLockNotAcquired === undefined;
      if (retries === -1) {
        fMutexBadRetries.push({ nodeName: nName, retries: retries, silent: silent });
      }
    }
    if (t === 'mutexUnlock') fMutexUnlockCt++;

    // -------- NEW: fan-out tracking --------
    if (t === 'fork')     { fForkCt++;    forkCt++; }
    if (t === 'combine')  { fCombineCt++; combineCt++; }
    if (t === 'collect')  { fCollectCt++; collectCt++; }

    // -------- NEW: delay nodes --------
    if (t === 'delay') {
      const ms = (typeof d.delay === 'number') ? d.delay : 0;
      fDelays.push({ nodeName: nName, ms: ms });
      delayTotalMs += ms;
    }

    // -------- NEW: self-recursion via executeFlow --------
    if (t === 'executeFlow') {
      const tgt = d.dataFlowId || d.flowId || d.dataFlow || d.flow || d.targetFlowId;
      if (tgt && f.id && tgt === f.id) fSelfRecursion = true;
    }

    // -------- v8: tryCatch presence + fallible-node detection --------
    if (t === 'tryCatch') fHasTryCatch = true;
    if (FALLIBLE_NODES[t]) fHasFallible = true;

    // -------- v8: null port references --------
    const nullFields = findNullPorts(nd);
    if (nullFields.length > 0) {
      nullPortNodeCt++;
      fNullPortNodes.push({ nodeName: nName, nodeType: t, fields: nullFields });
    }

    // -------- v8: saved query refs --------
    if (t === 'savedQuery' && d.savedQueryId) {
      const sqid = String(d.savedQueryId);
      const ref = ensure(savedQueryRefs, sqid, function () {
        return { id: sqid, type: 'savedQuery', flowIds: {}, flowNames: [], modules: {} };
      });
      if (!ref.flowIds[f.id]) {
        ref.flowIds[f.id] = true;
        ref.flowNames.push(f.name);
        if (modName) ref.modules[modName] = true;
      }
    }

    // -------- v8: saved script / data mapping refs --------
    if ((t === 'savedTransformV2' || t === 'savedTransform') && d.transformId) {
      const sid = String(d.transformId);
      const sType = t === 'savedTransform' ? 'savedTransform (legacy)' : 'savedTransformV2';
      const lang = d.transformScriptLanguage || 'JSONata';
      const ref = ensure(savedScriptRefs, sid, function () {
        return { id: sid, type: sType, language: lang, flowIds: {}, flowNames: [], modules: {} };
      });
      // If a legacy ref was registered first then a v2 reference shows up,
      // prefer the non-legacy type label (one saved script is one saved
      // script; the node-version variation is incidental).
      if (sType === 'savedTransformV2') ref.type = sType;
      if (!ref.flowIds[f.id]) {
        ref.flowIds[f.id] = true;
        ref.flowNames.push(f.name);
        if (modName) ref.modules[modName] = true;
      }
    }
    if (t === 'dataMapping' && d.dataMappingId) {
      const did = String(d.dataMappingId);
      const ref = ensure(savedScriptRefs, did, function () {
        return { id: did, type: 'dataMapping', language: d.transformScriptLanguage || 'JSONata',
                 flowIds: {}, flowNames: [], modules: {} };
      });
      if (!ref.flowIds[f.id]) {
        ref.flowIds[f.id] = true;
        ref.flowNames.push(f.name);
        if (modName) ref.modules[modName] = true;
      }
    }
  }

  const tKeys = Object.keys(typesInFlow);
  for (let j = 0; j < tKeys.length; j++) nodeTypeFlowCt[tKeys[j]] = (nodeTypeFlowCt[tKeys[j]] || 0) + 1;
  const aKeys = Object.keys(apisInFlow);
  for (let j = 0; j < aKeys.length; j++) ensure(apiStats, aKeys[j], apiShape).flows++;

  // Integrity flags (existing)
  const isOrphanRequest = requestCt > 0 && responseCt === 0;
  const isAmbiguousResponse = responseCt > 1 && branchingCt === 0;

  if (isOrphanRequest) {
    orphanRequest++;
    if (orphanRequestList.length < 25) orphanRequestList.push({
      id: f.id, name: f.name,
      module: modName || '—',
      requestNodes: requestCt
    });
  }
  if (isAmbiguousResponse) {
    ambiguousResponse++;
    if (ambiguousResponseList.length < 25) ambiguousResponseList.push({
      id: f.id, name: f.name,
      module: modName || '—',
      responseNodes: responseCt
    });
  }

  // -------- NEW: per-flow integrity findings --------
  const fMutexUnlockMissing = fMutexLockCt > fMutexUnlockCt;
  const fHasMutexIssue = fMutexUnlockMissing || fMutexBadRetries.length > 0;
  const fHasCycle = idsInFlow && Object.keys(adj).length > 0 ? hasCycle(adj) : false;
  const fForkMismatch = fForkCt !== fCombineCt;

  if (fMutexUnlockMissing) {
    mutexUnlockMissingCt++;
    riskSignals.mutexUnlockMissing = true;
  }
  if (fMutexBadRetries.length > 0) {
    mutexBadRetriesCt++;
    riskSignals.mutexBadRetries = true;
  }
  if (fHasMutexIssue) {
    mutexAnyIssueCt++;
    if (mutexIssueList.length < 25) {
      const parts = [];
      if (fMutexUnlockMissing) parts.push(fMutexLockCt + ' lock / ' + fMutexUnlockCt + ' unlock');
      for (let k = 0; k < fMutexBadRetries.length; k++) {
        const br = fMutexBadRetries[k];
        parts.push(br.nodeName + ' retries=-1' + (br.silent ? ' (silent)' : ''));
      }
      mutexIssueList.push({
        id: f.id, name: f.name,
        module: modName || '—',
        issue: parts.join('; '),
        unlockMissing: fMutexUnlockMissing,
        badRetries: fMutexBadRetries.length > 0
      });
    }
  }
  if (fHasCycle || fSelfRecursion) {
    cycleRiskCt++;
    if (fSelfRecursion) selfRecursionCt++;
    riskSignals.cycleRisk = true;
    if (cycleRiskList.length < 25) cycleRiskList.push({
      id: f.id, name: f.name,
      module: modName || '—',
      pattern: fSelfRecursion ? 'self-recursion (executeFlow)' : 'cycle in node graph'
    });
  }
  if (fDelays.length > 0) {
    delayPresentCt++;
    if (delayList.length < 25) {
      let sumMs = 0; const names = [];
      for (let k = 0; k < fDelays.length; k++) { sumMs += fDelays[k].ms; names.push(fDelays[k].nodeName); }
      delayList.push({
        id: f.id, name: f.name,
        module: modName || '—',
        delayCount: fDelays.length,
        totalMs: sumMs,
        humanTotal: sumMs >= 1000 ? (Math.round(sumMs / 100) / 10) + 's' : sumMs + 'ms'
      });
    }
  }
  if (fForkMismatch && (fForkCt > 0 || fCombineCt > 0)) {
    forkMismatchCt++;
    if (forkMismatchList.length < 25) forkMismatchList.push({
      id: f.id, name: f.name,
      module: modName || '—',
      forks: fForkCt,
      combines: fCombineCt
    });
  }
  if (fHttpCredHits.length > 0) {
    secHttpCred++;
    if (hardcodedCredList.length < 25) {
      const names = []; const sigs = {};
      for (let k = 0; k < fHttpCredHits.length; k++) {
        names.push(fHttpCredHits[k].nodeName);
        const s = fHttpCredHits[k].signals.split(', ');
        for (let m = 0; m < s.length; m++) sigs[s[m]] = true;
      }
      hardcodedCredList.push({
        id: f.id, name: f.name,
        module: modName || '—',
        nodes: names.join(', '),
        signals: Object.keys(sigs).join(', ')
      });
    }
  }
  if (fDebugCredHits.length > 0) {
    secDebugCred++;
    if (debugCredList.length < 25) {
      const names = []; const sigs = {};
      for (let k = 0; k < fDebugCredHits.length; k++) {
        names.push(fDebugCredHits[k].nodeName);
        const s = fDebugCredHits[k].signals.split(', ');
        for (let m = 0; m < s.length; m++) sigs[s[m]] = true;
      }
      debugCredList.push({
        id: f.id, name: f.name,
        module: modName || '—',
        nodes: names.join(', '),
        signals: Object.keys(sigs).join(', ')
      });
    }
  }

  // -------- v8: error-handling rollup --------
  if (!fHasTryCatch && nodes.length > 0) noTryCatchCt++;
  const fUnhandled = fHasFallible && !fHasTryCatch && !anyErrorLog;
  if (fUnhandled) {
    unhandledErrorsCt++;
    if (unhandledList.length < 25) unhandledList.push({
      id: f.id, name: f.name,
      module: modName || '—',
      // Briefly describe WHY this is fallible — pick a representative
      // node type to help the user prioritize. We don't have the list
      // of types in scope here; just rely on having at least one.
      // Detail enrichment can come from a follow-up tooltip if needed.
      protection: 'none (no tryCatch, no logging)'
    });
  }

  // -------- v8: null-port rollup --------
  if (fNullPortNodes.length > 0) {
    nullPortFlowCt++;
    if (nullPortList.length < 25) {
      // Flatten: one row per (flow, node) so the table is actionable.
      // Cap rows per flow so a single broken flow doesn't dominate.
      const perFlowCap = 5;
      const take = Math.min(fNullPortNodes.length, perFlowCap);
      for (let k = 0; k < take && nullPortList.length < 25; k++) {
        const np = fNullPortNodes[k];
        nullPortList.push({
          id: f.id, name: f.name,
          module: modName || '—',
          nodeName: np.nodeName,
          nodeType: np.nodeType,
          fields: np.fields.join(', ')
        });
      }
    }
  }

  // -------- existing signal counters --------
  if (riskSignals.graphqlDelete)        sigGqlDelete++;
  if (riskSignals.graphqlWrite)         sigGqlWrite++;
  if (riskSignals.httpDelete)           sigHttpDelete++;
  if (riskSignals.httpReplace)          sigHttpReplace++;
  if (riskSignals.httpDestructivePost)  sigHttpDestructivePost++;
  if (riskSignals.httpWrite)            sigHttpWrite++;
  if (riskSignals.jsCode)               sigJs++;
  if (riskSignals.transformIntegrate)   sigIntegrate++;
  if (riskSignals.broadcast)            sigBroadcast++;
  if (riskSignals.executesFlow)         sigExecutesFlow++;
  if (riskSignals.notifies)             sigNotifies++;

  // Operational tier (T1/T2/T3) — UNCHANGED
  let riskTier = 0;
  if (riskSignals.graphqlDelete || riskSignals.httpDelete
   || riskSignals.httpReplace   || riskSignals.httpDestructivePost) riskTier = 1;
  else if (riskSignals.graphqlWrite || riskSignals.httpWrite)        riskTier = 2;
  else if (riskSignals.jsCode || riskSignals.transformIntegrate
        || riskSignals.broadcast || riskSignals.executesFlow
        || riskSignals.notifies)                                     riskTier = 3;

  // Security flag — parallel dimension
  const hasSecurity = !!(riskSignals.hardcodedHttpCred || riskSignals.debugSourceCred);
  if (hasSecurity) {
    secAny++;
    if (modName) ensure(moduleStats, modName, modShape).sec++;
    if (grpName) ensure(modGrpStats, grpName, modShape).sec++;
  }

  if (riskTier === 1) {
    tier1++;
    if (modName) ensure(moduleStats, modName, modShape).t1++;
    if (grpName) ensure(modGrpStats, grpName, modShape).t1++;
  } else if (riskTier === 2) {
    tier2++;
    if (modName) ensure(moduleStats, modName, modShape).t2++;
    if (grpName) ensure(modGrpStats, grpName, modShape).t2++;
  } else if (riskTier === 3) {
    tier3++;
    if (modName) ensure(moduleStats, modName, modShape).t3++;
    if (grpName) ensure(modGrpStats, grpName, modShape).t3++;
  }

  // A flow appears in riskList if it has ANY signal — operational tier OR security
  if ((riskTier > 0 || hasSecurity) && riskList.length < 50) {
    const sigKeys = Object.keys(riskSignals).sort();
    // Display tier: SEC trumps T1 display? No — show operational tier as primary,
    // security as an additional badge column. If no operational tier but security
    // exists, display tier = SEC.
    const displayTier = riskTier > 0 ? ('T' + riskTier) : 'SEC';
    const displayNum  = riskTier > 0 ? riskTier : 0; // SEC sorts first (above T1)
    riskList.push({
      id: f.id,
      name: f.name,
      tier: displayTier,
      tierNum: displayNum,
      security: hasSecurity ? 'Yes' : '—',
      module: modName || '—',
      signals: sigKeys.join(', ') || '—',
      elementsReferencing: elemCt,
      active: isActive ? 'Yes' : 'No'
    });
  }

  if (hasBp) {
    withBreakpoints++;
    if (breakpointList.length < 25) breakpointList.push({
      id: f.id, name: f.name, module: modName || '—'
    });
  }
  if (!anyErrorLog && nodes.length > 0) missingErrorLogging++;
}

// Sort: security first (tierNum 0), then T1, T2, T3
riskList.sort(function (a, b) {
  if (a.tierNum !== b.tierNum) return a.tierNum - b.tierNum;
  if (a.security !== b.security) return a.security === 'Yes' ? -1 : 1;
  return (b.elementsReferencing || 0) - (a.elementsReferencing || 0);
});

// ===== Helpers =====
function topN(m, n) {
  const a = [], ks = Object.keys(m);
  for (let i = 0; i < ks.length; i++) a.push({ label: ks[i], value: m[ks[i]] });
  a.sort(function (x, y) { return y.value - x.value; });
  return a.slice(0, n);
}
const r1  = function (x) { const n = Number(x); return isFinite(n) ? Math.round(n * 10) / 10 : 0; };
const pct = function (n, d) { return d > 0 ? Math.round((n / d) * 100) : 0; };
const esc = function (s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
};
function sumValues(arr) { let s = 0; for (let i = 0; i < arr.length; i++) s += arr[i].value; return s; }
const SAFE_FMT = function (ms) { return ms > 0 ? $moment(ms).format('MMM D, YYYY') : '—'; };
const DAYS_AGO = function (ms) { return ms > 0 ? Math.floor((NOW - ms) / DAY) + 'd ago' : 'never'; };

// =========================================================================
// Tooltip flow-list helper (v8.2)
// =========================================================================
// Builds the HTML body for a FusionCharts bar tooltip that wants to surface
// the actual flow names behind a count. Dedupes by id (the nullPortList has
// one row per node, so a flow could appear N times; we want it once).
//
//   title       — bold header (e.g., "Orphan Request")
//   blurb       — one-line description of the category
//   list        — rows of { id, name, module, ... } captured during scan
//   totalCount  — the FULL count (e.g., orphanRequest), which may exceed
//                 list.length because lists are capped at 25 during capture
//   opts.maxShow   — names to show inline (default 10)
//   opts.detailKey — optional row field appended after the flow name
function tooltipFlowList(title, blurb, list, totalCount, opts) {
  opts = opts || {};
  const max = opts.maxShow || 10;
  let html = '<b>' + esc(title) + '</b>';
  if (blurb) html += '<br/>' + blurb;
  if (totalCount === 0) return html + '<br/><br/><i>None — ✓</i>';

  const seen = {};
  const unique = [];
  for (let i = 0; i < list.length; i++) {
    const rowId = list[i].id || list[i].name;
    if (!seen[rowId]) { seen[rowId] = true; unique.push(list[i]); }
  }

  html += '<br/><br/>';
  const shown = unique.slice(0, max);
  for (let i = 0; i < shown.length; i++) {
    const r = shown[i];
    let line = '&middot; ' + esc(r.name);
    if (r.module && r.module !== '—') line += ' [' + esc(r.module) + ']';
    if (opts.detailKey) {
      const detail = r[opts.detailKey];
      if (detail !== undefined && detail !== null && detail !== '') {
        line += ' — ' + esc(String(detail));
      }
    }
    html += line + '<br/>';
  }

  if (unique.length > max) {
    html += '<i>+' + (unique.length - max) + ' more captured</i><br/>';
  }
  if (totalCount > unique.length) {
    const beyond = totalCount - unique.length;
    html += '<i>(' + beyond + ' beyond 25-flow capture limit — see table)</i>';
  }
  return html;
}

// Per-flow null-port summary: nullPortList has one row per offending node,
// so one flow can appear up to 5 times. The bar tooltip wants one entry
// per flow with a node-count detail.
const _nullPortByFlow = {};
for (let i = 0; i < nullPortList.length; i++) {
  const r = nullPortList[i];
  if (!_nullPortByFlow[r.id]) {
    _nullPortByFlow[r.id] = { id: r.id, name: r.name, module: r.module, nodeCount: 0 };
  }
  _nullPortByFlow[r.id].nodeCount++;
}
const nullPortFlowList = [];
const _npKeys = Object.keys(_nullPortByFlow);
for (let i = 0; i < _npKeys.length; i++) {
  const s = _nullPortByFlow[_npKeys[i]];
  nullPortFlowList.push({
    id: s.id, name: s.name, module: s.module,
    nodeSummary: s.nodeCount + ' broken node' + (s.nodeCount === 1 ? '' : 's')
  });
}

// Pre-computed mutex sublists for the two mutex bars
const _mutexUnlockList = [];
const _mutexBadRetriesList = [];
for (let i = 0; i < mutexIssueList.length; i++) {
  if (mutexIssueList[i].unlockMissing) _mutexUnlockList.push(mutexIssueList[i]);
  if (mutexIssueList[i].badRetries)    _mutexBadRetriesList.push(mutexIssueList[i]);
}

// Pre-computed fork/combine mismatch summaries
const _forkMismatchList = [];
for (let i = 0; i < forkMismatchList.length; i++) {
  const r = forkMismatchList[i];
  _forkMismatchList.push({
    id: r.id, name: r.name, module: r.module,
    counts: r.forks + ' fork' + (r.forks === 1 ? '' : 's') + ' / ' + r.combines + ' combine' + (r.combines === 1 ? '' : 's')
  });
}

const nodeData     = topN(nodeTypeCt, 15);
const modData      = topN(moduleCt, 10);
const modGrpData   = topN(moduleGroupCt, 10);
const authorData   = topN(authorCt, 10);
const editorData   = topN(editorCt, 10);
const apiData      = topN(apiCt, 6);
const flowTypeData = topN(flowTypeCt, 6);

const nodesTotal   = sumValues(nodeData);
const modulesTotal = sumValues(modData);
const modGrpTotal  = sumValues(modGrpData);
const apiNodesTotal= sumValues(apiData);

const activitySeries = [];
for (let i = 29; i >= 0; i--) {
  const ms = NOW - i * DAY;
  const dk = $moment(ms).format('YYYY-MM-DD');
  const upd = activityByDay[dk] || 0;
  const cre = createdByDay[dk]  || 0;
  activitySeries.push({
    label: $moment(ms).format('MMM D'),
    value: String(upd),
    toolText: '<b>' + $moment(ms).format('ddd, MMM D YYYY') + '</b><br/>'
            + upd + ' flow' + (upd === 1 ? '' : 's') + ' updated<br/>'
            + cre + ' newly created<br/>'
            + (upd - cre) + ' edits to existing'
  });
}

const k = {
  totalFlows: total,
  activeFlows: active, inactiveFlows: inactive,
  deployedFlows: deployed, neverDeployed: neverDeployed,
  deploymentRate: pct(deployed, total),
  scheduledFlows: scheduled, mcpEnabledFlows: mcpEnabled, substitutedFlows: substituted,
  tier1Flows: tier1, tier2Flows: tier2, tier3Flows: tier3,
  flowsWithBreakpoints: withBreakpoints,
  flowsMissingErrorLogging: missingErrorLogging,
  orphanRequestFlows: orphanRequest,
  ambiguousResponseFlows: ambiguousResponse,
  unusedFlows: unused, usageRate: pct(total - unused, total),
  elementsReferencingFlows: elementsTotal, staleFlows: stale,
  avgNodesPerFlow: r1(total > 0 ? nodesSum / total : 0), maxNodesInFlow: maxNodes,
  avgVersionsPerFlow: r1(total > 0 ? versionsSum / total : 0),
  createdLast30: createdL30, updatedLast30: updatedL30, updatedLast7: updatedL7,
  // NEW
  securityFlows: secAny,
  hardcodedCredFlows: secHttpCred,
  debugCredFlows: secDebugCred,
  mutexIssueFlows: mutexAnyIssueCt,
  mutexUnlockMissingFlows: mutexUnlockMissingCt,
  mutexBadRetriesFlows: mutexBadRetriesCt,
  cycleRiskFlows: cycleRiskCt,
  selfRecursionFlows: selfRecursionCt,
  delayFlows: delayPresentCt,
  delayTotalMs: delayTotalMs,
  forkMismatchFlows: forkMismatchCt,
  // v8
