const kpiStripHtml = ''
  + '<div style="display:flex;flex-wrap:wrap;gap:10px;padding:4px 0;">'
  +   kpiCard('Total Flows',     k.totalFlows,          'in inventory',                       null)
  +   kpiCard('Deployment Rate', k.deploymentRate + '%', k.neverDeployed + ' never deployed',  null)
  +   kpiCard('Tier 1 Risk',     k.tier1Flows,          'confirmed destructive',              k.tier1Flows > 0 ? 'risk' : 'good')
  +   kpiCard('Hardcoded Creds', k.hardcodedCredFlows,  'secrets in flow definition',         k.hardcodedCredFlows > 0 ? 'risk' : 'good')
  +   kpiCard('Orphan Requests', k.orphanRequestFlows,  'request, no response',               k.orphanRequestFlows > 0 ? 'risk' : 'good')
  +   kpiCard('Mutex Issues',    k.mutexIssueFlows,     'lock/unlock or retries',             k.mutexIssueFlows > 0 ? 'warn' : 'good')
  +   kpiCard('Stale 90d+',      k.staleFlows,          'idle flows',                         k.staleFlows > 0 ? 'warn' : 'good')
  +   kpiCard('Updated 7d',      k.updatedLast7,        k.updatedLast30 + ' in 30d',          k.updatedLast7 > 0 ? 'good' : null)
