function modTooltip(label, value, rank, denom, statMap) {
  const s = statMap[label] || { total: value, deployed:0, active:0, t1:0, t2:0, t3:0, stale:0, unused:0, sec:0 };
  const lines = [
    '<b>#' + rank + ' &middot; ' + esc(label) + '</b>',
    s.total + ' flows &middot; ' + (denom > 0 ? Math.round((s.total/denom)*1000)/10 : 0) + '% of total',
    s.deployed + ' deployed (' + pct(s.deployed, s.total) + '%) &middot; ' + s.active + ' active'
  ];
  if (s.sec > 0)    lines.push('<span style="color:#f9a8d4;">⚷ ' + s.sec + ' security finding(s)</span>');
  if (s.t1 > 0)     lines.push('<span style="color:#fca5a5;">⚠ ' + s.t1 + ' Tier 1 risk</span>');
  if (s.t2 > 0)     lines.push('<span style="color:#fcd34d;">◐ ' + s.t2 + ' Tier 2 risk</span>');
  if (s.stale > 0)  lines.push('<span style="color:#fcd34d;">↻ ' + s.stale + ' stale (>90d)</span>');
  if (s.unused > 0) lines.push('<span style="color:#fcd34d;">○ ' + s.unused + ' unused</span>');
  return lines.join('<br/>');
}

function authorTooltip(label, value, rank) {
  const s = authorStats[label] || { total:value, lastCreatedMs:0, deployed:0, active:0 };
  return [
    '<b>#' + rank + ' &middot; ' + esc(label) + '</b>',
