    s.deployed + ' deployed (' + pct(s.deployed, s.total) + '%) &middot; ' + s.active + ' active',
    'Last created: ' + SAFE_FMT(s.lastCreatedMs) + ' (' + DAYS_AGO(s.lastCreatedMs) + ')'
  ].join('<br/>');
}

