  ].join('<br/>');
}

function apiTooltip(label, value, rank) {
  const s = apiStats[label] || { nodes:value, flows:0 };
  return [
    '<b>' + esc(label) + '</b>',
    s.nodes + ' node calls &middot; ' + pct(s.nodes, apiNodesTotal) + '% of API calls',
    'Used in ' + s.flows + ' flows (' + pct(s.flows, total) + '% of inventory)'
  ].join('<br/>');
