function flowTypeTooltip(label, value, rank) {
  const s = flowTypeStats[label] || { total:value, deployed:0, active:0 };
  return [
    '<b>' + esc(label) + '</b>',
    s.total + ' flows (' + pct(s.total, total) + '% of total)',
    s.deployed + ' deployed (' + pct(s.deployed, s.total) + '%) &middot; ' + s.active + ' active'
  ].join('<br/>');
}

function mapWith(data, fn, denom, statMap) {
  const out = [];
  for (let i = 0; i < data.length; i++) {
    out.push({
      label: data[i].label,
      value: String(data[i].value),
      toolText: fn(data[i].label, data[i].value, i + 1, denom, statMap)
    });
  }
  return out;
}

