// Saved-object row builders (for v8 tables)
// =========================================================================
function buildSavedRefRows(refMap, includeTypeCol) {
  const ids = Object.keys(refMap);
  const rows = [];
  for (let i = 0; i < ids.length; i++) {
    const r = refMap[ids[i]];
    const flowNames = r.flowNames.slice(0); // copy
    flowNames.sort();
    const shown = flowNames.slice(0, 5).join(', ');
    const more = flowNames.length > 5 ? ' +' + (flowNames.length - 5) + ' more' : '';
    const modNames = Object.keys(r.modules);
    modNames.sort();
    const row = {
      id: r.id,
      count: flowNames.length,
      flows: shown + more,
      modules: modNames.length === 0 ? '—'
            : modNames.length <= 3 ? modNames.join(', ')
            : modNames.slice(0, 3).join(', ') + ' +' + (modNames.length - 3)
    };
    if (includeTypeCol) {
      row.type = r.type === 'savedTransformV2'         ? 'Saved Script'
              : r.type === 'savedTransform (legacy)' ? 'Saved Script (Legacy)'
              : r.type === 'dataMapping'              ? 'Data Mapping'
              : r.type;
      row.language = r.language || '—';
    }
    rows.push(row);
  }
  rows.sort(function (a, b) { return b.count - a.count; });
  return rows;
}

const savedQueryRows  = buildSavedRefRows(savedQueryRefs,  false);
const savedScriptRows = buildSavedRefRows(savedScriptRefs, true);

const tables = {
  riskHtml: table('Risk-Bearing Flows', [
    { key: 'tier',                label: 'Tier' },
    { key: 'security',            label: 'Sec' },
    { key: 'name',                label: 'Flow' },
    { key: 'module',              label: 'Module' },
    { key: 'signals',             label: 'Signals' },
    { key: 'elementsReferencing', label: 'Used By' },
    { key: 'active',              label: 'Active' }
  ], riskList, 'risk'),

  hardcodedCredHtml: table('Hardcoded Credentials in HTTP/Integrate', [
    { key: 'name',    label: 'Flow' },
    { key: 'module',  label: 'Module' },
    { key: 'nodes',   label: 'Nodes' },
    { key: 'signals', label: 'Detected Patterns' }
  ], hardcodedCredList, 'sec'),

  debugCredHtml: table('Credentials in Debug/Test Payloads', [
