  ], staleList, 'warn'),

  unusedHtml: table('Unused Flows (0 element refs)', [
    { key: 'name',   label: 'Flow' },
    { key: 'module', label: 'Module' }
  ], unusedList, 'warn'),

  // ===== v8: new tables =====

  unhandledHtml: table('Unhandled Errors (fallible flow, no tryCatch, no error log)', [
    { key: 'name',       label: 'Flow' },
    { key: 'module',     label: 'Module' },
    { key: 'protection', label: 'Protection' }
  ], unhandledList, 'warn'),

  nullPortHtml: table('Null Port References (broken routing)', [
    { key: 'name',     label: 'Flow' },
