  ], savedQueryRows, null),

  savedScriptsHtml: table('Saved Scripts & Data Mappings Referenced by Flows', [
    { key: 'id',       label: 'ID' },
    { key: 'type',     label: 'Type' },
    { key: 'language', label: 'Lang' },
