// === Fuuz Document Design Governance Metrics — Risk-tiered, theme-aware ===
// Input: $.documentDesign.edges
// Theme: $state.context.REQUEST.theme  (also honors $$.theme, $.theme,
//        $state.context.theme — first non-empty wins; default Light)
//
// CHANGE LOG
//   - THEME default flipped to LIGHT and comparison fixed (was
//     `.toLowerCase() === 'Light'` which is never true). Now uses the
//     Fuuz convention: literal 'Light' or 'Dark' values, no case
//     normalization. Multiple signal sources accepted.
//   - donutOpts now includes the full compact mixin (showLabels:'0',
//     enableSlicing:'0', slicingDistance:'0', smartLineThickness:'0',
//     centerLabelColor/FontSize/Bold pinned, manageResize:'1') —
//     stops the outer pull-out labels overflowing and the doughnut
//     from auto-sizing past the canvas.
//   - BASE picks up manageResize:'1' + animation:'0' so every chart
//     type (bars, area, column) recomputes layout on container resize.

const NOW = $moment().valueOf();
const DAY = 86400000;
const D7  = NOW -  7 * DAY;
const D30 = NOW - 30 * DAY;
const D90 = NOW - 90 * DAY;

// ===== Theme — Fuuz convention: literal 'Light' or 'Dark' =====
// Server-side cannot auto-detect dark/light. The screen passes theme via
// the $executeFlow payload (REQUEST.theme) or on the input directly.
// Anything other than the literal 'Dark' → Light (the deployed default).
const _theme = ($state && $state.context && $state.context.REQUEST && $state.context.REQUEST.theme)
            || (typeof $$ !== 'undefined' && $$ && $$.theme)
            || ($ && $.theme)
            || ($state && $state.context && $state.context.theme)
            || '';
const THEME = _theme === 'Dark' ? 'Dark' : 'Light';

const C = THEME === 'Dark' ? {
  bg:'#1e293b', bgDeeper:'#0f172a',
  border:'rgba(148,163,184,0.18)', divLine:'rgba(148,163,184,0.12)',
  text:'#e2e8f0', textMuted:'#94a3b8',
  accent:'#3b82f6', good:'#10b981', warn:'#f59e0b', risk:'#ef4444',
  tooltipBg:'#0f172a', tooltipBd:'#3b82f6',
  palette:['#3b82f6','#10b981','#f59e0b','#a855f7','#06b6d4','#ec4899','#84cc16','#f97316','#8b5cf6','#14b8a6','#eab308','#ef4444']
} : {
  bg:'#ffffff', bgDeeper:'#f8fafc',
  border:'rgba(15,23,42,0.10)', divLine:'rgba(15,23,42,0.08)',
  text:'#0f172a', textMuted:'#64748b',
  accent:'#2563eb', good:'#059669', warn:'#d97706', risk:'#dc2626',
  tooltipBg:'#0f172a', tooltipBd:'#2563eb',
  palette:['#2563eb','#059669','#d97706','#9333ea','#0891b2','#db2777','#65a30d','#ea580c','#7c3aed','#0d9488','#ca8a04','#dc2626']
};

// ===== Parse =====
const src = ($ && $.documentDesign && $.documentDesign.edges)
         || ($state && $state.context && $state.context.documentDesigns) || [];

const docs = [];
for (let i = 0; i < src.length; i++) {
  const n = (src[i] && src[i].node) ? src[i].node : src[i];
  if (n) docs.push(n);
}
const total = docs.length;

// ===== Counters =====
let active=0, inactive=0;
let deployed=0, neverDeployed=0;
let substituted=0;
let brokenDocs=0;            // active doc, primary flow inactive
let flowSubstituted=0;       // primary flow has substitutedByDataFlow set
let noPrimaryFlow=0;         // missing primaryGenerationDataFlow entirely
let neverRendered=0;
let stale=0;
let createdL30=0, updatedL30=0, updatedL7=0;
let emptyVersions=0, singleVersion=0, multiAuthor=0;
let activeUndeployed=0, deployedInactive=0;
let missingDescription=0;
let rendersSum=0, maxRenders=0;
let versionsSum=0;
let tier1=0, tier2=0, tier3=0;

const authorCt={}, editorCt={}, versionAuthorCt={};
const activityByDay={}, createdByDay={};
const renderBuckets = { '0':0, '1-10':0, '11-100':0, '101-1k':0, '1k+':0 };

const riskList=[], brokenList=[], flowSubstitutedList=[];
const neverRenderedList=[], staleList=[];
const substitutedList=[], emptyVersionsList=[];
const activeUndeployedList=[], deployedInactiveList=[];
const topRenderedList=[];

// ===== Main loop =====
for (let i = 0; i < docs.length; i++) {
  const d = docs[i];
  const isActive = d.active !== false;
  const isDeployed = !!d.currentDeployment;
  const renders = (d.documentRenders && Number(d.documentRenders.total)) || 0;
  const flow = d.primaryGenerationDataFlow;
  const flowActive = flow ? flow.active !== false : null;
  const flowSubBy = flow ? !!flow.substitutedByDataFlow : false;
  const isStale = d.updatedByUser; // no updatedAt on this entity in the sample — use createdAt fallback

  if (isActive) active++; else inactive++;
  if (isDeployed) deployed++; else neverDeployed++;
  if (d.substitutedByDocumentDesign) {
    substituted++;
    if (substitutedList.length < 25) substitutedList.push({
      name: d.name,
      substitutes: (d.substitutedByDocumentDesign && (d.substitutedByDocumentDesign.name || d.substitutedByDocumentDesign.id)) || '—'
    });
  }
  if (!flow) {
    noPrimaryFlow++;
  } else {
    if (isActive && !flowActive) {
      brokenDocs++;
      if (brokenList.length < 25) brokenList.push({
        name: d.name, flowName: flow.name || '—', flowActive: 'No'
      });
    }
    if (flowSubBy) {
      flowSubstituted++;
      if (flowSubstitutedList.length < 25) flowSubstitutedList.push({
        name: d.name, flowName: flow.name || '—'
      });
    }
  }

  // State coherence
  if (isActive && !isDeployed) {
    activeUndeployed++;
    if (activeUndeployedList.length < 25) activeUndeployedList.push({ name: d.name });
  }
  if (!isActive && isDeployed) {
    deployedInactive++;
    if (deployedInactiveList.length < 25) deployedInactiveList.push({ name: d.name });
  }

  // Render usage
  rendersSum += renders;
  if (renders > maxRenders) maxRenders = renders;
  if (renders === 0) {
    renderBuckets['0']++;
    if (isDeployed && isActive) {
      neverRendered++;
      if (neverRenderedList.length < 25) neverRenderedList.push({
        name: d.name, deployed: 'Yes', active: 'Yes'
      });
    }
  } else if (renders <= 10)    renderBuckets['1-10']++;
  else if (renders <= 100)     renderBuckets['11-100']++;
  else if (renders <= 1000)    renderBuckets['101-1k']++;
  else                         renderBuckets['1k+']++;

  if (renders > 0) topRenderedList.push({ name: d.name, renders: renders });

  // Description hygiene
  if (!d.description || !String(d.description).trim()) missingDescription++;

  // Versions
  const verCt = (d.documentDesignVersions && Number(d.documentDesignVersions.total)) || 0;
  versionsSum += verCt;
  if (verCt === 1) singleVersion++;

  const verEdges = (d.documentDesignVersions && d.documentDesignVersions.edges) || [];
  const versionAuthorSet = {};
  for (let v = 0; v < verEdges.length; v++) {
    const vn = (verEdges[v] && verEdges[v].node) ? verEdges[v].node : verEdges[v];
    if (vn && vn.createdByUser && vn.createdByUser.email) {
      versionAuthorSet[vn.createdByUser.email] = true;
      versionAuthorCt[vn.createdByUser.email] = (versionAuthorCt[vn.createdByUser.email] || 0) + 1;
    }
    if (vn && vn.dataChanges && Number(vn.dataChanges.total) === 0) {
      emptyVersions++;
      if (emptyVersionsList.length < 25) emptyVersionsList.push({
        name: d.name, version: vn.number,
        author: (vn.createdByUser && vn.createdByUser.email) || '—'
      });
    }
  }
  if (Object.keys(versionAuthorSet).length > 1) multiAuthor++;

  // Time — sample lacks updatedAt at root; fall back to createdAt
  const cMs = d.createdAt ? $moment(d.createdAt).valueOf() : 0;
  const uMs = d.updatedAt ? $moment(d.updatedAt).valueOf() : cMs;
  if (cMs >= D30) createdL30++;
  if (uMs >= D30) updatedL30++;
  if (uMs >= D7)  updatedL7++;
  if (uMs > 0 && uMs < D90) {
    stale++;
    if (staleList.length < 25) staleList.push({
      name: d.name,
      daysSinceUpdate: Math.floor((NOW - uMs) / DAY),
      renders: renders,
      lastEditor: (d.updatedByUser && d.updatedByUser.email) || '—'
    });
  }
  if (uMs >= D30) {
    const uk = $moment(uMs).format('YYYY-MM-DD');
    activityByDay[uk] = (activityByDay[uk] || 0) + 1;
  }
  if (cMs >= D30) {
    const ck = $moment(cMs).format('YYYY-MM-DD');
    createdByDay[ck] = (createdByDay[ck] || 0) + 1;
  }

  // Authors
  const author = d.createdByUser && d.createdByUser.email;
  const editor = d.updatedByUser && d.updatedByUser.email;
  if (author) authorCt[author] = (authorCt[author] || 0) + 1;
  if (editor) editorCt[editor] = (editorCt[editor] || 0) + 1;

  // ===== Risk tier =====
  // T1: active doc with inactive/missing flow (broken — won't generate)
  // T2: active + deployed with substituted flow (out of sync), or deployed-active for >90d with 0 renders
  // T3: hygiene (missing description, empty versions, single-version)
  let tier = 0;
  const signals = [];
  if (isActive && (!flow || !flowActive)) {
    tier = 1;
    signals.push(flow ? 'flow inactive' : 'no primary flow');
  } else if (isActive && isDeployed && flowSubBy) {
    tier = 2;
    signals.push('flow substituted');
  } else if (isActive && isDeployed && renders === 0 && uMs > 0 && uMs < D90) {
    tier = 2;
    signals.push('deployed but unused (90d+)');
  } else if ((!d.description || !String(d.description).trim()) ||
             (verCt === 1 && emptyVersions > 0) ||
             verCt === 0) {
    tier = 3;
    if (!d.description || !String(d.description).trim()) signals.push('no description');
    if (verCt === 0) signals.push('no versions');
    if (verCt === 1) signals.push('single-version');
  }

  if (tier === 1) tier1++;
  else if (tier === 2) tier2++;
  else if (tier === 3) tier3++;

  if (tier > 0 && riskList.length < 50) {
    riskList.push({
      name: d.name,
      tier: 'T' + tier, tierNum: tier,
      signals: signals.join(', ') || '—',
      renders: renders,
      active: isActive ? 'Yes' : 'No',
      deployed: isDeployed ? 'Yes' : 'No'
    });
  }
}

riskList.sort(function (a, b) {
  if (a.tierNum !== b.tierNum) return a.tierNum - b.tierNum;
  return (b.renders || 0) - (a.renders || 0);
});
topRenderedList.sort(function (a, b) { return b.renders - a.renders; });
staleList.sort(function (a, b) { return b.daysSinceUpdate - a.daysSinceUpdate; });

// ===== Helpers =====
function topN(m, n) {
  const a = [], ks = Object.keys(m);
  for (let i = 0; i < ks.length; i++) a.push({ label: ks[i], value: m[ks[i]] });
  a.sort(function (x, y) { return y.value - x.value; });
  return a.slice(0, n);
}
const r1  = function (x) { const n = Number(x); return isFinite(n) ? Math.round(n * 10) / 10 : 0; };
const pct = function (n, d) { return d > 0 ? Math.round((n / d) * 100) : 0; };
const esc = function (s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
};
function sumValues(arr) { let s = 0; for (let i = 0; i < arr.length; i++) s += arr[i].value; return s; }

const authorData = topN(authorCt, 10);
const editorData = topN(editorCt, 10);
const versionAuthorData = topN(versionAuthorCt, 10);

const activitySeries = [];
for (let i = 29; i >= 0; i--) {
  const ms = NOW - i * DAY;
  const dk = $moment(ms).format('YYYY-MM-DD');
  const upd = activityByDay[dk] || 0;
  const cre = createdByDay[dk] || 0;
  activitySeries.push({
    label: $moment(ms).format('MMM D'),
    value: String(upd),
    toolText: '<b>' + $moment(ms).format('ddd, MMM D YYYY') + '</b><br/>'
            + upd + ' updated &middot; ' + cre + ' new'
  });
}

const k = {
  totalDocs: total,
  activeDocs: active, inactiveDocs: inactive,
  deployedDocs: deployed, neverDeployed: neverDeployed,
  deploymentRate: pct(deployed, total),
  substitutedDocs: substituted,
  brokenDocs: brokenDocs, flowSubstituted: flowSubstituted, noPrimaryFlow: noPrimaryFlow,
  neverRendered: neverRendered,
  totalRenders: rendersSum,
  avgRenders: r1(total > 0 ? rendersSum / total : 0),
  maxRenders: maxRenders,
  activeUndeployed: activeUndeployed, deployedInactive: deployedInactive,
  missingDescription: missingDescription,
  emptyVersions: emptyVersions, singleVersion: singleVersion, multiAuthor: multiAuthor,
  totalVersions: versionsSum,
  avgVersionsPerDoc: r1(total > 0 ? versionsSum / total : 0),
  staleDocs: stale,
  tier1Docs: tier1, tier2Docs: tier2, tier3Docs: tier3,
  createdLast30: createdL30, updatedLast30: updatedL30, updatedLast7: updatedL7
};

// ========================================================================
// KPI strip
// ========================================================================
function kpiCard(label, value, sublabel, tone) {
  const accent = tone === 'risk' ? C.risk : tone === 'warn' ? C.warn : tone === 'good' ? C.good : C.accent;
  const sub = sublabel
    ? '<div style="font-size:11px;color:' + C.textMuted + ';margin-top:4px;'
    +   'white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(sublabel) + '</div>'
    : '';
  return ''
    + '<div style="flex:1 1 150px;min-width:135px;max-width:220px;padding:14px 16px;'
    +   'background:' + C.bg + ';border:1px solid ' + C.border + ';'
    +   'border-left:3px solid ' + accent + ';border-radius:8px;'
    +   'box-shadow:0 1px 2px rgba(0,0,0,0.08);">'
    +   '<div style="font-size:10px;text-transform:uppercase;letter-spacing:0.08em;'
    +     'color:' + C.textMuted + ';font-weight:700;'
    +     'white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(label) + '</div>'
    +   '<div style="font-size:26px;font-weight:700;color:' + C.text + ';'
    +     'margin-top:6px;line-height:1;letter-spacing:-0.02em;">' + esc(value) + '</div>'
    +   sub
    + '</div>';
}

// =========================================================================
// KPI strip — daily-driver, 8 cards
// =========================================================================
// Tier 1 (inventory):  Total Documents, Deployment Rate
// Tier 2 (risk):       Tier 1 Risk, Flow Substituted
// Tier 3 (drift):      Never Rendered, Active Undeployed, Stale 90d+, Updated 7d
//
// Everything else (Active/Inactive, T2/T3 tiers, Broken Docs, No Primary Flow,
// Total/Avg Renders, Substituted, Deployed Inactive, Missing Desc, Empty
// Versions, Single-Version, Multi-Author, Avg Versions) is intentionally
// OFF the header. They're still computed in `k` and rendered in charts/
// tables below. Header is for "what do I act on today."
//
// Design notes:
//   - Tier 1 alone is the won't-generate headline; it already covers both
//     "broken docs" (active + flow inactive) and "no primary flow" sub-types.
//   - Flow Substituted gets its own risk card because it's a broken sync —
//     the doc still generates, but with stale flow logic. Same role as
//     Orphan Requests on flows / No Parent on screens / No Audit Trail on
//     models: the slot-4 "broken capability" card.
//   - Never Rendered is the document-unique signal — none of the other
//     governance dashboards have an equivalent "shipped but unused" metric.
//     Earns its place in the warn band.
//   - Updated 7d uses 'good' tone when >0 — gives the strip a positive
//     anchor so it doesn't read as all-warnings.
const kpiStripHtml = ''
  + '<div style="display:flex;flex-wrap:wrap;gap:10px;padding:4px 0;">'
  +   kpiCard('Total Documents',   k.totalDocs,         'in inventory',                       null)
  +   kpiCard('Deployment Rate',   k.deploymentRate + '%', k.neverDeployed + ' never deployed', null)
  +   kpiCard('Tier 1 Risk',       k.tier1Docs,         "broken — won't generate",            k.tier1Docs > 0 ? 'risk' : 'good')
  +   kpiCard('Flow Substituted',  k.flowSubstituted,   'pointing to deprecated flow',        k.flowSubstituted > 0 ? 'risk' : 'good')
  +   kpiCard('Never Rendered',    k.neverRendered,     'deployed but unused',                k.neverRendered > 0 ? 'warn' : 'good')
  +   kpiCard('Active Undeployed', k.activeUndeployed,  'marked live, not shipped',           k.activeUndeployed > 0 ? 'warn' : 'good')
  +   kpiCard('Stale 90d+',        k.staleDocs,         'idle documents',                     k.staleDocs > 0 ? 'warn' : 'good')
  +   kpiCard('Updated 7d',        k.updatedLast7,      k.updatedLast30 + ' in 30d',          k.updatedLast7 > 0 ? 'good' : null)
  + '</div>';

// ========================================================================
// FusionCharts
// ========================================================================
const BASE = {
  bgAlpha:'0', canvasBgAlpha:'0',
  showBorder:'0', showShadow:'0', showCanvasBorder:'0',
  // resize behavior — every chart type recomputes on container resize
  manageResize:'1', animation:'0',
  baseFont:'-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif',
  baseFontColor:C.text, baseFontSize:'12',
  captionFontColor:C.text, captionFontSize:'14', captionFontBold:'1',
  subCaptionFontColor:C.textMuted, subCaptionFontSize:'11',
  divLineColor:C.divLine, divLineAlpha:'60', divLineThickness:'1',
  showAlternateHGridColor:'0', showAlternateVGridColor:'0',
  xAxisNameFontColor:C.textMuted, xAxisNameFontSize:'11',
  yAxisNameFontColor:C.textMuted, yAxisNameFontSize:'11',
  xAxisValueFontColor:C.textMuted, xAxisValueFontSize:'11',
  yAxisValueFontColor:C.textMuted, yAxisValueFontSize:'11',
  labelFontColor:C.text, labelFontSize:'11',
  valueFontColor:C.text, valueFontSize:'11',
  useEllipsesWhenOverflow:'1', manageLabelOverflow:'1',
  toolTipBgColor:C.tooltipBg, toolTipBgAlpha:'95',
  toolTipBorderColor:C.tooltipBd, toolTipBorderRadius:'6', toolTipBorderThickness:'1',
  toolTipColor:'#f1f5f9', toolTipPadding:'8', showToolTipShadow:'1',
  legendBgAlpha:'0', legendBorderAlpha:'0', legendShadow:'0',
  legendItemFontColor:C.text, legendItemFontSize:'11',
  showValues:'0', paletteColors: C.palette.join(',')
};
function fcChart(type, caption, dataArr, extra) {
  const chart = Object.assign({ caption: caption }, BASE);
  if (extra) Object.assign(chart, extra);
  return { type: type, chart: chart, data: dataArr };
}
const CTR_PRIMARY   = 'color:' + C.text      + ';font-weight:700;font-size:14px;';
const CTR_SECONDARY = 'color:' + C.textMuted + ';font-weight:400;font-size:11px;';
function ctrLabel(line1, line2) {
  let out = '<span style="' + CTR_PRIMARY + '">' + line1 + '</span>';
  if (line2) out += '<br/><span style="' + CTR_SECONDARY + '">' + line2 + '</span>';
  return out;
}

// ===== DOUGHNUT COMPACT MIXIN =====
// Keep doughnuts inside the panel regardless of container aspect ratio.
// Outer pull-out labels are KILLED (they were overflowing); info flows:
// caption → bold center label → bottom legend (with %) → hover tooltip.
const donutOpts = {
  // Kill the outer pull-out labels — these were the culprits
  showLabels:           '0',
  showValues:           '0',
  enableSmartLabels:    '1',   // belt-and-braces if showLabels is ever flipped on
  smartLineThickness:   '0',
  // Pin the size so FC doesn't auto-size from canvas height and clip the top
  doughnutRadius:       '72',
  pieRadius:            '92',
  // No click-to-pull-out — cleaner for small panels
  enableSlicing:        '0',
  slicingDistance:      '0',
  // Legend at the bottom carries label + %
  showLegend:           '1',
  legendPosition:       'bottom',
  showPercentValues:    '1',
  showPercentInToolTip: '0',
  // Center label — explicit color/size/bold so FC theme doesn't override
  centerLabelFontSize:  '13',
  centerLabelBold:      '1',
  centerLabelColor:     C.text
};

const barOpts = {
  yAxisName:'', xAxisName:'Count',
  chartLeftMargin:'4', chartRightMargin:'14',
  chartTopMargin:'4', chartBottomMargin:'4',
  showValues:'1', placeValuesInside:'0', plotSpacePercent:'30',
  usePlotGradientColor:'0', showXAxisLine:'0', showYAxisLine:'0'
};
function simpleTooltip(label, value, rank, denom, unit) {
  const p = denom > 0 ? Math.round((value/denom)*1000)/10 : 0;
  return '<b>#' + rank + ' &middot; ' + esc(label) + '</b><br/>'
       + value + ' ' + unit + '<br/>' + p + '% of total';
}
function mapWith(data, fn, denom, unit) {
  const out = [];
  for (let i = 0; i < data.length; i++) {
    out.push({
      label: data[i].label,
      value: String(data[i].value),
      toolText: fn(data[i].label, data[i].value, i + 1, denom, unit)
    });
  }
  return out;
}

const renderBucketArr = [
  { label:'0',      value: renderBuckets['0'],      toolText:'<b>Never rendered</b><br/>' + renderBuckets['0'] + ' documents' },
  { label:'1-10',   value: renderBuckets['1-10'],   toolText:'<b>Light use</b><br/>' + renderBuckets['1-10'] + ' documents' },
  { label:'11-100', value: renderBuckets['11-100'], toolText:'<b>Regular use</b><br/>' + renderBuckets['11-100'] + ' documents' },
  { label:'101-1k', value: renderBuckets['101-1k'], toolText:'<b>Heavy use</b><br/>' + renderBuckets['101-1k'] + ' documents' },
  { label:'1k+',    value: renderBuckets['1k+'],    toolText:'<b>Very heavy use</b><br/>' + renderBuckets['1k+'] + ' documents' }
].map(function (x) { return { label: x.label, value: String(x.value), toolText: x.toolText }; });

const topRenderedChartData = topRenderedList.slice(0, 10).map(function (r, i) {
  return { label: r.name, value: String(r.renders),
    toolText: '<b>#' + (i+1) + ' &middot; ' + esc(r.name) + '</b><br/>'
            + r.renders + ' renders<br/>'
            + pct(r.renders, rendersSum) + '% of all renders' };
});

const charts = {
  activeStatus: fcChart('doughnut2d', 'Active vs Inactive', [
    { label:'Active',   value:String(active),   color:C.good,
      toolText:'<b>Active</b><br/>' + active + ' (' + pct(active, total) + '%)<br/>'
             + deployed + ' of these deployed' },
    { label:'Inactive', value:String(inactive), color:C.textMuted,
      toolText:'<b>Inactive</b><br/>' + inactive + ' (' + pct(inactive, total) + '%)' }
  ], Object.assign({
    defaultCenterLabel: ctrLabel(pct(active, total) + '% Active', active + ' of ' + total),
    centerLabel: ctrLabel('$label', '$value ($percentValue)')
  }, donutOpts)),

  deploymentStatus: fcChart('doughnut2d', 'Deployment Status', [
    { label:'Deployed', value:String(deployed), color:C.accent,
      toolText:'<b>Deployed</b><br/>' + deployed + ' (' + pct(deployed, total) + '%)' },
    { label:'Never Deployed', value:String(neverDeployed), color:C.textMuted,
      toolText:'<b>Never Deployed</b><br/>' + neverDeployed + ' (' + pct(neverDeployed, total) + '%)' }
  ], Object.assign({
    defaultCenterLabel: ctrLabel(k.deploymentRate + '% Deployed', deployed + ' of ' + total)
  }, donutOpts)),

  riskTiers: fcChart('doughnut2d', 'Risk Tier Distribution', [
    { label:'Tier 1 (Broken)',  value:String(tier1), color:C.risk,
      toolText:'<b>Tier 1 — Broken</b><br/>' + tier1 + ' documents<br/>'
             + 'Active but primary flow is inactive/missing<br/>'
             + 'Document generation will fail' },
    { label:'Tier 2 (Out of sync)', value:String(tier2), color:C.warn,
      toolText:'<b>Tier 2 — Out of Sync or Unused</b><br/>' + tier2 + ' documents<br/>'
             + 'Primary flow substituted, or deployed but never rendered' },
    { label:'Tier 3 (Hygiene)', value:String(tier3), color:C.accent,
      toolText:'<b>Tier 3 — Hygiene</b><br/>' + tier3 + ' documents<br/>'
             + 'Missing descriptions, empty/single-version' },
    { label:'No Risk Signal',   value:String(Math.max(0, total - tier1 - tier2 - tier3)), color:C.good,
      toolText:'<b>No Risk Signal</b><br/>Clean configuration' }
  ], Object.assign({
    defaultCenterLabel: ctrLabel((tier1+tier2+tier3) + ' at risk', 'of ' + total + ' docs')
  }, donutOpts)),

  renderVolume: fcChart('column2d', 'Render Volume Distribution', renderBucketArr, {
    subCaption: 'Documents bucketed by lifetime render count',
    xAxisName:'Renders', yAxisName:'Documents',
    showValues:'1', placeValuesInside:'0', plotSpacePercent:'30',
    showXAxisLine:'0', showYAxisLine:'0'
  }),

  topRendered: fcChart('bar2d', 'Most-Rendered Documents', topRenderedChartData,
    Object.assign({ xAxisName:'Renders' }, barOpts)),

  topAuthors: fcChart('bar2d', 'Top Authors (createdBy)',
    mapWith(authorData, simpleTooltip, sumValues(authorData), 'documents'),
    Object.assign({ xAxisName:'Documents authored' }, barOpts)),

  topEditors: fcChart('bar2d', 'Top Editors (updatedBy)',
    mapWith(editorData, simpleTooltip, sumValues(editorData), 'documents'),
    Object.assign({ xAxisName:'Documents edited' }, barOpts)),

  topVersionAuthors: fcChart('bar2d', 'Top Version Authors',
    mapWith(versionAuthorData, simpleTooltip, sumValues(versionAuthorData), 'versions'),
    Object.assign({ xAxisName:'Versions shipped' }, barOpts)),

  activity30d: fcChart('area2d', 'Update Activity (Last 30 Days)', activitySeries, {
    subCaption: k.updatedLast30 + ' documents updated this month',
    xAxisName:'', yAxisName:'Documents Updated',
    lineThickness:'2', anchorRadius:'3',
    anchorBgColor:C.accent, anchorBorderColor:C.accent, anchorBorderThickness:'2',
    plotFillAlpha:'40', showValues:'0',
    labelDisplay:'rotate', slantLabel:'1',
    labelFontSize:'10', labelStep:'3',
    setAdaptiveYMin:'1', paletteColors:C.accent,
    chartLeftMargin:'4', chartRightMargin:'14'
  })
};

// ========================================================================
// Tables
// ========================================================================
function table(title, columns, rows, tone) {
  const accent = tone === 'risk' ? C.risk : tone === 'warn' ? C.warn : C.accent;
  if (!rows.length) {
    return ''
      + '<div style="padding:16px 18px;background:' + C.bg + ';'
      +   'border:1px solid ' + C.border + ';border-left:3px solid ' + C.good + ';border-radius:8px;'
      +   'box-shadow:0 1px 2px rgba(0,0,0,0.08);">'
      +   '<div style="font-size:11px;text-transform:uppercase;letter-spacing:0.08em;'
      +     'color:' + C.textMuted + ';font-weight:700;margin-bottom:6px;">' + esc(title) + '</div>'
      +   '<div style="font-size:13px;color:' + C.good + ';font-weight:500;">No documents match. ✓</div>'
      + '</div>';
  }
  let head = '<tr>';
  for (let c = 0; c < columns.length; c++) {
    head += '<th style="text-align:left;padding:10px 12px;font-size:10px;text-transform:uppercase;'
         +    'letter-spacing:0.08em;color:' + C.textMuted + ';font-weight:700;'
         +    'border-bottom:1px solid ' + C.border + ';background:' + C.bgDeeper + ';">'
         +    esc(columns[c].label) + '</th>';
  }
  head += '</tr>';
  let body = '';
  for (let r = 0; r < rows.length; r++) {
    body += '<tr>';
    for (let c = 0; c < columns.length; c++) {
      const col = columns[c];
      const v = rows[r][col.key];
      let cellHtml;
      if (col.key === 'tier') {
        const tierColor = v === 'T1' ? C.risk : v === 'T2' ? C.warn : C.accent;
        cellHtml = '<span style="display:inline-block;font-size:11px;font-weight:700;color:' + tierColor + ';'
                 + 'padding:2px 8px;border-radius:10px;background:' + tierColor + '1F;">' + esc(v) + '</span>';
      } else {
        cellHtml = esc(v === null || v === undefined ? '—' : v);
      }
      body += '<td style="padding:9px 12px;font-size:13px;color:' + C.text + ';'
           +    'border-bottom:1px solid ' + C.divLine + ';">' + cellHtml + '</td>';
    }
    body += '</tr>';
  }
  return ''
    + '<div style="background:' + C.bg + ';'
    +   'border:1px solid ' + C.border + ';border-left:3px solid ' + accent + ';'
    +   'border-radius:8px;overflow:hidden;box-shadow:0 1px 2px rgba(0,0,0,0.08);">'
    +   '<div style="padding:12px 16px;display:flex;align-items:center;justify-content:space-between;'
    +     'border-bottom:1px solid ' + C.border + ';">'
    +     '<div style="font-size:11px;text-transform:uppercase;letter-spacing:0.08em;'
    +       'color:' + C.textMuted + ';font-weight:700;">' + esc(title) + '</div>'
    +     '<div style="font-size:12px;color:' + accent + ';font-weight:700;'
    +       'padding:3px 10px;border-radius:10px;background:' + accent + '1F;">' + rows.length + '</div>'
    +   '</div>'
    +   '<div style="max-height:400px;overflow-y:auto;">'
    +     '<table style="width:100%;border-collapse:collapse;">'
    +       '<thead>' + head + '</thead><tbody>' + body + '</tbody>'
    +     '</table>'
    +   '</div>'
    + '</div>';
}

const tables = {
  riskHtml: table('Risk-Bearing Documents', [
    { key:'tier',     label:'Tier' },
    { key:'name',     label:'Document' },
    { key:'signals',  label:'Signals' },
