  ], emptyVersionsList.slice(0, 25), 'warn'),

  substitutedHtml: table('Substituted Documents (migration)', [
    { key:'name',        label:'Document' },
    { key:'substitutes', label:'Substitutes' }
  ], substitutedList.slice(0, 25), null),

  staleHtml: table('Stale Documents (no update >90d)', [
    { key:'name',             label:'Document' },
    { key:'daysSinceUpdate',  label:'Days Idle' },
    { key:'renders',          label:'Renders' },
    { key:'lastEditor',       label:'Last Editor' }
  ], staleList.slice(0, 25), 'warn'),

  topRenderedHtml: table('Top 25 Most-Rendered Documents', [
