// =====================================================================
// SavedTransform KPI Dashboard
// JavaScript Script node. Returns the header KPI block PLUS every
// FusionCharts payload in one pass — single $executeFlow per page load,
// each Visualization reads its own key.
//
//   Input  ($$): savedTransform nodes (connection, array, single, or
//                $state.context.transforms); $$.theme is also honored as
//                a fallback signal for theme
//   Output:      { kpis, activeStatus, deploymentStatus, languageMix,
//                  topAuthors, topEditors, creationTrend,
//                  versionDistribution, domainMix, _meta }
//
// CHANGE LOG vs 0.0.1
//   - Theme default flipped to LIGHT (matches deployed environment);
//     dark mode uses bumped-brighter inks (#F2F4F8 / #B6BECC) for the
//     legibility-on-dark-bg case. Theme signal read from REQ.theme,
//     $$.theme, or $state.context.theme — first non-empty wins.
//   - Doughnut/pie outer labels hidden (showLabels:"0") to stop the
//     overflow when panels shrink; legend + center label + tooltip
//     carry the info. enableSmartLabels + manageResize folded in.
//   - plotToolText overridden per chart type with the correct macros
//     ($label/$value/$percentValue for pie+doughnut, $seriesName/$label/
//     $dataValue for category charts) and richer HTML formatting.
// =====================================================================


// ---------- 0. theme — read from any signal, LIGHT default -----------
// Server-side cannot auto-detect dark/light (no window/DOM). The screen
// should pass theme via the $executeFlow payload (REQ.theme) or directly
// on $$ ($$.theme). Anything other than the literal "dark" → light.
var REQ = ($state && $state.context && $state.context.REQUEST) || {};
var rawIn = $$;
var themeHint = (
  REQ.theme
  || (rawIn && rawIn.theme)
  || ($state && $state.context && $state.context.theme)
  || ""
).toString().toLowerCase();
var isDark = themeHint === "dark";

// Brighter inks in dark mode so axis/legend/caption text stays legible.
// Light-mode inks unchanged from the locked-in screen/model/flow palette.
var ink      = isDark ? "#F2F4F8" : "#1F2733";   // primary text
var inkMuted = isDark ? "#B6BECC" : "#5E6B7E";   // secondary text
var grid     = isDark ? "#3A4250" : "#E2E6ED";   // gridlines
var axisLine = isDark ? "#55606E" : "#C2C9D4";   // axis / scrollbar

// Tooltip surface — dark in both modes so it always pops off the panel
var tipBg   = "#1F2733";
var tipText = "#F2F4F8";


// ---------- 1. normalize input to a flat array of transform nodes ----
function unwrap(n) { return n && n.node ? n.node : n; }

var rows;
if (Array.isArray(rawIn))                                              rows = rawIn;
else if (rawIn && rawIn.edges)                                         rows = rawIn.edges;
else if (rawIn && rawIn.savedTransform && rawIn.savedTransform.edges)  rows = rawIn.savedTransform.edges;
else if (rawIn && rawIn.savedTransforms && rawIn.savedTransforms.edges) rows = rawIn.savedTransforms.edges;
else if ($state && $state.context && $state.context.transforms)        rows = $state.context.transforms;
else if (rawIn && rawIn.rows && Array.isArray(rawIn.rows))             rows = rawIn.rows;
else if (rawIn)                                                        rows = [rawIn];
else                                                                   rows = [];

var transforms = (rows || []).map(unwrap).filter(function (t) {
  return t && (t.name || t.scriptLanguage || t.versions);
});


// ---------- shared helpers -------------------------------------------
var TEAM_DOMAINS = { "fuuz.com": true, "mfgx.io": true };
var TEAM_LABEL   = "Fuuz Team";

function domainFor(email) {
  if (!email) return "Unknown";
  var at = email.lastIndexOf("@");
  var d = at >= 0 ? email.slice(at + 1).toLowerCase() : email.toLowerCase();
  return TEAM_DOMAINS[d] ? TEAM_LABEL : d;
}

function bump(obj, key, by) { obj[key] = (obj[key] || 0) + (by == null ? 1 : by); }

function weekKey(iso) {
  if (!iso) return null;
  var dt = new Date(iso);
  if (isNaN(dt.getTime())) return null;
  var d = new Date(Date.UTC(dt.getUTCFullYear(), dt.getUTCMonth(), dt.getUTCDate()));
  d.setUTCDate(d.getUTCDate() - d.getUTCDay()); // back up to Sunday
  return d.toISOString().slice(0, 10);
}
function weekLabel(key) {
  var p = key.split("-");
  return p[1] + "/" + p[2] + "/" + p[0];
}

function daysAgo(iso) {
  if (!iso) return null;
  var t = new Date(iso).getTime();
  if (isNaN(t)) return null;
  return Math.floor((Date.now() - t) / 86400000);
}

function pct(n, d) { return d > 0 ? Math.round((n / d) * 1000) / 10 : 0; }


// ---------- TOOLTIP FACTORY ------------------------------------------
// FusionCharts macros differ by chart type:
//   pie2d / doughnut2d:  $label, $value, $percentValue, $sum
//   category charts:      $seriesName, $label, $dataValue, $yDataValue
// Builders use these factories instead of inheriting baseChart's default
// so the macros line up with the chart type.
function tipShell(innerHtml) {
  return "<div style='padding:6px 9px; font-size:12px; line-height:1.45; "
       + "color:" + tipText + "; background:" + tipBg + ";'>"
       + innerHtml
       + "</div>";
}

function tipPieDoughnut(unitNoun, totalN) {
  return tipShell(
    "<b style='font-size:13px;'>$label</b><br/>"
    + "<span style='opacity:0.85;'>$value of " + totalN + " " + unitNoun + "</span><br/>"
    + "<b>$percentValue</b> of total"
  );
}

function tipBar(unitNoun) {
  return tipShell(
    "<b style='font-size:13px;'>$label</b><br/>"
    + "<b>$dataValue</b> " + unitNoun
  );
}

function tipColumn(unitNoun) {
  return tipShell(
    "<b style='font-size:13px;'>$label</b><br/>"
    + "<b>$dataValue</b> " + unitNoun
  );
}

function tipMultiSeriesWeek(unitNoun) {
  return tipShell(
    "<b style='font-size:13px;'>Week of $label</b><br/>"
    + "<span style='opacity:0.85;'>$seriesName</span><br/>"
    + "<b>$dataValue</b> " + unitNoun
  );
}


// ---------- baseChart: the shared styling contract (theme-aware) ------
function baseChart(caption, subCaption, xName, yName) {
  return {
    caption: caption || "",
    subCaption: subCaption || "",
    xAxisName: xName || "",
    yAxisName: yName || "",

    // zero outer chrome
    chartLeftMargin: "0", chartRightMargin: "0",
    chartTopMargin: "0",  chartBottomMargin: "0",
    captionPadding: "8",  canvasPadding: "0",
    captionFontBold: "1", captionFontSize: "13",
    subCaptionFontSize: "11",

    // resize behavior — recompute layout when panel changes size
    manageResize: "1",
    animation: "0",

    // transparent surface (inherits dashboard bg, flips with theme)
    bgColor: "transparent", bgAlpha: "0", canvasBgAlpha: "0",
    showBorder: "0", showCanvasBorder: "0",

    // text — the dark/light legibility fix (BOTH font-color groups)
    baseFontColor: ink, outCnvBaseFontColor: ink,
    captionFontColor: ink, subCaptionFontColor: inkMuted,
    xAxisNameFontColor: inkMuted, yAxisNameFontColor: inkMuted,
    legendItemFontColor: ink, valueFontColor: ink, sumFontColor: ink,
    labelFontColor: inkMuted,

    // long category labels wrap/rotate instead of colliding
    labelDisplay: "auto", useEllipsesWhenOverflow: "1",

    // gridlines / axis
    divLineColor: grid, divLineAlpha: "60",
    showAlternateVGridColor: "0", vDivLineColor: grid,
    yAxisValuesPadding: "12", axisLineThickness: "1",
    xAxisLineColor: axisLine, yAxisLineColor: axisLine,

    // plot — Fuuz palette
    paletteColors: "#1FA0FF,#7C5CFF,#18D7C4,#FFB020,#FF5C7C,#36C275",
    plotFillAlpha: "92", showPlotBorder: "0", use3DLighting: "0",

    // number format + legend
    formatNumberScale: "0",
    legendPosition: "bottom", legendBgAlpha: "0",
    legendBorderAlpha: "0", legendShadow: "0",
    legendItemFontSize: "11",
    showHoverEffect: "1",

    // tooltip surface (each builder overrides plotToolText with the
    // right macros for its chart type)
    toolTipBgColor:     tipBg,
    toolTipBgAlpha:     "100",
    toolTipColor:       tipText,
    toolTipBorderColor: tipBg,
    toolTipBorderAlpha: "100",
    toolTipBorderRadius: "4",
    toolTipPadding:     "0",
    toolTipSepChar:     "",

    // disable export/menu chrome
    exportEnabled: "0", toolbarButtonScale: "0",
    showFullScreenMenuItem: "0", fullScreenButton: "0",
    showContextMenu: "0"
  };
}

function makeChart(caption, subCaption, xName, yName) {
  return baseChart(caption, subCaption, xName, yName);
}

function emptyChart(type, caption, errMsg) {
  return {
    type: type,
    chart: baseChart(caption, errMsg ? "Data unavailable" : ""),
    categories: [{ category: [] }],
    dataset: []
  };
}


// ---------- 2. SINGLE-PASS ACCUMULATORS ------------------------------
var total            = transforms.length;
var activeCount      = 0;
var inactiveCount    = 0;
var deployedCount    = 0;
var undeployedCount  = 0;
var substitutedCount = 0;
var withDataChanges  = 0;
var totalVersions    = 0;
var totalDeployments = 0;

var languageCounts = {};
var authorCounts   = {};
var editorCounts   = {};
var domainCounts   = {};
var versionBuckets = { "1": 0, "2": 0, "3": 0, "4+": 0 };

var createsByWeek  = {};
var updatesByWeek  = {};
var weekSet        = {};

var authorSet      = {};
var editorSet      = {};

var recentCreated30 = 0;
var recentUpdated30 = 0;
var staleOver90     = 0;

transforms.forEach(function (t) {
  if (t.active === false) inactiveCount++; else activeCount++;

  var isDeployed = !!(t.currentDeployment || (t.deployments && t.deployments.total > 0));
  if (isDeployed) deployedCount++; else undeployedCount++;
  if (t.deployments && typeof t.deployments.total === "number") totalDeployments += t.deployments.total;

  if (t.substitutedBySavedTransform) substitutedCount++;

  var lang = (t.scriptLanguage && t.scriptLanguage.name) || "Unknown";
  bump(languageCounts, lang);

  var authorEmail = t.createdByUser && t.createdByUser.email;
  var editorEmail = t.updatedByUser && t.updatedByUser.email;
  if (authorEmail) { bump(authorCounts, authorEmail); authorSet[authorEmail] = true; }
  if (editorEmail) { bump(editorCounts, editorEmail); editorSet[editorEmail] = true; }
  bump(domainCounts, domainFor(authorEmail));

  var versionEdges = (t.versions && t.versions.edges) || [];
  var versionCount = (t.versions && typeof t.versions.total === "number")
                     ? t.versions.total
                     : versionEdges.length;
  totalVersions += versionCount;

  if (versionCount <= 1) bump(versionBuckets, "1");
  else if (versionCount === 2) bump(versionBuckets, "2");
  else if (versionCount === 3) bump(versionBuckets, "3");
  else bump(versionBuckets, "4+");

  var hasChanges = false;
  versionEdges.forEach(function (e) {
    var v = e && e.node ? e.node : e;
    if (!v) return;
    if (v.dataChanges && v.dataChanges.total > 0) hasChanges = true;

    var ck = weekKey(v.createdAt);
    var uk = weekKey(v.updatedAt);
    if (ck) { weekSet[ck] = true; bump(createsByWeek, ck); }
    if (uk && uk !== ck) { weekSet[uk] = true; bump(updatesByWeek, uk); }
  });
  if (hasChanges) withDataChanges++;

  var dC = daysAgo(t.createdAt);
  var dU = daysAgo(t.updatedAt);
  if (dC != null && dC <= 30) recentCreated30++;
  if (dU != null && dU <= 30) recentUpdated30++;
  if (dU != null && dU > 90) staleOver90++;

  var tck = weekKey(t.createdAt);
  var tuk = weekKey(t.updatedAt);
  if (tck) { weekSet[tck] = true; bump(createsByWeek, tck); }
  if (tuk && tuk !== tck) { weekSet[tuk] = true; bump(updatesByWeek, tuk); }
});

var weeks = Object.keys(weekSet).sort();


// ---------- 3. KPI BLOCK (scalar values for the header strip) --------
var kpis = {
  totalScripts:         total,
  activeScripts:        activeCount,
  activePct:            pct(activeCount, total),
  inactiveScripts:      inactiveCount,
  deployedScripts:      deployedCount,
  deploymentRate:       pct(deployedCount, total),
  undeployedScripts:    undeployedCount,
  substitutedScripts:   substitutedCount,
  totalVersions:        totalVersions,
  avgVersionsPerScript: total > 0 ? Math.round((totalVersions / total) * 10) / 10 : 0,
  scriptsWithChanges:   withDataChanges,
  totalDeployments:     totalDeployments,
  jsonataScripts:       languageCounts["JSONata"] || 0,
  javascriptScripts:    languageCounts["JavaScript"] || 0,
  distinctAuthors:      Object.keys(authorSet).length,
  distinctEditors:      Object.keys(editorSet).length,
  recentCreated30d:     recentCreated30,
  recentUpdated30d:     recentUpdated30,
  staleOver90d:         staleOver90,
  lastRefresh:          new Date().toISOString()
};


// ---------- 4. DOUGHNUT/PIE COMPACT MIXIN -----------------------------
// Hide outer pull-out labels so they don't overflow when the panel
// shrinks. Information goes: caption → center label → legend → tooltip.
function applyDoughnutCompact(c) {
  c.showLabels             = "0";     // OFF — was overflowing
  c.showValues             = "0";
  c.enableSmartLabels      = "1";     // belt-and-braces if showLabels is ever flipped on
  c.smartLineThickness     = "0";
  c.slicingDistance        = "0";
  c.enableSlicing          = "0";
  c.showLegend             = "1";
  c.legendNumColumns       = "0";     // auto
  c.legendItemFontSize     = "11";
  c.showPercentValues      = "1";
  c.showPercentInTooltip   = "1";
  c.doughnutRadius         = "62";
  c.pieRadius              = "92";
  c.centerLabelFontSize    = "13";
  c.centerLabelBold        = "1";
  c.centerLabelColor       = ink;     // explicit so it doesn't fall back to FC theme
  return c;
}


// ---------- 5. BUILDERS ----------------------------------------------

// 5a. Active vs Inactive
function buildActiveStatus() {
  try {
    var chart = makeChart("Active vs Inactive", "", "", "");
    chart.paletteColors      = "#36C275,#FF5C7C";
    chart.defaultCenterLabel = pct(activeCount, total) + "% active";
    chart.plotToolText       = tipPieDoughnut("scripts", total);
    applyDoughnutCompact(chart);

    return {
      type: "doughnut2d",
      chart: chart,
      data: [
        { label: "Active",   value: String(activeCount) },
        { label: "Inactive", value: String(inactiveCount) }
      ]
    };
  } catch (e) {
    return emptyChart("doughnut2d", "Active vs Inactive", e.message);
  }
}

// 5b. Deployment Status
function buildDeploymentStatus() {
  try {
    var chart = makeChart("Deployment Status", "", "", "");
    chart.paletteColors      = "#1FA0FF,#8A93A3";
    chart.defaultCenterLabel = pct(deployedCount, total) + "% deployed";
    chart.plotToolText       = tipPieDoughnut("scripts", total);
    applyDoughnutCompact(chart);

    return {
      type: "doughnut2d",
      chart: chart,
      data: [
        { label: "Deployed",       value: String(deployedCount) },
        { label: "Never Deployed", value: String(undeployedCount) }
      ]
    };
  } catch (e) {
    return emptyChart("doughnut2d", "Deployment Status", e.message);
  }
}

// 5c. Script Language Mix — pie (small categorical)
function buildLanguageMix() {
  try {
    var langs = Object.keys(languageCounts);
    var data = langs.map(function (l) {
      return { label: l, value: String(languageCounts[l]) };
    });

    var chart = makeChart("Script Language", "", "", "");
    chart.plotToolText = tipPieDoughnut("scripts", total);
    applyDoughnutCompact(chart);
    // pie2d — no center hole
    chart.pieRadius          = "95";
    chart.doughnutRadius     = "0";
    chart.defaultCenterLabel = "";

    return { type: "pie2d", chart: chart, data: data };
  } catch (e) {
    return emptyChart("pie2d", "Script Language", e.message);
  }
}

// 5d. Top Authors
function buildTopAuthors() {
  try {
    var entries = Object.keys(authorCounts).map(function (k) {
      return { label: k, value: authorCounts[k], dom: domainFor(k) };
    });
    entries.sort(function (a, b) { return b.value - a.value; });
    var top = entries.slice(0, 10).reverse();

    var data = top.map(function (e) {
      return { label: e.label, value: String(e.value) };
    });

    var chart = makeChart("Top Authors", "Top 10 by scripts created", "Scripts", "Author");
    chart.showValues    = "1";
    chart.valueFontSize = "10";
    chart.plotToolText  = tipBar("scripts created");

    return { type: "bar2d", chart: chart, data: data };
  } catch (e) {
    return emptyChart("bar2d", "Top Authors", e.message);
  }
}

// 5e. Top Editors
function buildTopEditors() {
  try {
    var entries = Object.keys(editorCounts).map(function (k) {
      return { label: k, value: editorCounts[k], dom: domainFor(k) };
    });
    entries.sort(function (a, b) { return b.value - a.value; });
    var top = entries.slice(0, 10).reverse();

    var data = top.map(function (e) {
      return { label: e.label, value: String(e.value) };
    });

    var chart = makeChart("Top Editors", "Top 10 by scripts edited", "Scripts", "Editor");
    chart.showValues    = "1";
    chart.valueFontSize = "10";
    chart.plotToolText  = tipBar("edits");

    return { type: "bar2d", chart: chart, data: data };
  } catch (e) {
    return emptyChart("bar2d", "Top Editors", e.message);
  }
}

// 5f. Creation/Update Trend
function buildCreationTrend() {
  try {
    var categories = [{
      category: weeks.map(function (w) { return { label: weekLabel(w) }; })
    }];

    var dataset = [
      {
        seriesname: "Created",
        data: weeks.map(function (w) { return { value: String(createsByWeek[w] || 0) }; })
      },
      {
        seriesname: "Updated",
        data: weeks.map(function (w) { return { value: String(updatesByWeek[w] || 0) }; })
      }
    ];

    var weeklyTotals = weeks.map(function (w) {
      return (createsByWeek[w] || 0) + (updatesByWeek[w] || 0);
    });
    var avg = weeklyTotals.length
      ? Math.round(weeklyTotals.reduce(function (a, b) { return a + b; }, 0) / weeklyTotals.length)
      : 0;

    var trendlines = [{
      line: [{
        startvalue:    String(avg),
        color:         isDark ? "#FFB020" : "#C77700",
        displayvalue:  "Avg " + avg,
        valueOnRight:  "1",
        thickness:     "1",
        dashed:        "1",
        dashLen:       "4",
        dashGap:       "3"
      }]
    }];

    var chart = makeChart("Script Activity", "Creates vs updates by week", "Week", "Events");
    chart.showValues            = "0";
    chart.lineThickness         = "2";
    chart.drawAnchors           = "1";
    chart.anchorRadius          = "3";
    chart.anchorBorderThickness = "1";
    chart.setAdaptiveYMin       = "1";
    chart.labelFontSize         = "9";
    chart.labelDisplay          = "rotate";
    chart.slantLabels           = "1";

    // scroll attrs
    chart.numVisiblePlot = "14";
    chart.flatScrollBars = "1";
    chart.scrollheight   = "8";
    chart.scrollColor    = axisLine;
    chart.scrollToEnd    = "0";

    chart.plotToolText = tipMultiSeriesWeek("events");

    return {
      type:       "scrollline2d",
      chart:      chart,
      categories: categories,
      dataset:    dataset,
      trendlines: trendlines
    };
  } catch (e) {
    return emptyChart("scrollline2d", "Script Activity", e.message);
  }
}

// 5g. Version Distribution
function buildVersionDistribution() {
  try {
    var labels = ["1", "2", "3", "4+"];
    var data = labels.map(function (l) {
      return { label: l + " version" + (l === "1" ? "" : "s"),
               value: String(versionBuckets[l] || 0) };
    });

    var chart = makeChart("Version Distribution", "Scripts grouped by version count",
                          "Versions", "Scripts");
    chart.showValues       = "1";
    chart.valueFontSize    = "10";
    chart.plotSpacePercent = "40";
    chart.plotToolText     = tipColumn("scripts");

    return { type: "column2d", chart: chart, data: data };
  } catch (e) {
    return emptyChart("column2d", "Version Distribution", e.message);
  }
}

// 5h. Domain Mix
function buildDomainMix() {
  try {
    var names = Object.keys(domainCounts).sort(function (a, b) {
      if (a === TEAM_LABEL) return -1;
      if (b === TEAM_LABEL) return 1;
      return a < b ? -1 : (a > b ? 1 : 0);
    });

    var data = names.map(function (n) {
      return { label: n, value: String(domainCounts[n]) };
    });

    var teamCount = domainCounts[TEAM_LABEL] || 0;

    var chart = makeChart("Authorship by Domain", "", "", "");
    chart.paletteColors      = "#1FA0FF,#7C5CFF,#18D7C4,#FFB020,#FF5C7C";
    chart.defaultCenterLabel = pct(teamCount, total) + "% Fuuz";
    chart.plotToolText       = tipPieDoughnut("scripts", total);
    applyDoughnutCompact(chart);

    return { type: "doughnut2d", chart: chart, data: data };
  } catch (e) {
    return emptyChart("doughnut2d", "Authorship by Domain", e.message);
  }
}


// ---------- 6. DISPATCH TAIL — single-call fan-out --------------------
return {
  kpis:                 kpis,
  activeStatus:         buildActiveStatus(),
  deploymentStatus:     buildDeploymentStatus(),
  languageMix:          buildLanguageMix(),
  topAuthors:           buildTopAuthors(),
  topEditors:           buildTopEditors(),
  creationTrend:        buildCreationTrend(),
  versionDistribution:  buildVersionDistribution(),
  domainMix:            buildDomainMix(),

  _meta: {
    scriptName:    "SavedTransform KPI Dashboard",
    scriptVersion: "0.0.2",
    theme:         isDark ? "dark" : "light",
    themeSource:   themeHint || "default",
    rowCount:      transforms.length,
    weekCount:     weeks.length
  }
};

// === Fuuz Saved Query Governance Metrics — Theme-aware ===
// Saved queries are named, callable GraphQL operations exposed as API
// endpoints. This dashboard surfaces (a) the API surface area, (b) the
// configuration risks — empty placeholders, hardcoded paging limits,
// connection queries missing `total`, debug artifacts — and (c) the
// activity rhythm.
//
// Inputs:
//   $.savedQuery.edges  OR  $$  OR  $state.context.savedQueries
//   $state.context.REQUEST.theme  (also honors $$.theme, $.theme,
//                                  $.REQUEST.theme, $state.context.theme;
//                                  first non-empty wins; default Light)

const NOW = $moment().valueOf();
const DAY = 86400000;
const D7  = NOW -  7 * DAY;
const D30 = NOW - 30 * DAY;
const D90 = NOW - 90 * DAY;

// ===== Theme — Fuuz convention: literal 'Light' or 'Dark' =====
const _theme = ($state && $state.context && $state.context.REQUEST && $state.context.REQUEST.theme)
            || (typeof $$ !== 'undefined' && $$ && $$.theme)
            || ($ && $.theme)
            || ($ && $.REQUEST && $.REQUEST.theme)
            || ($state && $state.context && $state.context.theme)
            || '';
const THEME = _theme === 'Dark' ? 'Dark' : 'Light';

const C = THEME === 'Dark' ? {
  bg:'#1e293b', bgDeeper:'#0f172a',
  border:'rgba(148,163,184,0.18)', divLine:'rgba(148,163,184,0.12)',
  text:'#e2e8f0', textMuted:'#94a3b8',
  accent:'#3b82f6', good:'#10b981', warn:'#f59e0b', risk:'#ef4444',
  tooltipBg:'#0f172a', tooltipBd:'#3b82f6',
  palette:['#3b82f6','#10b981','#f59e0b','#a855f7','#06b6d4','#ec4899','#84cc16','#f97316','#8b5cf6','#14b8a6','#eab308','#ef4444']
} : {
  bg:'#ffffff', bgDeeper:'#f8fafc',
  border:'rgba(15,23,42,0.10)', divLine:'rgba(15,23,42,0.08)',
  text:'#0f172a', textMuted:'#64748b',
  accent:'#2563eb', good:'#059669', warn:'#d97706', risk:'#dc2626',
  tooltipBg:'#0f172a', tooltipBd:'#2563eb',
  palette:['#2563eb','#059669','#d97706','#9333ea','#0891b2','#db2777','#65a30d','#ea580c','#7c3aed','#0d9488','#ca8a04','#dc2626']
};

// ===== Parse inputs =====
const src = ($ && $.savedQuery && $.savedQuery.edges)
         || (typeof $$ !== 'undefined' && $$ && $$.savedQuery && $$.savedQuery.edges)
         || (typeof $$ !== 'undefined' && Array.isArray($$) ? $$ : null)
         || ($state && $state.context && $state.context.savedQueries)
         || [];

const queries = [];
if (Array.isArray(src)) {
  for (let i = 0; i < src.length; i++) {
    const n = (src[i] && src[i].node) ? src[i].node : src[i];
    if (n) queries.push(n);
  }
}
const total = queries.length;

// ===== Helpers =====
const r1  = function (x) { const n = Number(x); return isFinite(n) ? Math.round(n * 10) / 10 : 0; };
const pct = function (n, d) { return d > 0 ? Math.round((n / d) * 100) : 0; };
const esc = function (s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
};
function topN(m, n) {
  const a = [], ks = Object.keys(m);
  for (let i = 0; i < ks.length; i++) a.push({ label: ks[i], value: m[ks[i]] });
  a.sort(function (x, y) { return y.value - x.value; });
  return a.slice(0, n);
}
function sumValues(arr) { let s = 0; for (let i = 0; i < arr.length; i++) s += arr[i].value; return s; }
function trim(arr, n) { return arr.slice(0, n); }

// Walk dataChanges, return the latest non-undefined value of `key`.
// queryText is full-text-replaced in `updated`, so taking the latest works.
// (savedQueryParameters can arrive as a partial diff in `updated`; for
// param COUNTS we instead derive from queryText below — more reliable.)
function latestProperty(q, key) {
  const edges = (q.dataChanges && q.dataChanges.edges) || [];
  let bestValue;
  let bestTime = -1;
  for (let i = 0; i < edges.length; i++) {
    const n = (edges[i] && edges[i].node) ? edges[i].node : edges[i];
    if (!n) continue;
    const diff = n.difference || {};
    let v;
    if (diff.updated && diff.updated[key] !== undefined) v = diff.updated[key];
    else if (diff.added && diff.added[key] !== undefined) v = diff.added[key];
    else continue;
    const t = n.changedAt ? $moment(n.changedAt).valueOf() : 0;
    if (t >= bestTime) { bestTime = t; bestValue = v; }
  }
  return bestValue;
}

// Detect quality signals from queryText.
function detectSignals(text) {
  if (!text) {
    return {
      isEmpty: true,
      operationKind: null,
      hardcodedLimit: false, hardcodedLimitValue: null,
      missingTotal: false,
      hardcodedWhere: false,
      hasDebugArtifact: false,
      uniqueParamCount: 0,
      uniqueParams: []
    };
  }
  const sig = { isEmpty: false };

  // Operation kind from queryText (fallback if savedQueryOperationType missing)
  const opMatch = /^\s*(query|mutation|subscription)\s+/m.exec(text);
  sig.operationKind = opMatch ? opMatch[1] : null;

  // Hardcoded `first: N` (perf risk — every call returns N records)
  const limitMatch = /\bfirst:\s*(\d+)/.exec(text);
  sig.hardcodedLimit = !!limitMatch;
  sig.hardcodedLimitValue = limitMatch ? parseInt(limitMatch[1], 10) : null;

  // Connection (edges) without total — pagination broken
  const edgesCount = (text.match(/\bedges\s*{/g) || []).length;
  const totalCount = (text.match(/\btotal\b/g) || []).length;
  sig.missingTotal = edgesCount > 0 && edgesCount > totalCount;

  // Hardcoded where (literal filter, not `where: $where`).
  // Looks for `where: {<non-$ char>` to skip `where: $variable`.
  sig.hardcodedWhere = /where:\s*\{[^}\s$]/.test(text);

  // Debug artifact left in production
  sig.hasDebugArtifact = /__typename/.test(text);

  // Unique parameter refs ($foo) — more reliable than savedQueryParameters
  // (which can arrive as partial diffs in `updated`)
  const refs = text.match(/\$\w+/g) || [];
  const uniq = {};
  for (let i = 0; i < refs.length; i++) uniq[refs[i]] = 1;
  sig.uniqueParams = Object.keys(uniq);
  sig.uniqueParamCount = sig.uniqueParams.length;

  return sig;
}

// Risk tiers:
//   T1: empty (broken — no queryText, cannot be called)
//   T2: hardcoded limit OR pagination broken (broken capability)
//   T3: debug artifact left in production
// hardcodedWhere is tracked but not tiered (often intentional scoping
// like `where: {active: {_eq: true}}` for active-records-only queries).
function classifyTier(sig) {
  if (sig.isEmpty) return 1;
  if (sig.hardcodedLimit || sig.missingTotal) return 2;
  if (sig.hasDebugArtifact) return 3;
  return 0;
}

// ===== Counters =====
const queriesByType = { Query: 0, Mutation: 0, Subscription: 0, Unknown: 0 };
let emptyQueries = 0;
let hardcodedLimits = 0;
let missingTotal = 0;
let hardcodedWhere = 0;
let debugArtifacts = 0;
let missingDescription = 0;
let noParameters = 0;
let singleVersion = 0;
let multiAuthor = 0;
let staleQueries = 0;
let highIteration = 0;
let createdL30 = 0, updatedL30 = 0, updatedL7 = 0;
let tier1 = 0, tier2 = 0, tier3 = 0;
let totalParamCount = 0;
let totalChangeCount = 0;

const iterationBuckets = { '0': 0, '1': 0, '2-3': 0, '4-10': 0, '10+': 0 };
const paramBuckets     = { '0': 0, '1-2': 0, '3-5': 0, '6+': 0 };
const limitValueBuckets= { '1-10': 0, '11-100': 0, '101-500': 0, '500+': 0 };

const authorCt = {};
const editorCt = {};
const activityByDay = {};
const createdByDay  = {};

const emptyList = [];
const hardcodedLimitsList = [];
const missingTotalList = [];
const hardcodedWhereList = [];
const missingDescList = [];
const staleList = [];
const mostIteratedList = [];
const multiAuthorList = [];
const riskList = [];

// ===== Main loop =====
for (let i = 0; i < queries.length; i++) {
  const q = queries[i];
  const name = q.name || '(unnamed)';
  const description = q.description || '';
  const changes = (q.dataChanges && Number(q.dataChanges.total)) || 0;

  const text = latestProperty(q, 'queryText');
  const sig = detectSignals(text);
  const tier = classifyTier(sig);

  // Operation type — prefer model field, fall back to detection
  let opLabel = (q.savedQueryOperationType && q.savedQueryOperationType.label) || null;
  if (!opLabel || opLabel === 'Unknown') {
    if (sig.operationKind === 'mutation') opLabel = 'Mutation';
    else if (sig.operationKind === 'subscription') opLabel = 'Subscription';
    else if (sig.operationKind === 'query') opLabel = 'Query';
    else opLabel = 'Unknown';
  }
  queriesByType[opLabel] = (queriesByType[opLabel] || 0) + 1;

  // Empty
  if (sig.isEmpty) {
    emptyQueries++;
    if (emptyList.length < 25) {
      const ageDays = q.createdAt ? Math.floor((NOW - $moment(q.createdAt).valueOf()) / DAY) : null;
      emptyList.push({ name: name, daysOld: ageDays !== null ? ageDays : '—', author: (q.createdByUser && q.createdByUser.email) || '—' });
    }
  }

  // Hardcoded limit
  if (sig.hardcodedLimit) {
    hardcodedLimits++;
    hardcodedLimitsList.push({ name: name, limit: sig.hardcodedLimitValue, operation: opLabel });
    const v = sig.hardcodedLimitValue;
    if (v <= 10)        limitValueBuckets['1-10']++;
    else if (v <= 100)  limitValueBuckets['11-100']++;
    else if (v <= 500)  limitValueBuckets['101-500']++;
    else                limitValueBuckets['500+']++;
  }

  // Missing total
  if (sig.missingTotal) {
    missingTotal++;
    if (missingTotalList.length < 25) missingTotalList.push({ name: name, operation: opLabel });
  }

  // Hardcoded where (tracked but not tiered)
  if (sig.hardcodedWhere) {
    hardcodedWhere++;
    if (hardcodedWhereList.length < 25) hardcodedWhereList.push({ name: name, operation: opLabel });
  }

  // Debug artifact
  if (sig.hasDebugArtifact) debugArtifacts++;

  // Description
  if (!description || description.trim() === '') {
    missingDescription++;
    if (missingDescList.length < 25) missingDescList.push({ name: name, operation: opLabel });
  }

  // Parameter counts (derived from queryText)
  const pn = sig.uniqueParamCount;
  totalParamCount += pn;
  if (pn === 0)       { paramBuckets['0']++; if (!sig.isEmpty) noParameters++; }
  else if (pn <= 2)   paramBuckets['1-2']++;
  else if (pn <= 5)   paramBuckets['3-5']++;
  else                paramBuckets['6+']++;

  // Iteration buckets
  totalChangeCount += changes;
  if (changes === 0)       iterationBuckets['0']++;
  else if (changes === 1)  { iterationBuckets['1']++; singleVersion++; }
  else if (changes <= 3)   iterationBuckets['2-3']++;
  else if (changes <= 10)  { iterationBuckets['4-10']++; highIteration++; }
  else                     { iterationBuckets['10+']++; highIteration++; }

  if (changes >= 3) {
    mostIteratedList.push({ name: name, changes: changes, operation: opLabel });
  }

  // Multi-author detection (across dataChanges)
  const authorSet = {};
  const changeEdges = (q.dataChanges && q.dataChanges.edges) || [];
  for (let j = 0; j < changeEdges.length; j++) {
    const ce = changeEdges[j];
    const cn = (ce && ce.node) ? ce.node : ce;
    if (cn && cn.changedByUser && cn.changedByUser.email) {
      authorSet[cn.changedByUser.email] = true;
    }
  }
  if (Object.keys(authorSet).length > 1) {
    multiAuthor++;
    multiAuthorList.push({ name: name, authors: Object.keys(authorSet).length });
  }

  // Top-level author/editor counts
  const author = q.createdByUser && q.createdByUser.email;
  const editor = q.updatedByUser && q.updatedByUser.email;
  if (author) authorCt[author] = (authorCt[author] || 0) + 1;
  if (editor) editorCt[editor] = (editorCt[editor] || 0) + 1;

  // Time analysis
  const cMs = q.createdAt ? $moment(q.createdAt).valueOf() : 0;
  const uMs = q.updatedAt ? $moment(q.updatedAt).valueOf() : 0;
  if (cMs >= D30) createdL30++;
  if (uMs >= D30) updatedL30++;
  if (uMs >= D7)  updatedL7++;
  if (uMs > 0 && uMs < D90) {
    staleQueries++;
    if (staleList.length < 25) staleList.push({
      name: name,
      operation: opLabel,
      daysSinceUpdate: Math.floor((NOW - uMs) / DAY),
      lastEditor: (q.updatedByUser && q.updatedByUser.email) || '—'
    });
  }
  if (uMs >= D30) {
    const uk = $moment(uMs).format('YYYY-MM-DD');
    activityByDay[uk] = (activityByDay[uk] || 0) + 1;
  }
  if (cMs >= D30) {
    const ck = $moment(cMs).format('YYYY-MM-DD');
    createdByDay[ck] = (createdByDay[ck] || 0) + 1;
  }

  // Tier counters
  if (tier === 1) tier1++;
  else if (tier === 2) tier2++;
  else if (tier === 3) tier3++;

  // Risk list
  if (tier > 0 && riskList.length < 50) {
    const signals = [];
    if (sig.isEmpty)         signals.push('empty (no queryText)');
    if (sig.hardcodedLimit)  signals.push('first: ' + sig.hardcodedLimitValue + ' hardcoded');
    if (sig.missingTotal)    signals.push('edges without total');
    if (sig.hasDebugArtifact)signals.push('__typename artifact');
    riskList.push({
      name: name,
      tier: 'T' + tier, tierNum: tier,
      operation: opLabel,
      signals: signals.join(', ') || '—',
      changes: changes,
      params: pn
    });
  }
}

// ===== Sorts =====
hardcodedLimitsList.sort(function (a, b) { return b.limit - a.limit; });
mostIteratedList.sort(function (a, b) { return b.changes - a.changes; });
staleList.sort(function (a, b) { return b.daysSinceUpdate - a.daysSinceUpdate; });
riskList.sort(function (a, b) {
  if (a.tierNum !== b.tierNum) return a.tierNum - b.tierNum;
  return (b.changes || 0) - (a.changes || 0);
});

// ===== Activity series =====
const activitySeries = [];
for (let i = 29; i >= 0; i--) {
  const ms = NOW - i * DAY;
  const dk = $moment(ms).format('YYYY-MM-DD');
  const upd = activityByDay[dk] || 0;
  const cre = createdByDay[dk]  || 0;
  activitySeries.push({
    label: $moment(ms).format('MMM D'),
    value: String(upd),
    toolText: '<b>' + $moment(ms).format('ddd, MMM D YYYY') + '</b><br/>'
            + upd + ' updated &middot; ' + cre + ' new'
  });
}

// ===== KPI aggregate =====
const k = {
  totalQueries: total,
  queryCount: queriesByType.Query,
  mutationCount: queriesByType.Mutation,
  subscriptionCount: queriesByType.Subscription,
  unknownTypeCount: queriesByType.Unknown,
  emptyQueries: emptyQueries,
  hardcodedLimits: hardcodedLimits,
  missingTotal: missingTotal,
  hardcodedWhere: hardcodedWhere,
  debugArtifacts: debugArtifacts,
  missingDescription: missingDescription,
  documentedPct: pct(total - missingDescription, total),
  noParameters: noParameters,
  avgParamsPerQuery: r1(total > 0 ? totalParamCount / total : 0),
  singleVersion: singleVersion,
  multiAuthor: multiAuthor,
  highIteration: highIteration,
  avgChangesPerQuery: r1(total > 0 ? totalChangeCount / total : 0),
  staleQueries: staleQueries,
  tier1Queries: tier1,
  tier2Queries: tier2,
  tier3Queries: tier3,
  createdLast30: createdL30,
  updatedLast30: updatedL30,
  updatedLast7: updatedL7
};

// =========================================================================
// HTML: KPI STRIP — daily-driver, 8 cards
// =========================================================================
// Tier 1 (inventory):  Total Queries, Mutations
// Tier 2 (risk):       Empty Queries, Hardcoded Limits
// Tier 3 (quality):    Pagination Broken, Missing Description, Stale 90d+, Updated 7d
//
// Everything else (Subscriptions, Queries-only count, hardcodedWhere,
// debugArtifacts, noParameters, multi-author, single-version, etc.) is
// intentionally OFF the header. All still computed in `k` and shown in
// the charts/tables below. Header is for "what do I act on today."
//
// Design notes:
//   - Mutations is a neutral inventory split (not risk tone). Mutations
//     existing isn't bad — they're a fact about your API surface. The
//     dangerous mutations would surface as Hardcoded Limits or Empty
//     instead.
//   - Empty Queries gets risk tone — these literally fail when called.
//   - Hardcoded Limits is the slot-4 "broken capability" card (every
//     call returns N rows; caller can't ask for less). Same role as
//     Orphan Requests on flows / No Audit Trail on models / No Parent
//     on screens / Flow Substituted on docs.
//   - Updated 7d uses 'good' tone when >0 — positive anchor so the
//     strip doesn't read as all-warnings.
function kpiCard(label, value, sublabel, tone) {
  const accent = tone === 'risk' ? C.risk : tone === 'warn' ? C.warn : tone === 'good' ? C.good : C.accent;
  const sub = sublabel
    ? '<div style="font-size:11px;color:' + C.textMuted + ';margin-top:4px;'
    +   'white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(sublabel) + '</div>'
    : '';
  return ''
    + '<div style="flex:1 1 150px;min-width:135px;max-width:220px;padding:14px 16px;'
    +   'background:' + C.bg + ';border:1px solid ' + C.border + ';'
    +   'border-left:3px solid ' + accent + ';border-radius:8px;'
    +   'box-shadow:0 1px 2px rgba(0,0,0,0.08);">'
    +   '<div style="font-size:10px;text-transform:uppercase;letter-spacing:0.08em;'
    +     'color:' + C.textMuted + ';font-weight:700;'
    +     'white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(label) + '</div>'
    +   '<div style="font-size:26px;font-weight:700;color:' + C.text + ';'
    +     'margin-top:6px;line-height:1;letter-spacing:-0.02em;">' + esc(value) + '</div>'
    +   sub
    + '</div>';
}

const kpiStripHtml = ''
  + '<div style="display:flex;flex-wrap:wrap;gap:10px;padding:4px 0;">'
  +   kpiCard('Total Queries',     k.totalQueries,         'in inventory',                   null)
  +   kpiCard('Mutations',         k.mutationCount,        'write operations',               null)
  +   kpiCard('Empty Queries',     k.emptyQueries,         'no queryText',                   k.emptyQueries > 0 ? 'risk' : 'good')
  +   kpiCard('Hardcoded Limits',  k.hardcodedLimits,      'first: N not parameterized',     k.hardcodedLimits > 0 ? 'risk' : 'good')
  +   kpiCard('Pagination Broken', k.missingTotal,         'edges without total',            k.missingTotal > 0 ? 'warn' : 'good')
