// ============================================================================
// Fuuz Screen Governance Dashboard — single-document HTML data URI (v2)
// ----------------------------------------------------------------------------
// What's new since v1:
//   • Drill-downs: click any bar/slice on a risk/inventory/hygiene chart to
//     jump to the table that drives it. The target panel expands, scrolls
//     into view, and its search input pre-fills with the relevant query.
//   • Sidebar filters: All / My screens / Recent 7d / At risk / Active+
//     Undeployed. Applies live to every table on the page (no re-query).
//   • Chart scrolling fixed: the trend chart and other multi-label charts
//     use a wrap/stage pattern so wide canvases scroll horizontally.
//   • Consistent spacing scale (CSS vars: --s1 … --s7).
//   • Output no longer includes `theme` — theme is still baked into the
//     HTML at build time, just not returned.
//
// OUTPUT SHAPE
//   {
//     dashboardUri: "data:text/html;charset=utf-8,...",
//     generatedAt:  "2026-06-03T14:22:51.000Z",
//     raw:          { kpis: { ... } }
//   }
//
// INPUTS  (theme + userEmail can come from REQUEST or $)
//   $.screen.edges                OR  $state.context.screens
//   $.screenElement.edges         OR  $state.context.screenElements
//   $state.context.REQUEST.theme  / $.theme         → 'Dark' | 'Light'
//   $state.context.REQUEST.userEmail / $state.context.user.email / $.userEmail
//
// CHART_JS_BUNDLE is inlined further down (~205KB UMD min, v4.4.7, MIT).
// ============================================================================

const NOW = $moment().valueOf();
const DAY = 86400000;
const D7  = NOW -  7 * DAY;
const D30 = NOW - 30 * DAY;
const D90 = NOW - 90 * DAY;

// ===== Theme ================================================================
const _theme = ($state && $state.context && $state.context.REQUEST && $state.context.REQUEST.theme)
            || (typeof $$ !== 'undefined' && $$ && $$.theme)
            || ($ && $.theme)
            || ($ && $.REQUEST && $.REQUEST.theme)
            || ($state && $state.context && $state.context.theme)
            || '';
const THEME = _theme === 'Dark' ? 'Dark' : 'Light';

// ===== User email (drives "My screens" filter) =============================
const _userEmail = ($state && $state.context && $state.context.REQUEST && $state.context.REQUEST.userEmail)
                || ($state && $state.context && $state.context.user && $state.context.user.email)
                || ($ && $.userEmail)
                || ($ && $.user && $.user.email)
                || ($ && $.REQUEST && $.REQUEST.userEmail)
                || '';
const USER_EMAIL = String(_userEmail || '').toLowerCase();

// ===== Color tokens =========================================================
const C = THEME === 'Dark' ? {
  good:'#10b981', warn:'#f59e0b', risk:'#ef4444', accent:'#3b82f6', muted:'#94a3b8',
  palette:['#3b82f6','#10b981','#f59e0b','#a855f7','#06b6d4','#ec4899','#84cc16','#f97316','#8b5cf6','#14b8a6','#eab308','#ef4444']
} : {
  good:'#059669', warn:'#d97706', risk:'#dc2626', accent:'#2563eb', muted:'#64748b',
  palette:['#2563eb','#059669','#d97706','#9333ea','#0891b2','#db2777','#65a30d','#ea580c','#7c3aed','#0d9488','#ca8a04','#dc2626']
};

// ===== Parse inputs =========================================================
const screensSrc = ($ && $.screen && $.screen.edges)
                || ($state && $state.context && $state.context.screens) || [];
const elementsSrc = ($ && $.screenElement && $.screenElement.edges)
                 || ($ && $.screenElements && $.screenElements.edges)
                 || ($state && $state.context && $state.context.screenElements) || [];

const screens = [];
for (let i = 0; i < screensSrc.length; i++) {
  const n = (screensSrc[i] && screensSrc[i].node) ? screensSrc[i].node : screensSrc[i];
  if (n) screens.push(n);
}
const elements = [];
for (let i = 0; i < elementsSrc.length; i++) {
  const n = (elementsSrc[i] && elementsSrc[i].node) ? elementsSrc[i].node : elementsSrc[i];
  if (n) elements.push(n);
}
const total = screens.length;

// ===== Element category sets (unchanged) ====================================
const INPUT_TYPES = { TextInput:1, NumberInput:1, DatePicker:1, TimePicker:1, DateTimePicker:1,
  Select:1, MultiSelect:1, Combobox:1, Autocomplete:1, Checkbox:1, Radio:1, RadioGroup:1,
  Switch:1, Toggle:1, Slider:1, TextArea:1, FileUpload:1, ColorPicker:1, RichTextEditor:1,
  PhoneInput:1, EmailInput:1, PasswordInput:1 };
const DISPLAY_TYPES = { TextField:1, Label:1, Text:1, Markdown:1, Heading:1, Title:1,
  Image:1, Avatar:1, Badge:1, Chip:1, Tag:1, Icon:1, ProgressBar:1, Spinner:1, Skeleton:1,
  Statistic:1, Metric:1, KpiTile:1 };
const ACTION_TYPES = { Button:1, IconButton:1, Link:1, ActionMenu:1, MenuItem:1,
  Toolbar:1, FloatingActionButton:1, ActionButton:1, Action:1 };
const LAYOUT_TYPES = { Container:1, Row:1, Column:1, Stack:1, Card:1,
  Tabs:1, Tab:1, TabList:1, TabPanel:1, Accordion:1, AccordionItem:1,
  Modal:1, Dialog:1, Drawer:1, Sheet:1, Section:1, Panel:1, Grid:1, Flex:1, Box:1, Divider:1 };
const TABLE_TYPES = { Table:1, DataGrid:1, DataTable:1 };
const TABLE_COL_TYPES = { TableColumn:1, DataGridColumn:1 };
const SCRIPT_TYPES = { JavaScript:1, Script:1, JavaScriptTransform:1, JavascriptTransform:1,
  CustomScript:1, InlineScript:1, JsScript:1 };
const DATA_TYPES = { DataSource:1, Transform:1, Query:1, Mutation:1, Subscription:1,
  GraphQLQuery:1, GraphQLMutation:1, RestQuery:1, DataTransform:1, JSONataTransform:1 };
const FORM_TYPES = { Form:1, FormGroup:1 };

function getElementType(el) {
  return (el && el.definition && el.definition.type && el.definition.type.resolvedName)
      || (el && el.type) || '';
}
function elementCategory(el) {
  const t = getElementType(el);
  if (TABLE_COL_TYPES[t]) return 'tableColumn';
  if (INPUT_TYPES[t])    return 'input';
  if (DISPLAY_TYPES[t])  return 'display';
  if (ACTION_TYPES[t])   return 'action';
  if (LAYOUT_TYPES[t])   return 'layout';
  if (TABLE_TYPES[t])    return 'table';
  if (SCRIPT_TYPES[t])   return 'script';
  if (DATA_TYPES[t])     return 'data';
  if (FORM_TYPES[t])     return 'form';
  return 'other';
}

const elementsByScreen = {};
const elementMapByScreen = {};
for (let i = 0; i < elements.length; i++) {
  const el = elements[i];
  const sid = el.screenId;
  if (!sid) continue;
  if (!elementsByScreen[sid]) elementsByScreen[sid] = [];
  elementsByScreen[sid].push(el);
  if (!elementMapByScreen[sid]) elementMapByScreen[sid] = {};
  elementMapByScreen[sid][el.elementId] = el;
}

function findFormAncestor(el, sid) {
  const map = elementMapByScreen[sid] || {};
  let current = el;
  let depth = 0;
  while (current && current.definition && current.definition.parent && depth < 50) {
    const parent = map[current.definition.parent];
    if (!parent) break;
    const pt = getElementType(parent);
    if (FORM_TYPES[pt]) return parent;
    current = parent;
    depth++;
  }
  return null;
}

function containsColorLiteral(value, depth) {
  depth = depth || 0;
  if (depth > 6 || value == null) return false;
  if (typeof value === 'string') {
    return /#[0-9a-f]{3,8}\b/i.test(value) || /\brgba?\s*\(/.test(value) || /\bhsla?\s*\(/.test(value);
  }
  if (typeof value === 'object') {
    const keys = Object.keys(value);
    for (let i = 0; i < keys.length; i++) {
      if (containsColorLiteral(value[keys[i]], depth + 1)) return true;
    }
  }
  return false;
}
function hasHardcodedColors(props) {
  if (!props) return false;
  const checkKeys = ['style','css','sx','background','backgroundColor','bgcolor','color','textColor',
    'borderColor','fill','stroke','boxShadow'];
  for (let i = 0; i < checkKeys.length; i++) {
    const v = props[checkKeys[i]];
    if (v !== undefined && v !== null && containsColorLiteral(v)) return true;
  }
  return false;
}
function hasTableColumnTransform(props, def) {
  if (props && (props.transform || props.dataTransform || props.expression)) return true;
  if (def && def.nodes && Array.isArray(def.nodes) && def.nodes.length > 0) return true;
  if (def && def.linkedNodes && Object.keys(def.linkedNodes).length > 0) return true;
  return false;
}

function evaluateElement(el, sid) {
  const issues = [];
  const cat = elementCategory(el);
  const def = el.definition || {};
  const props = def.props || {};
  const hasParent = !!def.parent;
  const description = el.description || props.description || '';
  const dataPath = el.dataPath || props.dataPath;

  if (!hasParent && (cat === 'input' || cat === 'display' || cat === 'action' ||
                     cat === 'table' || cat === 'tableColumn')) {
    issues.push('noParent');
  }
  if ((cat === 'input' || cat === 'display') && !dataPath) issues.push('noDataPath');
  if ((cat === 'input' || cat === 'display') && !description) issues.push('noDescription');
  if ((cat === 'input' || cat === 'display') && hasParent) {
    const hasFormElementProp = props.formElement && String(props.formElement).length > 0;
    if (!hasFormElementProp && !findFormAncestor(el, sid)) issues.push('notInForm');
  }
  if (cat === 'layout' && hasHardcodedColors(props)) issues.push('themeUnaware');
  if (cat === 'tableColumn') {
    const hasXform = hasTableColumnTransform(props, def);
    if (hasXform) issues.push('tableColTransform');
    if (!dataPath && !hasXform) issues.push('tableColNoDataPath');
  }
  if (cat === 'data' || cat === 'script') {
    const expr = props.expression || props.transform || props.script || '';
    const isRemote = props.remote === true || props.executionMode === 'remote';
    if (isRemote && /\$components\./.test(String(expr))) issues.push('remoteRefsComponents');
  }
  return { category: cat, issues: issues };
}

function evaluateScreen(s) {
  const sid = s.id || s.name;
  const els = elementsByScreen[sid] || [];
  const c = {
    total: els.length,
    input: 0, display: 0, action: 0, layout: 0, table: 0, tableColumn: 0,
    script: 0, data: 0, form: 0, other: 0,
    noParent: 0, noDataPath: 0, noDescription: 0, notInForm: 0,
    themeUnaware: 0, tableColTransform: 0, tableColNoDataPath: 0,
    remoteRefsComponents: 0,
    totalIssues: 0
  };
  for (let i = 0; i < els.length; i++) {
    const r = evaluateElement(els[i], sid);
    if (c[r.category] !== undefined) c[r.category]++;
    for (let j = 0; j < r.issues.length; j++) {
      const iss = r.issues[j];
      if (c[iss] !== undefined) c[iss]++;
      c.totalIssues++;
    }
  }
  let tier = 0;
  if (c.script > 0)                              tier = 1;
  else if (c.action > 10 || c.totalIssues > 10)  tier = 2;
  else if (c.totalIssues > 0)                    tier = 3;
  return { counts: c, tier: tier };
}

// ===== Counters & aggregates ================================================
let active=0, inactive=0, deployed=0, neverDeployed=0;
let edgeCount=0, edgeNeverDeployed=0;
let substituted=0;
let bloated=0, empty=0;
let singleVersion=0, multiAuthor=0;
let activeUndeployed=0, deployedInactive=0;
let emptyVersions=0;
let stale=0;
let createdL30=0, updatedL30=0, updatedL7=0;
let elementsTotal=0, versionsTotal=0;
let maxElements=0;
let tier1=0, tier2=0, tier3=0;
let scriptHeavyCt=0, actionHeavyCt=0;

let issNoParent=0, issNoDataPath=0, issNoDescription=0, issNotInForm=0;
let issThemeUnaware=0, issTableColTransform=0, issTableColNoDataPath=0, issRemoteRefsComponents=0;

const moduleCt={}, moduleGroupCt={}, authorCt={}, editorCt={}, versionAuthorCt={};
const activityByDay={}, createdByDay={};
const elementBuckets = { '0':0, '1-10':0, '11-25':0, '26-50':0, '51-100':0, '100+':0 };
const versionBuckets = { '1':0, '2-3':0, '4-10':0, '10+':0 };

const bloatedList=[], emptyList=[], scriptHeavyList=[], actionHeavyList=[];
const elementHygieneList=[], staleList=[], substitutedList=[];
const activeUndeployedList=[], deployedInactiveList=[], edgeNeverDeployedList=[];
const riskList=[];

const moduleStats={}, modGrpStats={};
function modShape() { return { total:0, deployed:0, active:0, t1:0, t2:0, t3:0, elementsSum:0 }; }
function ensure(map, key, shape) { if (!map[key]) map[key] = shape(); return map[key]; }

// ===== Main loop ============================================================
for (let i = 0; i < screens.length; i++) {
  const s = screens[i];
  const isActive = s.active !== false;
  const isDeployed = (s.currentDeployment !== null && s.currentDeployment !== undefined)
                   || ((s.deployments && Number(s.deployments.total)) > 0);
  const modName = (s.module && s.module.name) || null;
  const grpName = (s.module && s.module.moduleGroup && s.module.moduleGroup.name) || null;

  // Hoist time / authorship — used by both counters and meta blob below
  const cMs = s.createdAt ? $moment(s.createdAt).valueOf() : 0;
  const uMs = s.updatedAt ? $moment(s.updatedAt).valueOf() : 0;
  const author = (s.createdByUser && s.createdByUser.email) ? String(s.createdByUser.email).toLowerCase() : null;
  const editor = (s.updatedByUser && s.updatedByUser.email) ? String(s.updatedByUser.email).toLowerCase() : null;

  // Hoist tier early so meta blob includes risk flag
  const ev = evaluateScreen(s);
  const ec = ev.counts;
  const tier = ev.tier;

  // Per-screen meta blob — attached to every row this screen contributes to.
  // Drives the sidebar filters on the client. Stays compact (1-line object).
  const M = {
    a: author,                              // author email (lower)
    e: editor,                              // editor email (lower)
    r: uMs >= D7 ? 1 : 0,                   // recent (updated last 7d)
    k: tier > 0 ? 1 : 0,                    // at-risk
    v: isActive ? 1 : 0,                    // active (live)
    d: isDeployed ? 1 : 0                   // deployed
  };

  if (isActive) active++; else inactive++;
  if (isDeployed) deployed++; else neverDeployed++;
  if (s.edgeScreen === true) {
    edgeCount++;
    if (!isDeployed) {
      edgeNeverDeployed++;
      if (edgeNeverDeployedList.length < 25) edgeNeverDeployedList.push({
        name: s.name, module: modName || '—', _meta: M
      });
    }
  }
  if (s.substitutesScreen) {
    substituted++;
    if (substitutedList.length < 25) substitutedList.push({
      name: s.name, module: modName || '—',
      substitutes: (s.substitutesScreen && (s.substitutesScreen.name || s.substitutesScreen.id)) || '—',
      _meta: M
    });
  }
  if (isActive && !isDeployed) {
    activeUndeployed++;
    if (activeUndeployedList.length < 25) activeUndeployedList.push({
      name: s.name, module: modName || '—', _meta: M
    });
  }
  if (!isActive && isDeployed) {
    deployedInactive++;
    if (deployedInactiveList.length < 25) deployedInactiveList.push({
      name: s.name, module: modName || '—', _meta: M
    });
  }

  // Element density
  const elCt = (s.elements && Number(s.elements.total)) || 0;
  elementsTotal += elCt;
  if (elCt > maxElements) maxElements = elCt;
  if (elCt === 0) {
    empty++;
    elementBuckets['0']++;
    if (emptyList.length < 25) emptyList.push({ name: s.name, module: modName || '—', _meta: M });
  } else if (elCt <= 10)  elementBuckets['1-10']++;
  else if (elCt <= 25)    elementBuckets['11-25']++;
  else if (elCt <= 50)    elementBuckets['26-50']++;
  else if (elCt <= 100)   elementBuckets['51-100']++;
  else                    elementBuckets['100+']++;

  if (elCt > 50) {
    bloated++;
    bloatedList.push({ name: s.name, module: modName || '—', elements: elCt, _meta: M });
  }

  // Versions
  const verCt = (s.versions && Number(s.versions.total)) || 0;
  versionsTotal += verCt;
  if (verCt === 1)       { singleVersion++; versionBuckets['1']++; }
  else if (verCt <= 3)   versionBuckets['2-3']++;
  else if (verCt <= 10)  versionBuckets['4-10']++;
  else                   versionBuckets['10+']++;

  const versionEdges = (s.versions && s.versions.edges) || [];
  const versionAuthorSet = {};
  for (let v = 0; v < versionEdges.length; v++) {
    const vn = (versionEdges[v] && versionEdges[v].node) ? versionEdges[v].node : versionEdges[v];
    if (vn && vn.createdByUser && vn.createdByUser.email) {
      versionAuthorSet[vn.createdByUser.email] = true;
      versionAuthorCt[vn.createdByUser.email] = (versionAuthorCt[vn.createdByUser.email] || 0) + 1;
    }
    if (vn && vn.dataChanges && Number(vn.dataChanges.total) === 0) emptyVersions++;
  }
  if (Object.keys(versionAuthorSet).length > 1) multiAuthor++;

  // Time-based
  if (cMs >= D30) createdL30++;
  if (uMs >= D30) updatedL30++;
  if (uMs >= D7)  updatedL7++;
  if (uMs > 0 && uMs < D90) {
    stale++;
    if (staleList.length < 25) staleList.push({
      name: s.name,
      daysSinceUpdate: Math.floor((NOW - uMs) / DAY),
      module: modName || '—',
      lastEditor: editor || '—',
      _meta: M
    });
  }
  if (uMs >= D30) {
    const uk = $moment(uMs).format('YYYY-MM-DD');
    activityByDay[uk] = (activityByDay[uk] || 0) + 1;
  }
  if (cMs >= D30) {
    const ck = $moment(cMs).format('YYYY-MM-DD');
    createdByDay[ck] = (createdByDay[ck] || 0) + 1;
  }

  if (author) authorCt[author] = (authorCt[author] || 0) + 1;
  if (editor) editorCt[editor] = (editorCt[editor] || 0) + 1;

  if (modName) {
    moduleCt[modName] = (moduleCt[modName] || 0) + 1;
    const ms = ensure(moduleStats, modName, modShape);
    ms.total++;
    if (isDeployed) ms.deployed++;
    if (isActive) ms.active++;
    ms.elementsSum += elCt;
  }
  if (grpName) {
    moduleGroupCt[grpName] = (moduleGroupCt[grpName] || 0) + 1;
    const gs = ensure(modGrpStats, grpName, modShape);
    gs.total++;
    if (isDeployed) gs.deployed++;
    if (isActive) gs.active++;
    gs.elementsSum += elCt;
  }

  if (ec.script > 0) {
    scriptHeavyCt++;
    scriptHeavyList.push({
      name: s.name, module: modName || '—',
      scripts: ec.script, totalElements: ec.total, _meta: M
    });
  }
  if (ec.action > 10) {
    actionHeavyCt++;
    actionHeavyList.push({
      name: s.name, module: modName || '—',
      actions: ec.action, totalElements: ec.total, _meta: M
    });
  }

  issNoParent             += ec.noParent;
  issNoDataPath           += ec.noDataPath;
  issNoDescription        += ec.noDescription;
  issNotInForm            += ec.notInForm;
  issThemeUnaware         += ec.themeUnaware;
  issTableColTransform    += ec.tableColTransform;
  issTableColNoDataPath   += ec.tableColNoDataPath;
  issRemoteRefsComponents += ec.remoteRefsComponents;

  if (ec.totalIssues > 0) {
    const summary = [];
    if (ec.noDataPath > 0)            summary.push(ec.noDataPath + ' no dataPath');
    if (ec.noDescription > 0)         summary.push(ec.noDescription + ' no desc');
    if (ec.noParent > 0)              summary.push(ec.noParent + ' no parent');
    if (ec.notInForm > 0)             summary.push(ec.notInForm + ' not in form');
    if (ec.themeUnaware > 0)          summary.push(ec.themeUnaware + ' theme-unsafe');
    if (ec.tableColTransform > 0)     summary.push(ec.tableColTransform + ' col xforms');
    if (ec.tableColNoDataPath > 0)    summary.push(ec.tableColNoDataPath + ' col no dataPath');
    if (ec.remoteRefsComponents > 0)  summary.push(ec.remoteRefsComponents + ' remote refs $components');
    elementHygieneList.push({
      name: s.name, module: modName || '—',
      totalIssues: ec.totalIssues,
      issues: summary.join(', '),
      _meta: M
    });
  }

  if (tier === 1) {
    tier1++;
    if (modName) ensure(moduleStats, modName, modShape).t1++;
    if (grpName) ensure(modGrpStats, grpName, modShape).t1++;
  } else if (tier === 2) {
    tier2++;
    if (modName) ensure(moduleStats, modName, modShape).t2++;
    if (grpName) ensure(modGrpStats, grpName, modShape).t2++;
  } else if (tier === 3) {
    tier3++;
    if (modName) ensure(moduleStats, modName, modShape).t3++;
    if (grpName) ensure(modGrpStats, grpName, modShape).t3++;
  }
  if (tier > 0 && riskList.length < 50) {
    const signals = [];
    if (ec.script > 0)                signals.push('script (' + ec.script + ')');
    if (ec.action > 10)               signals.push('actions (' + ec.action + ')');
    if (ec.noDataPath > 0)            signals.push('noDataPath (' + ec.noDataPath + ')');
    if (ec.noDescription > 0)         signals.push('noDesc (' + ec.noDescription + ')');
    if (ec.noParent > 0)              signals.push('noParent (' + ec.noParent + ')');
    if (ec.notInForm > 0)             signals.push('notInForm (' + ec.notInForm + ')');
    if (ec.themeUnaware > 0)          signals.push('themeUnsafe (' + ec.themeUnaware + ')');
    if (ec.tableColTransform > 0)     signals.push('tableColXform (' + ec.tableColTransform + ')');
    if (ec.tableColNoDataPath > 0)    signals.push('tableColNoPath (' + ec.tableColNoDataPath + ')');
    if (ec.remoteRefsComponents > 0)  signals.push('remoteRefs (' + ec.remoteRefsComponents + ')');
    riskList.push({
      name: s.name,
      tier: 'T' + tier, tierNum: tier,
      module: modName || '—',
      signals: signals.join(', ') || '—',
      elements: ec.total,
      active: isActive ? 'Yes' : 'No',
      _meta: M
    });
  }
}

bloatedList.sort(function (a, b) { return b.elements - a.elements; });
scriptHeavyList.sort(function (a, b) { return b.scripts - a.scripts; });
actionHeavyList.sort(function (a, b) { return b.actions - a.actions; });
elementHygieneList.sort(function (a, b) { return b.totalIssues - a.totalIssues; });
staleList.sort(function (a, b) { return b.daysSinceUpdate - a.daysSinceUpdate; });
riskList.sort(function (a, b) {
  if (a.tierNum !== b.tierNum) return a.tierNum - b.tierNum;
  return (b.elements || 0) - (a.elements || 0);
});
const trim = function (arr, n) { return arr.slice(0, n); };

function topN(m, n) {
  const a = [], ks = Object.keys(m);
  for (let i = 0; i < ks.length; i++) a.push({ label: ks[i], value: m[ks[i]] });
  a.sort(function (x, y) { return y.value - x.value; });
  return a.slice(0, n);
}
const r1  = function (x) { const n = Number(x); return isFinite(n) ? Math.round(n * 10) / 10 : 0; };
const pct = function (n, d) { return d > 0 ? Math.round((n / d) * 100) : 0; };

// ===== Activity series ======================================================
const activitySeries = [];
for (let i = 29; i >= 0; i--) {
  const ms = NOW - i * DAY;
  const dk = $moment(ms).format('YYYY-MM-DD');
  const upd = activityByDay[dk] || 0;
  const cre = createdByDay[dk]  || 0;
  activitySeries.push({
    label: $moment(ms).format('MMM D'),
    fullDate: $moment(ms).format('ddd, MMM D YYYY'),
    updated: upd,
    created: cre
  });
}

const weekSeen = {}, weekOrder = [], weekLabel = {}, createdByWeek = {}, updatedByWeek = {};
function bucketWeek(iso) {
  try { const m = $moment(iso).startOf('week'); return { key: m.toISOString(), label: m.format('MM/DD/YYYY') }; }
  catch (e) { const d = (iso || '').slice(0, 10), p = d.split('-');
    return { key: d, label: p.length === 3 ? p[1] + '/' + p[2] + '/' + p[0] : d }; }
}
function trendBump(iso, bucket) {
  if (!iso) return;
  const b = bucketWeek(iso);
  if (!weekSeen[b.key]) { weekSeen[b.key] = 1; weekOrder.push(b.key); }
  weekLabel[b.key] = b.label;
  bucket[b.key] = (bucket[b.key] || 0) + 1;
}
for (let i = 0; i < screens.length; i++) {
  trendBump(screens[i].createdAt, createdByWeek);
  trendBump(screens[i].updatedAt, updatedByWeek);
}
weekOrder.sort();

const TEAM_DOMAINS = { 'fuuz.com': true, 'mfgx.io': true };
const TEAM_LABEL = 'Fuuz Team';
function domainFor(email) {
  if (!email) return 'Unknown';
  const at = email.lastIndexOf('@');
  const d = at >= 0 ? email.slice(at + 1).toLowerCase() : email.toLowerCase();
  return TEAM_DOMAINS[d] ? TEAM_LABEL : d;
}
const domSeen = {}, domOrder = [], domCreated = {}, domVersions = {};
function domBump(map, email) {
  const d = domainFor(email);
  if (!domSeen[d]) { domSeen[d] = 1; domOrder.push(d); }
  map[d] = (map[d] || 0) + 1;
}
for (let i = 0; i < screens.length; i++) {
  const s = screens[i];
  if (s.createdByUser) domBump(domCreated, s.createdByUser.email);
  const ve = (s.versions && s.versions.edges) || [];
  for (let j = 0; j < ve.length; j++) {
    const vn = (ve[j] && ve[j].node) ? ve[j].node : ve[j];
    if (vn && vn.createdByUser) domBump(domVersions, vn.createdByUser.email);
  }
}
domOrder.sort(function (a, b) {
  if (a === TEAM_LABEL) return -1; if (b === TEAM_LABEL) return 1;
  return a < b ? -1 : (a > b ? 1 : 0);
});

const lgSeen = {}, lgOrder = [], depByGroup = {}, undepByGroup = {};
for (let i = 0; i < screens.length; i++) {
  const s = screens[i];
  const g = (s.module && s.module.moduleGroup && s.module.moduleGroup.name) || 'Ungrouped';
  if (!lgSeen[g]) { lgSeen[g] = 1; lgOrder.push(g); }
  const isDep = (s.currentDeployment != null) || ((s.deployments && Number(s.deployments.total)) > 0);
  if (isDep) depByGroup[g] = (depByGroup[g] || 0) + 1;
  else undepByGroup[g] = (undepByGroup[g] || 0) + 1;
}
lgOrder.sort();

const complexityGroups = {}, complexityModSeen = {}, complexityModOrder = [], complexityGrpSeen = {}, complexityGrpOrder = [];
for (let i = 0; i < screens.length; i++) {
  const s = screens[i];
  const g = (s.module && s.module.moduleGroup && s.module.moduleGroup.name) || 'Ungrouped';
  const mod = (s.module && s.module.name) || 'Unassigned';
  const el = (s.elements && Number(s.elements.total)) || 0;
  if (!complexityGrpSeen[g]) { complexityGrpSeen[g] = 1; complexityGrpOrder.push(g); }
  if (!complexityModSeen[mod]) { complexityModSeen[mod] = 1; complexityModOrder.push(mod); }
  if (!complexityGroups[mod]) complexityGroups[mod] = {};
  complexityGroups[mod][g] = (complexityGroups[mod][g] || 0) + el;
}
complexityGrpOrder.sort();
complexityModOrder.sort();

const issueBreakdown = [
  { label: 'No dataPath',         value: issNoDataPath,           hint: 'Inputs & displays missing their data binding',                   drillKey: 'no dataPath' },
  { label: 'No description',      value: issNoDescription,        hint: 'Inputs & displays without descriptions',                          drillKey: 'no desc' },
  { label: 'No parent',           value: issNoParent,             hint: 'Orphan elements — render failure risk',                          drillKey: 'no parent' },
  { label: 'Not in form',         value: issNotInForm,            hint: 'Input/display elements outside a Form container',                drillKey: 'not in form' },
  { label: 'Theme-unaware',       value: issThemeUnaware,         hint: 'Layout elements with hardcoded color literals',                  drillKey: 'theme-unsafe' },
  { label: 'Col transforms',      value: issTableColTransform,    hint: 'Table columns with transforms — perf risk per row',              drillKey: 'col xforms' },
  { label: 'Col no dataPath',     value: issTableColNoDataPath,   hint: 'Table columns missing data binding and lacking a transform',     drillKey: 'col no dataPath' },
  { label: 'Remote refs $components', value: issRemoteRefsComponents, hint: 'Remote nodes referencing $components — won\'t resolve',     drillKey: 'remote refs $components' }
];

// ===== Aggregate KPIs =======================================================
const k = {
  totalScreens: total,
  activeScreens: active, inactiveScreens: inactive,
  deployedScreens: deployed, neverDeployed: neverDeployed,
  deploymentRate: pct(deployed, total),
  edgeScreens: edgeCount, edgeNeverDeployed: edgeNeverDeployed,
  substitutedScreens: substituted,
  bloatedScreens: bloated, emptyScreens: empty,
  singleVersionScreens: singleVersion, multiAuthorScreens: multiAuthor,
  activeUndeployed: activeUndeployed, deployedInactive: deployedInactive,
  emptyVersions: emptyVersions, staleScreens: stale,
  tier1Screens: tier1, tier2Screens: tier2, tier3Screens: tier3,
  scriptHeavyScreens: scriptHeavyCt, actionHeavyScreens: actionHeavyCt,
  totalElements: elementsTotal,
  avgElementsPerScreen: r1(total > 0 ? elementsTotal / total : 0),
  maxElementsInScreen: maxElements,
  totalVersions: versionsTotal,
  avgVersionsPerScreen: r1(total > 0 ? versionsTotal / total : 0),
  createdLast30: createdL30, updatedLast30: updatedL30, updatedLast7: updatedL7,
  issues: {
    noParent: issNoParent, noDataPath: issNoDataPath, noDescription: issNoDescription,
    notInForm: issNotInForm, themeUnaware: issThemeUnaware,
    tableColTransform: issTableColTransform, tableColNoDataPath: issTableColNoDataPath,
    remoteRefsComponents: issRemoteRefsComponents
  },
  elementHygieneIssues: issNoDataPath + issNoDescription + issNotInForm
                      + issThemeUnaware + issTableColTransform
                      + issTableColNoDataPath + issRemoteRefsComponents
};

// ===== STATE ================================================================
// drill formats:
//   { sameLabel: { table: 'X' } }      — search the bar's label string in table X
//   { byIndex: [target,target,...] }   — pick target by bar index (null = no drill)
//   { bySeries: [target,target,...] }  — pick target by series index (stacked/grouped)
//   target shape: { table: 'X', query: 'optional preset' }
const STATE = {
  generatedAt: $moment(NOW).toISOString(),
  generatedAtLabel: $moment(NOW).format('ddd, MMM D YYYY [at] h:mm A'),
  theme: THEME,
  userEmail: USER_EMAIL,
  palette: C.palette,
  semantic: { good: C.good, warn: C.warn, risk: C.risk, accent: C.accent, muted: C.muted },
  kpis: k,
  kpiCards: [
    { label: 'Total Screens',     value: k.totalScreens,            sub: 'in inventory',                            tone: 'neutral' },
    { label: 'Deployment Rate',   value: k.deploymentRate + '%',    sub: k.neverDeployed + ' never deployed',       tone: 'neutral' },
    { label: 'Tier 1 Risk',       value: k.tier1Screens,            sub: 'contain scripts',                         tone: k.tier1Screens > 0 ? 'risk' : 'good' },
    { label: 'Hygiene Issues',    value: k.elementHygieneIssues,    sub: 'across all element checks',               tone: k.elementHygieneIssues > 0 ? 'warn' : 'good' },
    { label: 'No Parent',         value: k.issues.noParent,         sub: 'orphan render risk',                      tone: k.issues.noParent > 0 ? 'risk' : 'good' },
    { label: 'Stale 90d+',        value: k.staleScreens,            sub: 'idle screens',                            tone: k.staleScreens > 0 ? 'warn' : 'good' },
    { label: 'Active Undeployed', value: k.activeUndeployed,        sub: 'marked active, not shipped',              tone: k.activeUndeployed > 0 ? 'warn' : 'good' },
    { label: 'Updated 7d',        value: k.updatedLast7,            sub: k.updatedLast30 + ' in 30d',               tone: k.updatedLast7 > 0 ? 'good' : 'neutral' }
  ],
  charts: {
    activeStatus: {
      type: 'doughnut',
      title: 'Active vs Inactive',
      centerTitle: pct(active, total) + '% Active',
      centerSub: active + ' of ' + total,
      labels: ['Active','Inactive'],
      data:   [active, inactive],
      colors: [C.good, C.muted]
    },
    deploymentStatus: {
      type: 'doughnut',
      title: 'Deployment Status',
      centerTitle: k.deploymentRate + '% Deployed',
      centerSub: deployed + ' of ' + total,
      labels: ['Deployed','Never Deployed'],
      data:   [deployed, neverDeployed],
      colors: [C.accent, C.muted],
      drill: { byIndex: [null, { table: 'activeUndeployed' }] }
    },
    edgeStatus: {
      type: 'doughnut',
      title: 'Edge vs Standard',
      centerTitle: edgeCount + ' Edge',
      centerSub: 'of ' + total + ' screens',
      labels: ['Edge','Standard'],
      data:   [edgeCount, total - edgeCount],
      colors: [C.accent, C.muted],
      drill: { byIndex: [{ table: 'edgeNeverDeployed' }, null] }
    },
    riskTiers: {
      type: 'doughnut',
      title: 'Risk Tier Distribution',
      centerTitle: (tier1 + tier2 + tier3) + ' at risk',
      centerSub: 'of ' + total + ' screens',
      labels: ['Tier 1 (Scripts)','Tier 2 (Heavy)','Tier 3 (Hygiene)','No Risk Signal'],
      data:   [tier1, tier2, tier3, Math.max(0, total - tier1 - tier2 - tier3)],
      colors: [C.risk, C.warn, C.accent, C.good],
      drill: { byIndex: [
        { table: 'risk', query: 'T1' },
        { table: 'risk', query: 'T2' },
        { table: 'risk', query: 'T3' },
        null
      ] }
    },
    elementDensity: {
      type: 'column',
      title: 'Element Density Distribution',
      subtitle: 'Screens bucketed by total element count',
      xAxis: 'Element count', yAxis: 'Screens',
      labels: ['0','1-10','11-25','26-50','51-100','100+'],
      data:   [elementBuckets['0'], elementBuckets['1-10'], elementBuckets['11-25'],
               elementBuckets['26-50'], elementBuckets['51-100'], elementBuckets['100+']],
      color: C.accent,
      drill: { byIndex: [
        { table: 'empty' },
        null, null, null,
        { table: 'bloated' },
        { table: 'bloated' }
      ] }
    },
    versionDistribution: {
      type: 'column',
      title: 'Version Count Distribution',
      subtitle: 'How often screens are iterated',
      xAxis: 'Versions', yAxis: 'Screens',
      labels: ['1','2-3','4-10','10+'],
      data:   [versionBuckets['1'], versionBuckets['2-3'], versionBuckets['4-10'], versionBuckets['10+']],
      color: C.accent
    },
    issueBreakdown: {
      type: 'horizontalBar',
      title: 'Element Hygiene — Issue Breakdown',
      xAxis: 'Occurrences',
      labels: issueBreakdown.map(function (x) { return x.label; }),
      data:   issueBreakdown.map(function (x) { return x.value; }),
      hints:  issueBreakdown.map(function (x) { return x.hint; }),
      color: C.warn,
      drill: { byIndex: issueBreakdown.map(function (x) {
        return x.value > 0 ? { table: 'elementHygiene', query: x.drillKey } : null;
      }) }
    },
    topBloated: {
      type: 'horizontalBar',
      title: 'Top Bloated Screens (most elements)',
      xAxis: 'Element count',
      labels: trim(bloatedList, 10).map(function (r) { return r.name; }),
      data:   trim(bloatedList, 10).map(function (r) { return r.elements; }),
      meta:   trim(bloatedList, 10).map(function (r) { return r.module; }),
      color: C.warn,
      drill: { sameLabel: { table: 'bloated' } }
    },
    topScriptHeavy: {
      type: 'horizontalBar',
      title: 'Top Script-Heavy Screens (Tier 1)',
      xAxis: 'Script elements',
      labels: trim(scriptHeavyList, 10).map(function (r) { return r.name; }),
      data:   trim(scriptHeavyList, 10).map(function (r) { return r.scripts; }),
      meta:   trim(scriptHeavyList, 10).map(function (r) { return r.module + ' • ' + r.totalElements + ' total el.'; }),
      color: C.risk,
      drill: { sameLabel: { table: 'scriptHeavy' } }
    },
    topActionHeavy: {
      type: 'horizontalBar',
      title: 'Top Action-Heavy Screens (>10 actions)',
      xAxis: 'Action elements',
      labels: trim(actionHeavyList, 10).map(function (r) { return r.name; }),
      data:   trim(actionHeavyList, 10).map(function (r) { return r.actions; }),
      meta:   trim(actionHeavyList, 10).map(function (r) { return r.module + ' • ' + r.totalElements + ' total el.'; }),
      color: C.warn,
      drill: { sameLabel: { table: 'actionHeavy' } }
    },
    topAuthors: {
      type: 'horizontalBar',
      title: 'Top Authors (createdBy)',
      xAxis: 'Screens authored',
      labels: topN(authorCt, 10).map(function (r) { return r.label; }),
      data:   topN(authorCt, 10).map(function (r) { return r.value; }),
      color: C.accent
    },
    topEditors: {
      type: 'horizontalBar',
      title: 'Top Editors (updatedBy)',
      xAxis: 'Screens edited',
      labels: topN(editorCt, 10).map(function (r) { return r.label; }),
      data:   topN(editorCt, 10).map(function (r) { return r.value; }),
      color: C.accent
    },
    topVersionAuthors: {
      type: 'horizontalBar',
      title: 'Top Version Authors',
      xAxis: 'Versions shipped',
      labels: topN(versionAuthorCt, 10).map(function (r) { return r.label; }),
      data:   topN(versionAuthorCt, 10).map(function (r) { return r.value; }),
      color: C.accent
    },
    activity30d: {
      type: 'area',
      title: 'Update Activity — Last 30 Days',
      subtitle: k.updatedLast30 + ' screens updated this month',
      xAxis: '', yAxis: 'Screens updated',
      labels:   activitySeries.map(function (x) { return x.label; }),
      data:     activitySeries.map(function (x) { return x.updated; }),
      created:  activitySeries.map(function (x) { return x.created; }),
      fullDate: activitySeries.map(function (x) { return x.fullDate; }),
      color: C.accent
    },
    screenTrend: {
      type: 'multiLine',
      title: 'Screen Activity Trend',
      subtitle: 'Created vs updated, weekly',
      xAxis: 'Week', yAxis: 'Screens',
      labels: weekOrder.map(function (key) { return weekLabel[key]; }),
      series: [
        { name: 'Created', data: weekOrder.map(function (key) { return createdByWeek[key] || 0; }), color: C.accent },
        { name: 'Updated', data: weekOrder.map(function (key) { return updatedByWeek[key] || 0; }), color: C.warn }
      ]
    },
    deploymentHealth: {
      type: 'stackedColumn',
      title: 'Deployment Health by Module Group',
      subtitle: 'Deployed vs undeployed screens',
      xAxis: 'Module group', yAxis: 'Screens',
      labels: lgOrder,
      series: [
        { name: 'Deployed',   data: lgOrder.map(function (g) { return depByGroup[g]   || 0; }), color: C.good },
        { name: 'Undeployed', data: lgOrder.map(function (g) { return undepByGroup[g] || 0; }), color: C.risk }
      ],
      drill: { bySeries: [ null, { table: 'activeUndeployed' } ] }
    },
    screenComplexity: {
      type: 'stackedColumn',
      title: 'Screen Complexity by Module',
      subtitle: 'Element counts stacked by module',
      xAxis: 'Module group', yAxis: 'Elements',
      labels: complexityGrpOrder,
      series: complexityModOrder.map(function (mod, i) {
        return {
          name: mod,
          color: C.palette[i % C.palette.length],
          data: complexityGrpOrder.map(function (g) {
            return (complexityGroups[mod] && complexityGroups[mod][g]) || 0;
          })
        };
      })
    },
    authorship: {
      type: 'groupedColumn',
      title: 'Authorship by Domain',
      subtitle: 'Screens created vs versions authored, by email domain',
      xAxis: 'Domain', yAxis: 'Count',
      labels: domOrder,
      series: [
        { name: 'Screens Created',   data: domOrder.map(function (d) { return domCreated[d]  || 0; }), color: C.accent },
        { name: 'Versions Authored', data: domOrder.map(function (d) { return domVersions[d] || 0; }), color: C.warn }
      ]
    }
  },
  tables: {
    risk: {
      title: 'Risk-Bearing Screens',
      tone: 'risk',
      columns: [
        { key: 'tier',     label: 'Tier' },
        { key: 'name',     label: 'Screen' },
        { key: 'module',   label: 'Module' },
        { key: 'signals',  label: 'Risk Signals' },
        { key: 'elements', label: 'Elements' },
        { key: 'active',   label: 'Active' }
      ],
      rows: trim(riskList, 50)
    },
    scriptHeavy: {
      title: 'Script-Heavy Screens (Tier 1)',
      tone: 'risk',
      columns: [
        { key: 'name',          label: 'Screen' },
        { key: 'module',        label: 'Module' },
        { key: 'scripts',       label: 'Script Elements' },
        { key: 'totalElements', label: 'Total Elements' }
      ],
      rows: trim(scriptHeavyList, 25)
    },
    actionHeavy: {
      title: 'Action-Heavy Screens (>10 actions)',
      tone: 'warn',
      columns: [
        { key: 'name',          label: 'Screen' },
        { key: 'module',        label: 'Module' },
        { key: 'actions',       label: 'Action Elements' },
        { key: 'totalElements', label: 'Total Elements' }
      ],
      rows: trim(actionHeavyList, 25)
    },
    elementHygiene: {
      title: 'Screens with Element Hygiene Issues',
      tone: 'warn',
      columns: [
        { key: 'name',        label: 'Screen' },
        { key: 'module',      label: 'Module' },
        { key: 'totalIssues', label: 'Issues' },
        { key: 'issues',      label: 'Detail' }
      ],
      rows: trim(elementHygieneList, 25)
    },
    bloated: {
      title: 'Bloated Screens (>50 elements)',
      tone: 'warn',
      columns: [
        { key: 'name',     label: 'Screen' },
        { key: 'module',   label: 'Module' },
        { key: 'elements', label: 'Elements' }
      ],
      rows: trim(bloatedList, 25)
    },
    empty: {
      title: 'Empty Screens (0 elements)',
      tone: 'warn',
      columns: [
        { key: 'name',   label: 'Screen' },
        { key: 'module', label: 'Module' }
      ],
      rows: trim(emptyList, 25)
    },
    activeUndeployed: {
      title: 'Active but Never Deployed',
      tone: 'warn',
      columns: [
        { key: 'name',   label: 'Screen' },
        { key: 'module', label: 'Module' }
      ],
      rows: trim(activeUndeployedList, 25)
    },
    deployedInactive: {
      title: 'Deployed but Inactive',
      tone: 'warn',
      columns: [
        { key: 'name',   label: 'Screen' },
        { key: 'module', label: 'Module' }
      ],
      rows: trim(deployedInactiveList, 25)
    },
    stale: {
      title: 'Stale Screens (no update >90d)',
      tone: 'warn',
      columns: [
        { key: 'name',             label: 'Screen' },
        { key: 'module',           label: 'Module' },
        { key: 'daysSinceUpdate',  label: 'Days Idle' },
        { key: 'lastEditor',       label: 'Last Editor' }
      ],
      rows: trim(staleList, 25)
    },
    substituted: {
      title: 'Substituted Screens (migration audit)',
      tone: 'neutral',
      columns: [
        { key: 'name',        label: 'Screen' },
        { key: 'module',      label: 'Module' },
        { key: 'substitutes', label: 'Substitutes' }
      ],
      rows: trim(substitutedList, 25)
    },
    edgeNeverDeployed: {
      title: 'Edge Screens Never Deployed',
      tone: 'warn',
      columns: [
        { key: 'name',   label: 'Screen' },
        { key: 'module', label: 'Module' }
      ],
      rows: trim(edgeNeverDeployedList, 25)
    }
  }
};

