const TPL_HEAD = `<!DOCTYPE html>
<html lang="en" data-theme="dark">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Screen Governance</title>
<style>
  /* ===== Spacing scale ===== */
  :root {
    --s1: 4px;  --s2: 8px;  --s3: 12px;  --s4: 16px;
    --s5: 20px; --s6: 24px; --s7: 32px;
  }

  /* ===== Theme colors ===== */
  :root, :root[data-theme="dark"] {
    --bg:           #0b1220;
    --bg-deeper:    #060a14;
    --panel:        #131826;
    --panel-2:      #1c2336;
    --border:       rgba(148,163,184,0.16);
    --divider:      rgba(148,163,184,0.10);
    --text:         #e2e8f0;
    --text-strong:  #f8fafc;
    --dim:          #94a3b8;
    --accent:       #3b82f6;
    --accent-soft:  rgba(59,130,246,0.18);
    --good:         #10b981;
    --warn:         #f59e0b;
    --risk:         #ef4444;
    --hover:        rgba(148,163,184,0.06);
    --chip-bg:      rgba(148,163,184,0.10);
    --scroll-thumb: rgba(148,163,184,0.30);
  }
  :root[data-theme="light"] {
    --bg:           #f1f5f9;
    --bg-deeper:    #e2e8f0;
    --panel:        #ffffff;
    --panel-2:      #f8fafc;
    --border:       rgba(15,23,42,0.10);
    --divider:      rgba(15,23,42,0.06);
    --text:         #0f172a;
    --text-strong:  #020617;
    --dim:          #475569;
    --accent:       #2563eb;
    --accent-soft:  rgba(37,99,235,0.15);
    --good:         #059669;
    --warn:         #d97706;
    --risk:         #dc2626;
    --hover:        rgba(15,23,42,0.04);
    --chip-bg:      rgba(15,23,42,0.05);
    --scroll-thumb: rgba(15,23,42,0.25);
  }

  *, *::before, *::after { box-sizing: border-box; }
  html, body { margin: 0; padding: 0; height: 100%; }
  body {
    background: var(--bg);
    color: var(--text);
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto,
                 'Helvetica Neue', Arial, sans-serif;
    font-size: 13px;
    line-height: 1.5;
    -webkit-font-smoothing: antialiased;
    opacity: 0;
    transition: opacity 0.25s ease-out;
  }
  body.ready { opacity: 1; }

  ::-webkit-scrollbar { width: 10px; height: 10px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb {
    background: var(--scroll-thumb);
    border-radius: 6px;
    border: 2px solid transparent;
    background-clip: padding-box;
  }
  ::-webkit-scrollbar-thumb:hover { background-color: var(--dim); background-clip: padding-box; }

  /* ===== Layout shell ===== */
  .shell { display: flex; min-height: 100vh; }
  .sidebar {
    width: 240px;
    flex-shrink: 0;
    background: var(--panel);
    border-right: 1px solid var(--border);
    position: sticky;
    top: 0;
    height: 100vh;
    overflow-y: auto;
    z-index: 10;
    display: flex;
    flex-direction: column;
  }
  .sidebar-header {
    padding: var(--s5) var(--s5) var(--s3);
    border-bottom: 1px solid var(--divider);
  }
  .sidebar-eyebrow {
    font-size: 11px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.10em;
    color: var(--dim);
    margin: 0 0 var(--s1);
  }
  .sidebar-subtitle {
    font-size: 15px;
    font-weight: 700;
    color: var(--text-strong);
    margin: 0;
    letter-spacing: -0.01em;
  }
  .sidebar-meta {
    font-size: 11px;
    color: var(--dim);
    margin-top: var(--s2);
    line-height: 1.45;
  }
  .sidebar-group {
    padding: var(--s2) 0;
    border-bottom: 1px solid var(--divider);
  }
  .sidebar-group:last-child { border-bottom: none; }
  .sidebar-group-title {
    padding: var(--s2) var(--s5);
    font-size: 10px;
    text-transform: uppercase;
    letter-spacing: 0.10em;
    color: var(--dim);
    font-weight: 700;
  }
  .sidebar-item {
    display: flex;
    align-items: center;
    gap: var(--s2);
    padding: 9px 18px 9px 17px;
    font-size: 13px;
    color: var(--dim);
    cursor: pointer;
    border-left: 3px solid transparent;
    user-select: none;
    transition: background 0.15s ease, color 0.15s ease;
  }
  .sidebar-item:hover { background: var(--hover); color: var(--text); }
  .sidebar-item.active {
    color: var(--text-strong);
    background: var(--hover);
    border-left-color: var(--accent);
    font-weight: 600;
  }
  .sidebar-item .icon { width: 14px; height: 14px; flex-shrink: 0; opacity: 0.85; }
  .sidebar-item .count {
    margin-left: auto;
    font-size: 11px;
    color: var(--dim);
    background: var(--chip-bg);
    padding: 1px 7px;
    border-radius: 10px;
    font-weight: 600;
  }
  .sidebar-item.active .count { color: var(--text); }

  /* Filter radio item (smaller, no nav icon) */
  .filter-item {
    display: flex;
    align-items: center;
    gap: var(--s2);
    padding: 7px 18px 7px 17px;
    font-size: 12.5px;
    color: var(--dim);
    cursor: pointer;
    border-left: 3px solid transparent;
    user-select: none;
  }
  .filter-item:hover { background: var(--hover); color: var(--text); }
  .filter-item::before {
    content: '';
    width: 11px;
    height: 11px;
    border-radius: 50%;
    border: 1.5px solid var(--dim);
    flex-shrink: 0;
    transition: border-color 0.15s ease, background 0.15s ease;
  }
  .filter-item.active {
    color: var(--text-strong);
    background: var(--hover);
    border-left-color: var(--accent);
    font-weight: 600;
  }
  .filter-item.active::before {
    border-color: var(--accent);
    background: radial-gradient(var(--accent) 45%, transparent 50%);
  }
  .filter-item.disabled { opacity: 0.4; cursor: not-allowed; }
  .filter-item.disabled:hover { background: transparent; color: var(--dim); }

  .main {
    flex: 1;
    min-width: 0;
    padding: var(--s5) var(--s6) var(--s7);
    overflow-x: hidden;
  }
  @media (max-width: 900px) {
    .shell { flex-direction: column; }
    .sidebar { width: 100%; height: auto; position: relative; }
    .sidebar-group { display: flex; flex-wrap: wrap; padding: var(--s1); border-bottom: none; }
    .sidebar-group-title { width: 100%; }
    .sidebar-item, .filter-item { border-left: none; border-bottom: 3px solid transparent; padding: var(--s2) var(--s3); }
    .sidebar-item.active, .filter-item.active { border-left: none; border-bottom-color: var(--accent); }
    .main { padding: var(--s4); }
  }

  /* ===== Sticky page header ===== */
  .page-header {
    position: sticky;
    top: 0;
    z-index: 5;
    background: linear-gradient(to bottom, var(--bg) 0%, var(--bg) 88%, transparent 100%);
    padding: var(--s1) 0 var(--s4);
    margin: 0 0 var(--s1);
    display: flex;
    align-items: baseline;
    gap: var(--s3);
    flex-wrap: wrap;
  }
