    // so the stage is at least as wide as the wrap and grows past it (triggering
    // horizontal scroll in the wrap) when there are many x-axis labels.
    const labelCount = (spec.labels || []).length;
    const wideTypes = { multiLine: 60, stackedColumn: 70, groupedColumn: 70, column: 50, area: 38 };
    const minPxPerLabel = wideTypes[spec.type];
    if (minPxPerLabel && labelCount > 0) {
      const desiredWidth = labelCount * minPxPerLabel;
      stage.style.setProperty('--min-stage-width', desiredWidth + 'px');
    }

    const canvas = el('canvas', { attrs: { id: 'cv_' + (++_chartSeq) } });
    stage.appendChild(canvas);

    if (spec.type === 'doughnut' && spec.centerTitle) {
      const overlay = el('div', { cls: 'doughnut-center' });
      overlay.innerHTML =
        '<div class="big">' + esc(spec.centerTitle) + '</div>' +
        (spec.centerSub ? '<div class="small">' + esc(spec.centerSub) + '</div>' : '');
      wrap.appendChild(overlay);
    }

    if (spec.drill) {
      const hint = el('div', { cls: 'chart-hint',
        html: '<svg width="11" height="11" viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="2"><path d="M3 8h10M9 4l4 4-4 4"/></svg> Click a bar to drill into the table.'
      });
      card.appendChild(hint);
    }

    requestAnimationFrame(function () { instantiateChart(canvas, spec); });
    return card;
  }

  function chartGlobalDefaults() {
    if (!CHART_AVAILABLE) return;
    const cs = getComputedStyle(document.documentElement);
    const dim    = cs.getPropertyValue('--dim').trim()    || '#94a3b8';
    const accent = cs.getPropertyValue('--accent').trim() || '#3b82f6';
    Chart.defaults.color = dim;
    Chart.defaults.borderColor = cs.getPropertyValue('--divider').trim() || 'rgba(148,163,184,0.10)';
    Chart.defaults.font.family = '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif';
    Chart.defaults.font.size = 11;
    Chart.defaults.responsive = true;
    Chart.defaults.maintainAspectRatio = false;
    Chart.defaults.animation.duration = 320;
    const t = Chart.defaults.plugins.tooltip = Chart.defaults.plugins.tooltip || {};
    t.backgroundColor = '#0f172a';
    t.titleColor = '#f1f5f9';
    t.bodyColor  = '#e2e8f0';
    t.borderColor = accent;
    t.borderWidth = 1;
    t.padding = 8;
    t.cornerRadius = 6;
    t.boxPadding = 4;
  }

  // ---- Drill-down handling -------------------------------------------------
  function resolveDrill(spec, activeElement, chart) {
    if (!spec.drill) return null;
    const d = spec.drill;
    if (d.byIndex)   return d.byIndex[activeElement.index] || null;
    if (d.bySeries)  return d.bySeries[activeElement.datasetIndex] || null;
    if (d.sameLabel) {
      const label = chart.data.labels[activeElement.index];
      return { table: d.sameLabel.table, query: label };
    }
    return null;
  }

  function triggerDrill(target) {
    if (!target || !target.table) return;
    const panel = PANEL_BY_TABLE[target.table];
    if (!panel) return;

    panel.classList.remove('collapsed');

    const input = panel.querySelector('.table-search');
    if (input) {
      input.value = target.query ? String(target.query) : '';
      input.dispatchEvent(new Event('input'));
    }

    setTimeout(function () {
      panel.scrollIntoView({ behavior: 'smooth', block: 'start' });
      panel.classList.remove('drill-flash');
      // Force reflow to restart animation
      void panel.offsetWidth;
      panel.classList.add('drill-flash');
      setTimeout(function () { panel.classList.remove('drill-flash'); }, 1200);
    }, 30);
  }

  function attachInteractivity(chart, spec) {
    if (!spec.drill) return;
    chart.options.onClick = function (ev, active) {
      if (!active || !active.length) return;
      const target = resolveDrill(spec, active[0], chart);
      if (target) triggerDrill(target);
    };
    chart.options.onHover = function (ev, active) {
      const canvas = ev.native && ev.native.target;
      if (!canvas) return;
      const drillable = active && active.length && resolveDrill(spec, active[0], chart);
      canvas.style.cursor = drillable ? 'pointer' : 'default';
    };
    chart.update('none');
  }

  function instantiateChart(canvas, spec) {
    const ctx = canvas.getContext('2d');
    let config;
    switch (spec.type) {
      case 'doughnut':       config = cfgDoughnut(spec);    break;
      case 'column':         config = cfgColumn(spec);      break;
      case 'horizontalBar':  config = cfgHorizBar(spec);    break;
      case 'area':           config = cfgArea(spec);        break;
      case 'multiLine':      config = cfgMultiLine(spec);   break;
      case 'stackedColumn':  config = cfgStackedColumn(spec); break;
      case 'groupedColumn':  config = cfgGroupedColumn(spec); break;
      default:               return;
    }
    try {
      const chart = new Chart(ctx, config);
      attachInteractivity(chart, spec);
    } catch (e) {
      const stage = canvas.parentElement;
      stage.removeChild(canvas);
      stage.appendChild(el('div', { cls: 'chart-empty', text: 'Chart failed to render: ' + (e && e.message ? e.message : 'unknown') }));
    }
  }

  // ---- Chart configs -------------------------------------------------------
  function cfgDoughnut(s) {
    return {
      type: 'doughnut',
      data: {
        labels: s.labels,
        datasets: [{
          data: s.data,
          backgroundColor: s.colors,
          borderColor: 'transparent',
          borderWidth: 0,
          hoverOffset: 6
        }]
      },
      options: {
        cutout: '64%',
        layout: { padding: { bottom: 4 } },
        plugins: {
          legend: { position: 'bottom', labels: { boxWidth: 10, boxHeight: 10, padding: 10, usePointStyle: true, pointStyle: 'circle' } },
          tooltip: {
            callbacks: {
              label: function (ctx) {
                const total = ctx.dataset.data.reduce(function (a, b) { return a + b; }, 0);
                const v = ctx.parsed;
                const p = total > 0 ? Math.round((v / total) * 1000) / 10 : 0;
                return ' ' + ctx.label + ': ' + v + ' (' + p + '%)';
              }
            }
          }
        }
      }
    };
  }

  function cfgColumn(s) {
    return {
      type: 'bar',
      data: {
        labels: s.labels,
        datasets: [{
          label: s.yAxis || 'Count',
          data: s.data,
          backgroundColor: s.color,
          borderRadius: 4,
          maxBarThickness: 56
        }]
      },
      options: {
        plugins: { legend: { display: false } },
        scales: {
          x: { title: { display: !!s.xAxis, text: s.xAxis || '' }, grid: { display: false } },
          y: { title: { display: !!s.yAxis, text: s.yAxis || '' }, beginAtZero: true, ticks: { precision: 0 } }
        }
      }
    };
  }

  function cfgHorizBar(s) {
    const meta = s.meta || s.hints;
    return {
      type: 'bar',
      data: {
        labels: s.labels,
        datasets: [{
          label: s.xAxis || 'Count',
          data: s.data,
          backgroundColor: s.color,
          borderRadius: 4,
          maxBarThickness: 22
        }]
      },
      options: {
        indexAxis: 'y',
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              label: function (ctx) {
                const parts = [' ' + ctx.parsed.x];
                if (meta && meta[ctx.dataIndex]) parts.push(meta[ctx.dataIndex]);
                return parts;
              }
            }
          }
        },
        scales: {
          x: { title: { display: !!s.xAxis, text: s.xAxis || '' }, beginAtZero: true, ticks: { precision: 0 } },
          y: { grid: { display: false }, ticks: { autoSkip: false, font: { size: 11 } } }
        }
      }
    };
  }

  function cfgArea(s) {
    const color = s.color || STATE.semantic.accent;
    return {
      type: 'line',
      data: {
        labels: s.labels,
        datasets: [{
          label: 'Updated',
          data: s.data,
          fill: true,
          borderColor: color,
          backgroundColor: color + '33',
          tension: 0.35,
          pointRadius: 2,
          pointHoverRadius: 5,
          borderWidth: 2
        }]
      },
      options: {
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              title: function (ctx) { return s.fullDate ? s.fullDate[ctx[0].dataIndex] : ctx[0].label; },
              label: function (ctx) {
                const i = ctx.dataIndex;
                const u = s.data[i] || 0;
                const c = s.created ? (s.created[i] || 0) : 0;
                return [' ' + u + ' updated', ' ' + c + ' newly created'];
              }
            }
          }
        },
        scales: {
          x: { grid: { display: false }, ticks: { autoSkip: true, maxRotation: 0 } },
          y: { beginAtZero: true, ticks: { precision: 0 } }
        }
      }
    };
  }

  function cfgMultiLine(s) {
    return {
      type: 'line',
      data: {
        labels: s.labels,
        datasets: s.series.map(function (ser) {
          return {
            label: ser.name,
            data: ser.data,
            borderColor: ser.color,
            backgroundColor: ser.color,
            tension: 0.3,
            pointRadius: 2,
            pointHoverRadius: 4,
            borderWidth: 2,
            fill: false
          };
        })
      },
      options: {
        plugins: { legend: { position: 'bottom', labels: { boxWidth: 10, boxHeight: 10, usePointStyle: true, pointStyle: 'circle' } } },
        scales: {
          x: { title: { display: !!s.xAxis, text: s.xAxis || '' }, grid: { display: false }, ticks: { maxRotation: 60, minRotation: 30 } },
          y: { title: { display: !!s.yAxis, text: s.yAxis || '' }, beginAtZero: true, ticks: { precision: 0 } }
        }
      }
    };
  }

  function cfgStackedColumn(s) {
    return {
      type: 'bar',
      data: {
        labels: s.labels,
        datasets: s.series.map(function (ser) {
          return {
            label: ser.name,
            data: ser.data,
            backgroundColor: ser.color,
            borderRadius: 2,
            maxBarThickness: 60
          };
        })
      },
      options: {
        plugins: { legend: { position: 'bottom', labels: { boxWidth: 10, boxHeight: 10, usePointStyle: true, pointStyle: 'rect' } } },
        scales: {
          x: { stacked: true, title: { display: !!s.xAxis, text: s.xAxis || '' }, grid: { display: false } },
          y: { stacked: true, title: { display: !!s.yAxis, text: s.yAxis || '' }, beginAtZero: true, ticks: { precision: 0 } }
        }
      }
    };
  }

  function cfgGroupedColumn(s) {
    return {
      type: 'bar',
      data: {
        labels: s.labels,
        datasets: s.series.map(function (ser) {
          return {
            label: ser.name,
            data: ser.data,
            backgroundColor: ser.color,
            borderRadius: 3,
            maxBarThickness: 36
          };
        })
      },
      options: {
        plugins: { legend: { position: 'bottom', labels: { boxWidth: 10, boxHeight: 10, usePointStyle: true, pointStyle: 'rect' } } },
        scales: {
          x: { title: { display: !!s.xAxis, text: s.xAxis || '' }, grid: { display: false } },
          y: { title: { display: !!s.yAxis, text: s.yAxis || '' }, beginAtZero: true, ticks: { precision: 0 } }
        }
      }
    };
  }

  // ---- Table panel ---------------------------------------------------------
  function makeTablePanel(tableKey) {
    const t = STATE.tables[tableKey];
    if (!t) return el('div');

    if (!t.rows || t.rows.length === 0) {
      const empty = el('div', { cls: 'panel tone-good', attrs: { 'data-table-key': tableKey } });
      empty.innerHTML =
        '<div class="panel-header" style="cursor:default;">' +
          '<svg class="chev" viewBox="0 0 10 10" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" style="visibility:hidden;"><path d="M2 3.5l3 3 3-3"/></svg>' +
          '<span class="panel-title">' + esc(t.title) + '</span>' +
          '<span class="panel-count" style="background:transparent;color:var(--good);">none</span>' +
        '</div>' +
        '<div class="panel-body"><div class="table-empty good">No screens match. ✓</div></div>';
      PANEL_BY_TABLE[tableKey] = empty;
      return empty;
    }

    const body = el('div');

    const toolbar = el('div', { cls: 'table-toolbar' });
    toolbar.innerHTML =
      '<input class="table-search" type="text" placeholder="Search ' + esc(t.rows.length) + ' rows…" />' +
      '<button class="table-clear">Clear</button>';
    body.appendChild(toolbar);

    const scroll = el('div', { cls: 'table-scroll' });
    const table = el('table', { cls: 'data' });

    const thead = el('thead');
    const trH = el('tr');
    t.columns.forEach(function (c, idx) {
      const th = el('th');
      th.innerHTML = esc(c.label) + ' <span class="sort-ind">▾</span>';
      th.setAttribute('data-col', String(idx));
      trH.appendChild(th);
    });
    thead.appendChild(trH);
    table.appendChild(thead);

    const tbody = el('tbody');
    const dataRows = [];
    t.rows.forEach(function (r) {
      const tr = el('tr');
      t.columns.forEach(function (c) {
        const td = el('td');
        const v = r[c.key];
        if (c.key === 'tier') {
          td.innerHTML = '<span class="tier ' + esc(v) + '">' + esc(v) + '</span>';
        } else if (v == null || v === '') {
          td.textContent = '—';
        } else {
          td.textContent = String(v);
        }
        tr.appendChild(td);
      });
      // Attach meta blob for filter predicates
      if (r._meta) ROW_META.set(tr, r._meta);
      tbody.appendChild(tr);
      dataRows.push(tr);
    });

    // Empty-filter sentinel row (hidden by default)
    const emptyRow = el('tr', { cls: 'empty-filter-row' });
    emptyRow.style.display = 'none';
    const emptyCell = el('td', { attrs: { colspan: String(t.columns.length) }, text: 'No rows match the current filter or search.' });
    emptyRow.appendChild(emptyCell);
    tbody.appendChild(emptyRow);

    table.appendChild(tbody);
    scroll.appendChild(table);
    body.appendChild(scroll);

    // Visibility composition: row hidden iff filter-hidden OR search-hidden
    function setRowVisibility(row) {
      const fh = row.dataset.fh === '1';
      const sh = row.dataset.sh === '1';
      row.style.display = (fh || sh) ? 'none' : '';
    }
    function refreshCount(panel) {
      const visible = dataRows.filter(function (r) { return r.style.display !== 'none'; }).length;
      const total = dataRows.length;
      const cnt = panel.querySelector('[data-count-el]');
      if (cnt) cnt.textContent = visible < total ? (visible + ' / ' + total) : String(total);
      emptyRow.style.display = visible === 0 ? '' : 'none';
    }

    const searchInput = toolbar.querySelector('.table-search');
    const clearBtn    = toolbar.querySelector('.table-clear');
    function runSearch() {
      const q = searchInput.value.toLowerCase();
      dataRows.forEach(function (row) {
        const hit = !q || row.textContent.toLowerCase().indexOf(q) > -1;
        row.dataset.sh = hit ? '0' : '1';
        setRowVisibility(row);
      });
      refreshCount(panel);
    }
    function runFilter() {
      const pred = FILTERS[CURRENT_FILTER].pred;
      dataRows.forEach(function (row) {
        const meta = ROW_META.get(row);
        const pass = pred(meta);
        row.dataset.fh = pass ? '0' : '1';
        setRowVisibility(row);
      });
      refreshCount(panel);
    }
    searchInput.addEventListener('input', runSearch);
    clearBtn.addEventListener('click', function () {
      searchInput.value = '';
      runSearch();
      searchInput.focus();
    });

    // Sort wiring
    let sortCol = -1, sortDir = 1;
    const ths = trH.querySelectorAll('th');
    ths.forEach(function (th, idx) {
      th.addEventListener('click', function () {
        if (sortCol === idx) sortDir = -sortDir;
        else { sortCol = idx; sortDir = 1; }
        ths.forEach(function (h, i) {
          h.classList.toggle('sorted', i === idx);
          const ind = h.querySelector('.sort-ind');
          if (ind) ind.textContent = (i === idx) ? (sortDir > 0 ? '▾' : '▴') : '▾';
        });
        const trList = Array.prototype.slice.call(tbody.querySelectorAll('tr:not(.empty-filter-row)'));
        trList.sort(function (a, b) {
          const av = a.children[idx].textContent.trim();
          const bv = b.children[idx].textContent.trim();
          const an = parseFloat(av), bn = parseFloat(bv);
          if (!isNaN(an) && !isNaN(bn) && isFinite(an) && isFinite(bn)) return (an - bn) * sortDir;
          return av.localeCompare(bv) * sortDir;
        });
        trList.forEach(function (tr) { tbody.insertBefore(tr, emptyRow); });
      });
    });

    const panel = makePanel({
      title: t.title,
      count: t.rows.length,
      tone: t.tone === 'neutral' ? null : t.tone,
      body: body,
      tableKey: tableKey
    });

    // Run filter on first render to set the baseline
    runFilter();
    return panel;
  }

  // ---- Filter application --------------------------------------------------
  function applyFilter(name) {
    if (!FILTERS[name]) return;
    CURRENT_FILTER = name;

    document.querySelectorAll('.filter-item').forEach(function (item) {
      item.classList.toggle('active', item.getAttribute('data-filter') === name);
    });

    // Re-evaluate every table
    Object.keys(PANEL_BY_TABLE).forEach(function (key) {
      const panel = PANEL_BY_TABLE[key];
      const pred = FILTERS[name].pred;
      const rows = panel.querySelectorAll('tbody tr:not(.empty-filter-row)');
      const emptyRow = panel.querySelector('.empty-filter-row');
      let visible = 0;
      rows.forEach(function (row) {
        const meta = ROW_META.get(row);
        const pass = pred(meta);
        row.dataset.fh = pass ? '0' : '1';
        const fh = row.dataset.fh === '1';
        const sh = row.dataset.sh === '1';
        row.style.display = (fh || sh) ? 'none' : '';
        if (!fh && !sh) visible++;
      });
      const total = rows.length;
      const cnt = panel.querySelector('[data-count-el]');
      if (cnt) cnt.textContent = visible < total ? (visible + ' / ' + total) : String(total);
      if (emptyRow) emptyRow.style.display = (total > 0 && visible === 0) ? '' : 'none';
    });

    // Page header chip
    const chip = document.getElementById('pageFilterChip');
    if (name === 'all') {
      chip.classList.remove('active');
      chip.textContent = '';
    } else {
      chip.classList.add('active');
      chip.textContent = 'Tables filtered: ' + FILTERS[name].label;
    }
  }

  // ---- Section builders ----------------------------------------------------
  function buildOverview(host) {
    host.appendChild(makeKpiStrip());
    const grid = el('div', { cls: 'chart-grid' });
    grid.appendChild(makeChartCard(STATE.charts.activeStatus));
    grid.appendChild(makeChartCard(STATE.charts.deploymentStatus));
    grid.appendChild(makeChartCard(STATE.charts.edgeStatus));
    grid.appendChild(makeChartCard(STATE.charts.riskTiers));
    host.appendChild(grid);
  }

  function buildRisk(host) {
    const grid1 = el('div', { cls: 'chart-grid' });
    grid1.appendChild(makeChartCard(STATE.charts.topScriptHeavy));
    grid1.appendChild(makeChartCard(STATE.charts.topActionHeavy));
    grid1.appendChild(makeChartCard(STATE.charts.topBloated));
    host.appendChild(grid1);

    host.appendChild(makeTablePanel('risk'));
    host.appendChild(makeTablePanel('scriptHeavy'));
    host.appendChild(makeTablePanel('actionHeavy'));
  }

  function buildHygiene(host) {
    const grid = el('div', { cls: 'chart-grid wide' });
    grid.appendChild(makeChartCard(STATE.charts.issueBreakdown, { height: 'tall' }));
    host.appendChild(grid);
    host.appendChild(makeTablePanel('elementHygiene'));
  }

  function buildActivity(host) {
    const gridA = el('div', { cls: 'chart-grid' });
    gridA.appendChild(makeChartCard(STATE.charts.activity30d));
    gridA.appendChild(makeChartCard(STATE.charts.authorship));
    host.appendChild(gridA);

    const gridB = el('div', { cls: 'chart-grid wide' });
    gridB.appendChild(makeChartCard(STATE.charts.screenTrend, { height: 'tall' }));
    host.appendChild(gridB);

    const gridC = el('div', { cls: 'chart-grid' });
    gridC.appendChild(makeChartCard(STATE.charts.topAuthors));
    gridC.appendChild(makeChartCard(STATE.charts.topEditors));
    gridC.appendChild(makeChartCard(STATE.charts.topVersionAuthors));
    host.appendChild(gridC);
  }

  function buildInventory(host) {
    const grid = el('div', { cls: 'chart-grid' });
    grid.appendChild(makeChartCard(STATE.charts.elementDensity));
    grid.appendChild(makeChartCard(STATE.charts.versionDistribution));
    grid.appendChild(makeChartCard(STATE.charts.deploymentHealth));
    host.appendChild(grid);

    const gridB = el('div', { cls: 'chart-grid wide' });
    gridB.appendChild(makeChartCard(STATE.charts.screenComplexity, { height: 'tall' }));
    host.appendChild(gridB);

    host.appendChild(makeTablePanel('bloated'));
    host.appendChild(makeTablePanel('empty'));
  }

  function buildDrift(host) {
    host.appendChild(makeTablePanel('stale'));
    host.appendChild(makeTablePanel('activeUndeployed'));
    host.appendChild(makeTablePanel('deployedInactive'));
    host.appendChild(makeTablePanel('edgeNeverDeployed'));
    host.appendChild(makeTablePanel('substituted'));
  }

  // ---- Boot ----------------------------------------------------------------
  function boot() {
    renderSidebar();
    chartGlobalDefaults();

    const content = document.getElementById('content');
    SECTIONS.forEach(function (s) {
      const sec = el('section', { cls: 'section', attrs: { id: 'sec-' + s.id } });
      sec.appendChild(el('div', { cls: 'section-title', text: s.label }));
      s.build(sec);
      content.appendChild(sec);
    });

    setupSectionObserver();
    requestAnimationFrame(function () { document.body.classList.add('ready'); });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    boot();
  }
})();
</script>
</body>
</html>`;

// ============================================================================
// Encoding polyfill
// ============================================================================
function encodeURIComponentPolyfill(str) {
  const unreserved = {};
  const safe = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_.~";
  for (let i = 0; i < safe.length; i++) unreserved[safe.charCodeAt(i)] = true;
  const out = [];
  const hex = function (n) { const h = n.toString(16).toUpperCase(); return h.length === 1 ? '0' + h : h; };
  for (let i = 0; i < str.length; i++) {
    const c = str.charCodeAt(i);
    if (c < 0x80) {
      out.push(unreserved[c] ? str.charAt(i) : '%' + hex(c));
    } else if (c < 0x800) {
      out.push('%' + hex(0xC0 | (c >> 6))
             + '%' + hex(0x80 | (c & 0x3F)));
    } else if (c >= 0xD800 && c <= 0xDBFF) {
      const next = str.charCodeAt(i + 1);
      const cp = 0x10000 + ((c & 0x3FF) << 10) + (next & 0x3FF);
      i++;
      out.push('%' + hex(0xF0 | (cp >> 18))
             + '%' + hex(0x80 | ((cp >> 12) & 0x3F))
             + '%' + hex(0x80 | ((cp >> 6) & 0x3F))
             + '%' + hex(0x80 | (cp & 0x3F)));
    } else {
      out.push('%' + hex(0xE0 | (c >> 12))
             + '%' + hex(0x80 | ((c >> 6) & 0x3F))
             + '%' + hex(0x80 | (c & 0x3F)));
    }
  }
  return out.join('');
}

// ============================================================================
// Assemble + encode + return
// ============================================================================
const themeAttr = THEME === 'Dark' ? 'dark' : 'light';
const themedHead = TPL_HEAD.replace('data-theme="dark"', 'data-theme="' + themeAttr + '"');

const html = themedHead + CHART_JS_BUNDLE + TPL_AFTER_LIB + JSON.stringify(STATE) + TPL_TAIL;
const dashboardUri = 'data:text/html;charset=utf-8,' + encodeURIComponentPolyfill(html);

return {
  dashboardUri: dashboardUri,
  generatedAt: STATE.generatedAt,
  raw: { kpis: k }
};

data.query:
{
