// ============================================================================
// Fuuz Model ERD — single-document HTML data URI  (OPTIMIZED v2 — CDN dagre)
// ----------------------------------------------------------------------------
// Builds an interactive entity-relationship diagram for a set of Fuuz/GraphQL
// model definitions. Designed for hundreds of models (500–750+): filtered-by-
// default, with each focused model showing its 1-hop direct relations.
//
// OUTPUT
//   { dashboardUri: "data:text/html;charset=utf-8,...", generatedAt: "..." }
//
// INPUTS (from the upstream flow's Collect node)
//   $.modelDefinitions            direct array of model definition records
//   $.topic.edges                 GraphQL Connection — each .node is a topic
//   $.deviceSubscription.edges    GraphQL Connection — each .node is an edge subscription
//   $state.context.REQUEST.theme  'Dark' | 'Light'
//
// CHANGES vs v1
//   • Dagre is loaded from CDN (jsdelivr) — was inlined as a string literal.
//     Drops ~140KB of source / ~400KB of percent-encoded URI weight.
//   • Field processing reduced from 5 passes to 2 passes per model.
//   • Native encodeURIComponent used when available (huge win on big payloads).
//   • script-tag JSON escaping uses a single regex pass instead of 5.
//   • Field objects are emitted in a slim shape — intermediate props stripped
//     before serialization. ~30% smaller STATE payload at scale.
//   • searchIndex no longer precomputed server-side — client builds it lazily
//     on first keystroke. Smaller payload, no perceivable UI impact.
//   • Diagnostic shape strings only computed when no models found.
//   • Client auto-switches view-all to layered layout when N > 150 (force-
//     directed is O(N²); layered scales linearly via dagre).
//
// IMPORTANT: the rendering iframe must be able to reach
//   https://cdn.jsdelivr.net/npm/dagre@0.8.5/dist/dagre.min.js
// If the dashboard renders blank with a "dagre is not defined" error in the
// browser console, the client network is blocking the CDN. Fix by either
// self-hosting dagre 0.8.5 on the same domain as Fuuz, or re-inlining the
// library text into a <script> tag in TPL_HEAD. Pin stays at 0.8.5 — 1.x uses
// class field syntax and Object.hasOwn which break older webview engines.
// ============================================================================

const NOW = $moment().valueOf();

// ===== Theme ================================================================
const _theme = ($state && $state.context && $state.context.REQUEST && $state.context.REQUEST.theme)
            || ($state && $state.context && $state.context.theme)
            || ($ && $.theme)
            || ($ && $.REQUEST && $.REQUEST.theme)
            || '';
const THEME = _theme === 'Dark' ? 'Dark' : 'Light';

// ===== Parse inputs =========================================================
// Inputs from the upstream flow:
//   $.modelDefinitions            — direct array of model definition records
//   $.topic.edges                 — GraphQL Connection (each .edges[i].node is a topic)
//   $.deviceSubscription.edges    — GraphQL Connection (each .edges[i].node is an edge subscription)
//
// `toArray` accepts either shape — a raw array, or a Connection with .edges —
// so the script is resilient if the upstream flow's collect node shape drifts.

function toArray(input) {
  if (!input) return [];
  if (Array.isArray(input)) return input;
  if (Array.isArray(input.edges)) {
    const out = [];
    const n = input.edges.length;
    for (let i = 0; i < n; i++) {
      const e = input.edges[i];
      if (e && e.node != null) out.push(e.node);
    }
    return out;
  }
  return [];
}

const rawModels   = toArray($ && $.modelDefinitions);
const rawTopics   = toArray($ && $.topic);
const rawEdgeSubs = toArray($ && $.deviceSubscription);

// ===== Type parsing =========================================================
const SCALAR_TYPES = {
  'ID': 1, 'String': 1, 'Int': 1, 'Float': 1, 'Boolean': 1, 'Bool': 1,
  'DateTime': 1, 'Date': 1, 'Time': 1, 'Timestamp': 1,
  'JSON': 1, 'JSONObject': 1, 'BigInt': 1, 'Decimal': 1, 'Long': 1,
  'Number': 1, 'Object': 1, 'Any': 1, 'Void': 1
};

function parseType(typeStr) {
  if (!typeStr) return { base: 'unknown', required: false, isList: false, raw: '' };
  let s = String(typeStr);
  // Avoid .trim() — these strings are always tight in our data; skip the work
  const raw = s;
  let required = false;
  const lastChar = s.charCodeAt(s.length - 1);
  if (lastChar === 33 /* ! */) { required = true; s = s.slice(0, -1); }
  let isList = false;
  if (s.charCodeAt(0) === 91 /* [ */ && s.charCodeAt(s.length - 1) === 93 /* ] */) {
    isList = true;
    s = s.slice(1, -1);
    if (s.charCodeAt(s.length - 1) === 33) { s = s.slice(0, -1); }
  }
  return { base: s, required: required, isList: isList, raw: raw };
}

// ===== Field classification =================================================
const AUDIT_FIELDS = {
  'createdAt': 1, 'updatedAt': 1,
  'createdByUserId': 1, 'updatedByUserId': 1,
  'createdByUser': 1, 'updatedByUser': 1,
  'dataChanges': 1
};

// For unpaired FKs like `destinationTenantId`, naive `Capitalize(strippedName)`
// would produce `DestinationTenant`, but the real target is usually `Tenant`.
// Walk the camelCase word boundaries from longest prefix to shortest suffix.
function smartTargetGuess(strippedName, modelNameSet) {
  if (!strippedName) return '';
  const fullCap = strippedName.charAt(0).toUpperCase() + strippedName.slice(1);
  if (modelNameSet[fullCap]) return fullCap;
  // Inline camelCase split — avoid regex for hot loop
  const len = strippedName.length;
  for (let i = 1; i < len; i++) {
    const cc = strippedName.charCodeAt(i);
    if (cc >= 65 && cc <= 90) {
      const candidate = strippedName.slice(i);
      if (modelNameSet[candidate]) return candidate;
    }
  }
  return fullCap;
}

function classifyField(field, modelNameSet) {
  const name = field.name || '';
  const type = parseType(field.type);
  const desc = field.description || '';
  const isScalar = SCALAR_TYPES.hasOwnProperty(type.base);

  if (name.charCodeAt(0) === 95 /* _ */) {
    return { name: name, type: type, desc: desc, category: 'system', targetModel: null };
  }
  if (name === 'id' && type.base === 'ID') {
    return { name: name, type: type, desc: desc, category: 'primary', targetModel: null };
  }
  if (AUDIT_FIELDS[name]) {
    return {
      name: name, type: type, desc: desc, category: 'audit',
      targetModel: isScalar ? null : type.base
    };
  }
  // Foreign key ID — name ends with 'Id' and type is ID (with or without !)
  if (type.base === 'ID' && !type.isList && name.length > 2
      && name.charCodeAt(name.length - 2) === 73   /* I */
      && name.charCodeAt(name.length - 1) === 100  /* d */) {
    const pairedName = name.slice(0, -2);
    return {
      name: name, type: type, desc: desc, category: 'fkId',
      pairedName: pairedName,
      inferredTarget: smartTargetGuess(pairedName, modelNameSet),
      targetModel: null
    };
  }
  if (!isScalar) {
    return {
      name: name, type: type, desc: desc,
      category: type.isList ? 'listRel' : 'relation',
      targetModel: type.base
    };
  }
  return { name: name, type: type, desc: desc, category: 'scalar', targetModel: null };
}

// ===== Synthesized field schemas (topics + edge subscriptions) ==============
const TOPIC_FIELDS = [
  { name: 'id',                  type: 'ID!',      description: 'Unique identifier' },
  { name: 'name',                type: 'String!',  description: 'Topic name (typically dot-delimited, e.g. test.webhook)' },
  { name: 'fullyQualifiedName',  type: 'String!',  description: 'Tenant-scoped fully-qualified topic path' },
  { name: 'description',         type: 'String',   description: 'Human-readable description' },
  { name: 'valueSchema',         type: 'JSON',     description: 'Schema describing the topic payload structure' },
  { name: 'webhookAccessible',   type: 'Boolean!', description: 'Whether this topic accepts publishing via webhook' },
  { name: 'createdAt',           type: 'DateTime!' },
  { name: 'createdByUserId',     type: 'ID!' },
  { name: 'createdByUser',       type: 'User!' },
  { name: 'updatedAt',           type: 'DateTime!' },
  { name: 'updatedByUserId',     type: 'ID!' },
  { name: 'updatedByUser',       type: 'User!' }
];

const EDGE_SUB_FIELDS = [
  { name: 'id',                       type: 'ID!',         description: 'Unique identifier' },
  { name: 'name',                     type: 'String!',     description: 'Subscription tag name' },
  { name: 'description',              type: 'String',      description: 'Human-readable description' },
  { name: 'fullyQualifiedTopicName',  type: 'String!',     description: 'Fully-qualified path including gateway, device, and subscription type' },
  { name: 'configuration',            type: 'JSONObject!', description: 'Subscription configuration (topics, storeAndForward, continuousValues, etc.)' },
  { name: 'deviceGatewayDeviceId',    type: 'ID!' },
  { name: 'deviceGatewayDevice',      type: 'DeviceGatewayDevice!', description: 'The device-gateway device this subscription is bound to' },
  { name: 'deviceSubscriptionTypeId', type: 'String!',     description: 'Type discriminator (e.g. mqttBrokerReceiveData, opcuaReadData)' },
  { name: 'deviceSubscriptionType',   type: 'DeviceSubscriptionType', description: 'Wrapper carrying the type label' },
  { name: 'updateFrequencySeconds',   type: 'Int!',        description: 'How often the subscription polls or updates, in seconds' },
  { name: 'createdAt',                type: 'DateTime!' },
  { name: 'createdByUserId',          type: 'ID!' },
  { name: 'createdByUser',            type: 'User!' },
  { name: 'updatedAt',                type: 'DateTime!' },
  { name: 'updatedByUserId',          type: 'ID!' },
  { name: 'updatedByUser',            type: 'User!' }
];

// ===== Model pass 1: name index =============================================
const modelNameSet = {};
const rawModelCount = rawModels.length;
for (let i = 0; i < rawModelCount; i++) {
  const r = rawModels[i];
  if (r && r.name) {
    modelNameSet[r.name] = 1;
  } else if (r && r.modelDefinition && r.modelDefinition.name) {
    // DataModelVersion wrapper form — model name is on the inner record
    modelNameSet[r.modelDefinition.name] = 1;
  }
}

// ===== Model pass 2: classify + pair + count in two combined passes =========
// OPTIMIZATION: previous version did 5 sequential passes per model:
//   (1) classifyField over fields
//   (2) build fieldByName map
//   (3) pair fkId with partner
//   (4) reclassify singular references as scalars
//   (5) count categories
// This version does it in 2 passes:
//   PASS A: classify each field + populate fieldByName in the same loop
//   PASS B: pair + reclassify + count in a single loop
// At 750 models × 30 fields, this saves ~67,500 iterations of work and a
// ton of property writes.

const models = [];
const modelByName = {};

function processEntity(raw, kind) {
  if (!raw || !raw.name) return;
  const rawFields = raw.fields || [];
  const fieldCount = rawFields.length;
  const fields = new Array(fieldCount);
  const fieldByName = {};

  // PASS A — classify + index
  for (let j = 0; j < fieldCount; j++) {
    const f = classifyField(rawFields[j], modelNameSet);
    fields[j] = f;
    fieldByName[f.name] = f;
  }

  // PASS B — pair fkId with partner, reclassify unpaired singular refs,
  // count categories. All three operations in a single iteration over the
  // field list.
  let coreCount = 0, auditCount = 0, systemCount = 0;
  for (let j = 0; j < fieldCount; j++) {
    const f = fields[j];

    // (i) FK pairing
    if (f.category === 'fkId') {
      const partner = fieldByName[f.pairedName];
      if (partner && partner.category === 'relation') {
        f.pairedWith = partner.name;
        f.targetModel = partner.targetModel;
        f.inferred = false;
        partner.pairedWith = f.name;
        partner.hasFkPartner = true;
      } else if (partner && partner.category === 'audit') {
        f.pairedWith = partner.name;
        f.targetModel = partner.targetModel;
        f.inferred = false;
        f.category = 'audit';
      } else {
        f.inferred = true;
        f.targetModel = f.inferredTarget;
      }
    }

    // (ii) Reclassify unpaired singular references as scalars (Fuuz
    // convention — embedded values like Measure, Address, RichText).
    // NOTE: a 'relation' field without `hasFkPartner` was checked AFTER all
    // FKs in the original. We rely on the fact that we've already visited
    // every field in pass A — so fieldByName is complete — and FK pairing
    // sets `hasFkPartner` immediately. If a relation appears BEFORE its FK
    // partner in the field list, we still process them correctly because
    // the FK branch above handles the partner lookup. The only failure mode
    // would be a relation processed BEFORE its FK — which would not yet
    // have hasFkPartner set. To guard against that, do reclassification in
    // a separate sweep below.

    // (iii) Counting must wait until reclassification settles
  }

  // PASS B-2 — reclassify + count (split out of B so that all FK pairings
  // have been observed first; this guarantees `hasFkPartner` is set before
  // the relation branch checks it)
  for (let j = 0; j < fieldCount; j++) {
    const f = fields[j];
    if (f.category === 'relation' && !f.hasFkPartner) {
      f.category = 'scalar';
      f.targetModel = null;
    }
    const c = f.category;
    if (c === 'system') systemCount++;
    else if (c === 'audit') auditCount++;
    else coreCount++;
  }

  const entity = {
    kind: kind,
    name: raw.name,
    description: raw.description || '',
    fields: fields,
    counts: { core: coreCount, audit: auditCount, system: systemCount, total: fieldCount }
  };
  models.push(entity);
  modelByName[entity.name] = entity;
}

// Process models (unwrap DataModelVersion wrapper if present), then topics,
// then edge subscriptions. Same pipeline for each.
for (let i = 0; i < rawModelCount; i++) {
  const r = rawModels[i];
  const def = r && r.modelDefinition ? r.modelDefinition : r;
  processEntity(def, 'model');
}
const rawTopicCount = rawTopics.length;
for (let i = 0; i < rawTopicCount; i++) {
  processEntity({
    name: rawTopics[i].name,
    description: rawTopics[i].description || '',
    fields: TOPIC_FIELDS
  }, 'topic');
}
const rawEdgeSubCount = rawEdgeSubs.length;
for (let i = 0; i < rawEdgeSubCount; i++) {
  processEntity({
    name: rawEdgeSubs[i].name,
    description: rawEdgeSubs[i].description || '',
    fields: EDGE_SUB_FIELDS
  }, 'edgeSubscription');
}

// ===== Relation extraction =================================================
const relations = [];
const modelCount = models.length;
for (let i = 0; i < modelCount; i++) {
  const m = models[i];
  const mFields = m.fields;
  const fCount = mFields.length;
  for (let j = 0; j < fCount; j++) {
    const f = mFields[j];
    const cat = f.category;
    if (cat === 'audit' || cat === 'system' || cat === 'primary' || cat === 'scalar') continue;

    let target, cardinality, inferred = false;
    if (cat === 'relation') {
      target = f.targetModel;
      cardinality = 'M:1';
    } else if (cat === 'listRel') {
      target = f.targetModel;
      cardinality = '1:M';
    } else if (cat === 'fkId') {
      if (f.pairedWith) continue;          // already emitted from resolved side
      target = f.targetModel || f.inferredTarget;
      cardinality = 'M:1';
      inferred = !!f.inferred;
    } else {
      continue;
    }

    if (!target) continue;
    relations.push({
      from: m.name,
      to: target,
      via: f.name,
      cardinality: cardinality,
      inferred: inferred,
      external: !modelNameSet[target]
    });
  }
}

// ===== Relation dedup ======================================================
// When the data has a paired (FK on A, inverse list on B) relationship, the
// extraction above emits two edges: A → B (M:1) and B → A (1:M). They're the
// same relationship viewed from opposite sides — render as one edge, with
// the FK side as canonical. Drop the 1:M whenever an inverse M:1 exists.
const fkSideExists = {};
const relCount = relations.length;
for (let i = 0; i < relCount; i++) {
  const r = relations[i];
  if (r.cardinality === 'M:1') {
    fkSideExists[r.from + '\u0001' + r.to] = true;
  }
}
let writeIdx = 0;
for (let readIdx = 0; readIdx < relCount; readIdx++) {
  const r = relations[readIdx];
  if (r.cardinality === '1:M' && fkSideExists[r.to + '\u0001' + r.from]) continue;
  relations[writeIdx++] = r;
}
relations.length = writeIdx;

// ===== Outgoing / incoming indexes =========================================
const outgoing = {}, incoming = {};
for (let i = 0; i < modelCount; i++) {
  const n = models[i].name;
  outgoing[n] = [];
  incoming[n] = [];
}
const finalRelCount = relations.length;
let inferredCount = 0, externalCount = 0;
for (let i = 0; i < finalRelCount; i++) {
  const r = relations[i];
  if (outgoing[r.from]) outgoing[r.from].push(i);
  if (incoming[r.to])   incoming[r.to].push(i);
  if (r.inferred) inferredCount++;
  if (r.external) externalCount++;
}

// ===== Strip intermediate-only field props + AGGRESSIVE COMPRESSION =======
// Field objects are flattened to the minimal shape the client actually uses.
// The biggest single win is collapsing the type object {base, required, raw}
// to just the raw string — the client re-inflates it in boot() via
// inflateType(). For a 350-model schema this drops STATE size by ~30%
// (roughly 300-500 KB raw, 800-1300 KB once URL-encoded). Combined with
// dropping empty `desc` and null `targetModel`, the URI lands well under
// Chrome's ~2 MB data: URI iframe cap.
for (let i = 0; i < modelCount; i++) {
  const m = models[i];
  if (m.description === '' || m.description == null) delete m.description;

  const fs = m.fields;
  const n = fs.length;
  for (let j = 0; j < n; j++) {
    const f = fs[j];
    // Intermediate-only props from FK pairing
    if (f.pairedName !== undefined)     delete f.pairedName;
    if (f.inferredTarget !== undefined) delete f.inferredTarget;
    if (f.hasFkPartner !== undefined)   delete f.hasFkPartner;
    if (f.inferred !== undefined)       delete f.inferred;
    // Type compression: object → raw string. Client re-inflates lazily.
    if (f.type && typeof f.type === 'object') {
      f.type = f.type.raw || '';
    }
    // Drop empties — JSON.stringify omits undefined-valued keys
    if (f.desc === '' || f.desc == null) delete f.desc;
    if (f.targetModel == null)           delete f.targetModel;
  }
}

// ===== Build diagnostic only if needed =====================================
// OPTIMIZATION: the shape-summary strings are only displayed when no models
// were found. Skip the work otherwise.
function buildDiagnostic() {
  function summarizeShape(obj, depth, maxDepth) {
    if (depth > maxDepth) return '…';
    if (obj == null) return String(obj);
    if (Array.isArray(obj)) return '[' + (obj.length ? summarizeShape(obj[0], depth + 1, maxDepth) + (obj.length > 1 ? ', …(' + obj.length + ')' : '') : '') + ']';
    if (typeof obj === 'object') {
      const keys = Object.keys(obj).slice(0, 8);
      return '{ ' + keys.join(', ') + (Object.keys(obj).length > 8 ? ', …' : '') + ' }';
    }
    if (typeof obj === 'string') return obj.length > 40 ? JSON.stringify(obj.slice(0, 40)) + '…' : JSON.stringify(obj);
    return String(obj);
  }
  return {
    expectedPaths: ['$.modelDefinitions', '$.topic.edges', '$.deviceSubscription.edges'],
    foundCounts: {
      modelDefinitions:   rawModels.length,
      topic:              rawTopics.length,
      deviceSubscription: rawEdgeSubs.length
    },
    dollarKeys: $ ? Object.keys($) : [],
    stateContextKeys: ($state && $state.context) ? Object.keys($state.context) : [],
    dollarShape: summarizeShape($, 0, 2),
    stateContextShape: $state && $state.context ? summarizeShape($state.context, 0, 2) : null
  };
}

// ===== STATE ===============================================================
// OPTIMIZATION: searchIndex is no longer precomputed server-side. Client
// builds it on first keystroke. Saves ~150KB on the wire for 750 models with
// no perceivable UI lag.
const STATE = {
  generatedAt: $moment(NOW).toISOString(),
  generatedAtLabel: $moment(NOW).format('ddd, MMM D YYYY [at] h:mm A'),
  theme: THEME,
  counts: {
    models: modelCount,
    modelsByKind: {
      model:             modelCount > 0 ? models.filter(function (m) { return m.kind === 'model'; }).length : 0,
      topic:             rawTopicCount,
      edgeSubscription:  rawEdgeSubCount
    },
    relations: finalRelCount,
    inferredRelations: inferredCount,
    externalRelations: externalCount
  },
  models: models,
  relations: relations,
  outgoing: outgoing,
  incoming: incoming,
  inputDiagnostic: modelCount === 0 ? buildDiagnostic() : null
};

// ============================================================================
// HTML TEMPLATE
// ============================================================================
const TPL_HEAD = `<!DOCTYPE html>
