  }
  :root[data-theme="light"] {
    --bg:           #f8fafc;
    --bg-deeper:    #e2e8f0;
    --panel:        #ffffff;
    --panel-2:      #f1f5f9;
    --canvas:       #fafbfc;
    --border:       rgba(15,23,42,0.10);
    --border-strong:rgba(15,23,42,0.20);
