    const outIdx = STATE.outgoing[focusName] || [];
    for (let i = 0; i < outIdx.length; i++) {
      const r = STATE.relations[outIdx[i]];
      if (!nodeNames[r.to]) nodeNames[r.to] = r.external ? 'external' : 'neighbor';
      edges.push(r);
    }
    const inIdx = STATE.incoming[focusName] || [];
    for (let i = 0; i < inIdx.length; i++) {
      const r = STATE.relations[inIdx[i]];
      if (!nodeNames[r.from]) nodeNames[r.from] = r.external ? 'external' : 'neighbor';
      edges.push(r);
    }

    const nodes = [];
    Object.keys(nodeNames).forEach(function (n) {
      const m = MODEL_BY_NAME[n];
      nodes.push({
        name: n,
        kind: nodeNames[n],
        model: m || null,
        external: nodeNames[n] === 'external' || !m
