      const r = STATE.relations[i];
      if (!nodeNames[r.to])   nodeNames[r.to]   = 'external';
      if (!nodeNames[r.from]) nodeNames[r.from] = 'external';
    }
    const nodes = [];
    Object.keys(nodeNames).forEach(function (n) {
